f38", "created_at": "2026-04-20T10:06:46.787732+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-20T10:06:46.787732+00:00", "updated_by": null, "description": null, "contact_name": null, "country_code": "TW", "english_name": null, "ticket_price": null, "workspace_id": "2035d43b-ed17-40ef-9a15-a5651543f469", "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "google_maps_url": null, "duration_minutes": null}, {"id": "07169f9f-af63-4d95-8292-069aabededd3", "fax": null, "name": "巴亭廣場", "tags": ["廣場", "歷史", "升旗"], "type": "attraction", "notes": null, "phone": null, "images": null, "address": null, "city_id": "hanoi", "website": null, "category": "歷史文化 / History & Culture", "latitude": 21.0369867, "is_active": true, "longitude": 105.8357925, "region_id": null, "country_id": "vietnam", "created_at": "2026-04-04T11:17:37.177+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "《巴亭廣場》是越南最重要的政治廣場,1945年胡志明在此宣讀《獨立宣言》。廣場寬闊整齊,中央是國旗台,周圍是政府機關建築。每天清晨有升旗儀式,禮兵動作精準劃一,氣氛莊嚴肅穆。廣場對外開放,但禁止喧嘩、穿著暴露。這裡不是觀光景點,而是越南現代歷史的起點——國家意識在此誕生,政治儀式在此上演。站在廣場上,你會感受到一個國家對獨立與尊嚴的執著。參觀建議與胡志明陵墓、一柱寺安排在同一行程。", "contact_name": null, "country_code": "VN", "english_name": "Ba Dinh Square", "ticket_price": null, "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "google_maps_url": null, "duration_minutes": null}, {"id": "07303231-cd37-4159-ba09-025e47231134", "fax": null, "name": "森美術館", "tags": ["美術館", "現代藝術", "展望"], "type": "heritage", "notes": "六本木之丘頂樓的當代藝術館，展覽結合觀景台一票到底。", "phone": null, "images": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/japan/07303231-cd37-4159-ba09-025e47231134-1.jpeg", "https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/japan/07303231-cd37-4159-ba09-025e47231134-2.jpg"], "address": null, "city_id": "tokyo", "website": null, "category": "歷史文化 / History & Culture", "latitude": 35.6605, "is_active": true, "longitude": 139.7292, "region_id": "jp_kanto", "country_id": "japan", "created_at": "2025-12-06T07:10:59.517511+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "《森美術館》六本木之丘森大樓 52-53 樓，當代藝術企劃展、國際新銳藝術家個展前衛大膽。展期結合「東京城市觀景」52 樓展望台俯瞰東京鐵塔、晴空塔、夜景璀璨。週五六延長至 22 點，夜間看展後直接賞夜景，藝文與城市景觀完美結合。", "contact_name": null, "country_code": "JP", "english_name": "Mori Art Museum", "ticket_price": "¥2,000（美術館+展望台）", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 645, "opening_hours": {"closed": "展期間無休", "weekdays": "10:00-22:00（週二至 17:00）"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 120}, {"id": "0781fdcc-ab50-4605-b340-0d2ed13e29b9", "fax": null, "name": "大英博物館", "tags": ["博物館", "免費", "木乃伊", "羅塞塔石碑", "世界級"], "type": "heritage", "notes": "世界最著名博物館之一，收藏超過800萬件文物。必看埃及木乃伊、羅塞塔石碑、帕德嫩神廟雕塑。免費入場。建議至少安排半天。\n\n旅遊提示：免費但建議捐款，週五晚上人較少", "phone": null, "images": null, "address": null, "city_id": null, "website": null, "category": "歷史文化 / History & Culture", "latitude": 51.5194, "is_active": true, "longitude": -0.127, "region_id": null, "country_id": "uk", "created_at": "2025-12-06T07:06:39.590633+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "倫敦大英博物館，世界最古老博物館之一。埃及木乃伊、羅塞塔石碑、帕德嫩神廟雕塑，館藏800萬件。", "contact_name": null, "country_code": "GB", "english_name": "British Museum", "ticket_price": "免費", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 55, "opening_hours": {"sun": "12:00-18:00", "mon_sat": "10:00-18:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 240}, {"id": "07a53c15-8163-4798-8020-64a94c235701", "fax": null, "name": "下龍灣皮划艇探洞秘境之旅", "tags": ["冒險體驗", "頂級體驗"], "type": "attraction", "notes": "頂級體驗 | 冒險體驗 | 價位: | 難度:None", "phone": null, "images": ["https://images.unsplash.com/photo-1528127269322-539801943592?w=800", "https://images.unsplash.com/photo-1583417319070-4a69db38a482?w=800"], "address": null, "city_id": "hanoi", "website": null, "category": "景點 / Attraction", "latitude": null, "is_active": true, "longitude": null, "region_id": null, "country_id": "vietnam", "created_at": "2026-04-06T22:24:11.457463+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "在越南世界遺產下龍灣，體驗不為遊客所知的秘境探險。搭乘私人豪華遊艇（非大型遊輪）出海，抵達人跡罕至的海域。換乘雙人皮划艇，由專業嚮導帶領穿越石灰岩洞穴、探索隱藏的潟湖與漂浮村落。在秘密沙灘野餐，游泳、浮潛。下午繼續皮划艇冒險，進入只有退潮時才能通過的洞穴，發現鐘乳石與地下湖。傍晚返回遊艇，在甲板享用海鮮BBQ晚餐，觀賞日落。夜宿遊艇上的豪華客房。", "contact_name": null, "country_code": "VN", "english_name": "Ha Long Bay Kayaking Cave Expedition", "ticket_price": null, "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 0}, {"id": "07b71560-1742-45b1-b70b-c6b26dc66754", "fax": null, "name": "翠湖公園", "tags": null, "type": "park", "notes": "昆明市區公園，四季花開，冬季紅嘴鷗聚集", "phone": null, "images": null, "address": null, "city_id": null, "website": null, "category": "自然風景 / Nature", "latitude": 25.045, "is_active": true, "longitude": 102.708, "region_id": "cn_southwest", "country_id": "china", "created_at": "2025-12-06T01:24:52.82314+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "翠湖公園，中國著名湖泊，景色秀麗，適合休閒遊覽與欣賞湖光山色。", "contact_name": null, "country_code": "CN", "english_name": "Green Lake Park", "ticket_price": "免費或5-20元", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": {"daily": "06:00-18: