ull, "google_maps_url": null, "duration_minutes": 60}, {"id": "092ee146-511c-4ac9-83f1-717a74d034e3", "fax": null, "name": "胡志明美術館", "tags": ["美術館", "當代藝術", "法式建築"], "type": "attraction", "notes": null, "phone": null, "images": null, "address": null, "city_id": "ho-chi-minh", "website": null, "category": "歷史文化 / History & Culture", "latitude": 10.7698707, "is_active": true, "longitude": 106.6992242, "region_id": null, "country_id": "vietnam", "created_at": "2026-04-04T11:19:45.981+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "《胡志明美術館》位於法式黃色別墅,展示越南從古代到當代的藝術作品。一樓是傳統漆畫、絲畫,二樓是當代藝術,三樓是戰爭主題創作。展品包含繪畫、雕塑、裝置藝術,風格從寫實、抽象到政治諷刺都有。這裡遊客不多,可以安靜欣賞。英文說明不多,但藝術語言跨越文字。美術館證明:越南藝術不只有政治宣傳,也有個人創作與美學探索。門票便宜,冷氣充足,適合炎熱午後躲進來吸收藝術養分。", "contact_name": null, "country_code": "VN", "english_name": "Ho Chi Minh City Fine Arts Museum", "ticket_price": null, "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "google_maps_url": null, "duration_minutes": null}, {"id": "0961a22d-49c9-4816-a9bf-fe9650698819", "fax": null, "name": "愛情巷", "tags": ["巷弄", "IG打卡", "咖啡", "文青", "浪漫"], "type": "shopping", "notes": "檳城喬治城的一條小巷，因名字浪漫而成為打卡熱點。巷內有咖啡店和文創小店，氛圍悠閒文青。", "phone": null, "images": null, "address": null, "city_id": "penang", "website": null, "category": "購物 / Shopping", "latitude": 5.4203139, "is_active": true, "longitude": 100.3372809, "region_id": null, "country_id": "malaysia", "created_at": "2025-12-06T07:01:20.923168+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "檳城愛情巷，喬治城背包客街區，窄巷兩旁是青年旅館、咖啡廳、酒吧、紋身店。價格親民、氣氛輕鬆，是背包客聚集地。這裡也是喬治城文青街區，有特色咖啡廳、vintage店。這是檳城背包客天堂，也是體驗青年文化的好地方。免費參觀，建議傍晚或夜晚前往。可搭配喬治城壁畫、姓氏橋一起遊覽。", "contact_name": null, "country_code": "MY", "english_name": "Love Lane", "ticket_price": "免費或依業者而異", "