_minutes": 150}, {"id": "0a7baaaa-c358-4f09-9551-d9ee836897a0", "fax": null, "name": "文武廟", "tags": null, "type": "attraction", "notes": null, "phone": null, "images": null, "address": "南投縣魚池鄉中山路63號", "city_id": "nantou-698c1821-d3e7-4008-a70e-7633ba447409", "website": null, "category": "歷史文化 / History & Culture", "latitude": 23.8783, "is_active": true, "longitude": 120.9283, "region_id": null, "country_id": "taiwan-country-001", "created_at": "2026-01-09T03:36:28.944514+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "日月潭著名的廟宇，供奉關聖帝君、岳飛。廟宇建在山坡上，層層拾級而上，可以俯瞰日月潭全景。廟宇建築宏偉，雕樑畫棟，是日月潭重要的信仰中心。農曆春節期間香火鼎盛，也是欣賞湖景的絕佳地點。", "contact_name": null, "country_code": "TW", "english_name": "Wenwu Temple", "ticket_price": "免費", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 54, "opening_hours": {"daily": "06:00-21:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 45}, {"id": "0a816ed4-ff29-42fe-9944-0c246a87c330", "fax": null, "name": "全州韓紙工藝與天然染色", "tags": ["工藝體驗", "頂級體驗"], "type": "attraction", "notes": "頂級體驗 | 工藝體驗 | 價位: | 難度:None", "phone": null, "images": ["https://images.unsplash.com/photo-1586864387634-92fda7c6cab8?w=800", "https://images.unsplash.com/photo-1516631670063-e9c0f33afd06?w=800"], "address": null, "city_id": "seoul", "website": null, "category": "景點 / Attraction", "latitude": null, "is_active": true, "longitude": null, "region_id": null, "country_id": "korea", "created_at": "2026-04-06T22:24:09.335051+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "韓紙（한지）是韓國傳統手工紙，使用桑樹皮製成，以堅韌耐久聞名，可保存千年。全州是韓紙的故鄉，擁有最高品質的韓紙工藝。在首爾的全州韓紙工坊，跟隨國家指定韓紙匠人學習造紙與染色。從桑樹皮處理、打漿、抄紙到乾燥，體驗完整工序。使用天然植物染料（梔子、蘇木、藍草）染色，製作彩色韓紙。學習韓紙工藝品製作：燈籠、摺扇、書籤、筆記本等。", "contact_name": null, "country_code": "KR", "english_name": "Jeonju Hanji Papercraft & Natural Dyeing", "ticket_price": null, "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 0}, {"id": "0ae6fd4b-bdce-4ab8-b2a2-abddaacd0d18", "fax": null, "name": "芽莊咖啡街", "tags": ["咖啡街", "海景", "社交"], "type": "attraction", "notes": null, "phone": null, "images": null, "address": null, "city_id": "nha-trang", "website": null, "category": "購物 / Shopping", "latitude": null, "is_active": true, "longitude": null, "region_id": null, "country_id": "vietnam", "created_at": "2026-04-04T11:24:21.899+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "《芽莊咖啡街》沿海而建,兩側是咖啡館、酒吧、餐廳。白天喝咖啡看海,夜晚喝啤酒看夜景。這裡是芽莊年輕人的社交空間,也是觀光客的休息站。咖啡街證明:芽莊不只有海灘,還有咖啡文化。", "contact_name": null, "country_code": "VN", "english_name": "Nha Trang Coffee Street", "ticket_price": null, "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "google_maps_url": null, "duration_minutes": null}, {"id": "0af02b90-ebd5-4b31-b322-e9588d9b8e33", "fax": null, "name": "牛車水", "tags": ["唐人街", "美食", "購物", "文化", "新加坡"], "type": "shopping", "notes": "新加坡的唐人街，有傳統商店、美食、寺廟。佛牙寺龍華院是必訪。史密斯街是美食街。麥士威熟食中心的天天海南雞飯超有名。\n\n旅遊提示：天天海南雞飯要排很久的隊", "phone": null, "images": null, "address": null, "city_id": null, "website": null, "category": "景點 / Attraction", "latitude": 1.2833, "is_active": true, "longitude": 103.8442, "region_id": null, "country_id": "singapore", "created_at": "2025-12-06T02:06:36.968269+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "新加坡牛車水，唐人街歷史街區。南洋式騎樓、中藥行、佛牙寺龍華院，保留華人移民文化。麥士威熟食中心的天天海南雞飯、老伴豆花都是名店。牛車水原點是新加坡名稱由來，過去用牛車運水得名。這裡是認識新加坡華人歷史的最佳場所。", "contact_name": null, "country_code": "SG", "engl