ated_at": "2025-12-06T02:12:42.416379+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "亞龍灣麗思卡爾頓，中國知名景點，值得探訪。", "contact_name": null, "country_code": "CN", "english_name": null, "ticket_price": "免費或依業者而異", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 321, "opening_hours": {"daily": "08:30-17:30"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": null}, {"id": "14d3d56d-1205-4c5d-b8ac-a0613d709bda", "fax": null, "name": "河內法國區", "tags": ["法式建築", "殖民歷史", "林蔭大道"], "type": "attraction", "notes": null, "phone": null, "images": null, "address": null, "city_id": "hanoi", "website": null, "category": "歷史文化 / History & Culture", "latitude": 11.9363958, "is_active": true, "longitude": 108.4483156, "region_id": null, "country_id": "vietnam", "created_at": "2026-04-04T11:17:37.92+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "《河內法國區》保留了法國殖民時期(1887-1954)的建築與城市規劃。林蔭大道兩側是黃色法式別墅,歌劇院、郵政總局、政府機關建築帶有濃厚歐洲風格。這裡不是刻意保存的博物館區,而是持續使用的城市空間——法式建築內是咖啡館、餐廳、精品店、政府機關。殖民歷史在此被重新詮釋:不刻意美化,也不全盤否定,而是承認它是城市記憶的一部分。在法國區散步,你會看到歷史的複雜性——殖民與抵抗、壓迫與影響,同時存在於同一片土地上。", "contact_name": null, "country_code": "VN", "english_name": "French Quarter", "ticket_price": null, "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "google_maps_url": null, "duration_minutes": null}, {"id": "14d544b5-7f94-4011-b2cd-2548d085bb5d", "fax": null, "name": "皓月園", "tags": null, "type": "garden", "notes": null, "phone": null, "images": null, "address": null, "city_id": null, "website": null, "category": "景點 / Attraction", "latitude": 22.620317, "is_active": true, "longitude": 114.0394273, "region_id": null, "country_id": "china", "created_at": "2025-12-06T01:13:29.809