": null, "city_id": null, "website": null, "category": "自然風景 / Nature", "latitude": 25.0167, "is_active": true, "longitude": 121.95, "region_id": null, "country_id": "taiwan-country-001", "created_at": "2025-12-15T04:21:35.91677+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "新北福隆，金黃色的沙灘綿延2公里，是北台灣最美的海水浴場。每年夏天舉辦國際沙雕藝術季，藝術家在沙灘上創作巨型沙雕。福隆便當也是這裡的名產，木片便當盒、滷蛋、滷豆干、酸菜,是老一輩台灣人的回憶。海邊玩水、吃便當、看沙雕，是福隆夏日的標準行程。", "contact_name": null, "country_code": "TW", "english_name": "Fulong", "ticket_price": "海水浴場夏季全票100元", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 755, "opening_hours": {"daily": "全天開放"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 180}, {"id": "1d25884f-e230-4a16-98c7-cfe167b96ac7", "fax": null, "name": "華嚴瀑布", "tags": ["瀑布", "三大名瀑", "必遊", "楓葉"], "type": "attraction", "notes": "日本三大名瀑之一，從 97 公尺高處傾瀉而下，搭乘電梯到瀑布正下方感受震撼。", "phone": null, "images": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/japan/1d25884f-e230-4a16-98c7-cfe167b96ac7-1.jpeg", "https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/japan/1d25884f-e230-4a16-98c7-cfe167b96ac7-2.jpg"], "address": null, "city_id": "nikko", "website": null, "category": "自然風景 / Nature", "latitude": 36.7388, "is_active": true, "longitude": 139.4993, "region_id": "jp_kanto", "country_id": "japan", "created_at": "2025-10-28T06:35:52.864591+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "日光華嚴瀑布，日本三大名瀑之一，高97公尺。中禪寺湖水從岩壁直洩而下，氣勢磅礡。電梯可下到觀瀑台近距離觀賞。電梯秋季紅葉、冬季結冰最壯觀。", "contact_name": null, "country_code": "JP", "english_name": "Kegon Falls", "ticket_price": "免費或依業者而異", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 2, "opening_hours": {"daily": "10:00-18:00"}