": null, "google_maps_url": null, "duration_minutes": 90}, {"id": "1f69c069-ab41-4742-9ddd-d495b8ed4e39", "fax": null, "name": "韓服體驗景福宮", "tags": null, "type": "experience", "notes": "朝鮮王朝第一座宮殿，1395年建成。穿韓服可免費入場，每天10:00和14:00有守門將交接儀式。", "phone": null, "images": null, "address": null, "city_id": "seoul", "website": null, "category": "歷史文化 / History & Culture", "latitude": 37.5797, "is_active": true, "longitude": 126.977, "region_id": null, "country_id": "korea", "created_at": "2025-12-06T01:49:08.661176+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "首爾景福宮，朝鮮王朝最大的宮殿，建於1395年。勤政殿是國王處理政務的正殿，慶會樓是水上樓閣，香遠亭蓮花池優雅寧靜。守門將交接儀式每日舉行，身著傳統服飾的衛兵莊嚴行禮。春天櫻花、秋天銀杏，四季景色各異。這是首爾必訪的歷史景點，也是認識朝鮮王朝文化的最佳場域。", "contact_name": null, "country_code": "KR", "english_name": "Hanbok at Gyeongbokgung", "ticket_price": "成人3000韓元", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": {"closed": "週二", "tue_sun": "09:00-18:00（冬季至17:00）", "ceremony": "10:00、14:00守門將交接"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 120}, {"id": "1f841c10-1299-4065-b13b-31cd8afd33be", "fax": null, "name": "太古倉", "tags": ["碼頭", "文創", "酒吧", "夜景", "打卡"], "type": "attraction", "notes": "百年碼頭倉庫改造", "phone": null, "images": null, "address": "廣州市海珠區革新路124號", "city_id": null, "website": null, "category": "購物 / Shopping", "latitude": 23.0983, "is_active": true, "longitude": 113.2717, "region_id": "cn_south", "country_id": "china", "created_at": "2025-12-05T14:34:26.951064+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "太古倉，中國知名景點，值得探訪。", "contact_name": null, "country_code": "CN", "english_name": "Taikoo Warehouse", "ticket_price": "免費或依業者而異", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 15,