": null, "address": "花蓮縣秀林鄉中橫公路", "city_id": "769364e9-d3e2-474f-bc80-0184c00e6d9e", "website": null, "category": "歷史文化 / History & Culture", "latitude": 24.1667, "is_active": true, "longitude": 121.5833, "region_id": null, "country_id": "taiwan-country-001", "created_at": "2026-01-09T03:36:28.944514+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "太魯閣國家公園內的祠廟，紀念開鑿中橫公路殉職的工程人員。祠廟建在山壁上，飛簷翹角，古典優雅。旁邊有湧泉從山壁流下，形成小瀑布。這裡是太魯閣重要的紀念地，也是觀景的好地方。", "contact_name": null, "country_code": "TW", "english_name": "Changchun Shrine", "ticket_price": "免費", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 36, "opening_hours": {"daily": "全天開放"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 30}, {"id": "27e11593-427e-4b50-a9dd-6dd32c8b8662", "fax": null, "name": "胡志明市藝術街", "tags": ["藝術街", "精品店", "藝廊"], "type": "attraction", "notes": null, "phone": null, "images": null, "address": null, "city_id": "ho-chi-minh", "website": null, "category": "購物 / Shopping", "latitude": 10.7762521, "is_active": true, "longitude": 106.7028775, "region_id": null, "country_id": "vietnam", "created_at": "2026-04-04T11:19:46.368+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "《胡志明市藝術街》Dong Khoi Street 是第一郡的主要商業街,兩側是精品店、藝廊、咖啡館、飯店。法式建築保存良好,街道寬敞整齊,是胡志明最有質感的區域。藝廊展示越南當代藝術,從傳統漆畫到現代裝置都有。這裡不便宜,但品質有保證。週末有街頭藝術市集,獨立創作者在此擺攤。藝術街代表胡志明的文化野心——不只是經濟中心,也要成為藝術之都。", "contact_name": null, "country_code": "VN", "english_name": "Dong Khoi Street", "ticket_price": null, "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "google_maps_url": null, "duration_minutes": null}, {"id": "28020702-8536-4791-aec7-8ebfc8aaff2a", "fax": null, "name": "東京迪士尼度假區", "tags": ["主題樂園",