escription": "沙壩愛情市場，沙壩山區少數民族的傳統市集，每週六晚上舉辦。年輕人穿著傳統服飾、唱歌、跳舞、尋找對象。遊客可觀賞、拍照，但需尊重當地文化。這是沙壩必體驗活動，也是認識少數民族習俗的好地方。需尊重當地傳統。", "contact_name": null, "country_code": "VN", "english_name": "Love Market", "ticket_price": "免費", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 308, "opening_hours": {"daily": "夜市17:00-23:00，傳統市場06:00-18:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": null}, {"id": "29a67b7b-d472-4d30-83ec-a0eb9ef2b8df", "fax": null, "name": "大象保育園", "tags": ["大象保育", "動物", "倫理旅遊"], "type": "attraction", "notes": null, "phone": null, "images": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/thailand/29a67b7b-d472-4d30-83ec-a0eb9ef2b8df-1.jpeg", "https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/thailand/29a67b7b-d472-4d30-83ec-a0eb9ef2b8df-2.jpeg"], "address": null, "city_id": "chiang-mai", "website": null, "category": "活動體驗 / Activity", "latitude": 19.0658184, "is_active": true, "longitude": 98.9404693, "region_id": null, "country_id": "thailand", "created_at": "2025-10-28T06:16:48.533253+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "《大象保育園》在清邁周邊山區，這些機構從馬戲團與伐木業救出退役大象，提供安養空間。遊客可以餵食、幫大象洗澡，但不騎乘、不看表演——這是對動物最基本的尊重。站在河裡幫一頭五噸重的大象刷洗，水花濺起時你會感受到生命的重量與溫度。保育員會解釋每頭大象的故事——牠們背上的傷疤、個性差異、喜歡的食物。這不是迪士尼式的動物體驗，而是關於如何與其他物種共存的課程。選擇保育園時請確認：不騎象、不表演、有獸醫照護。", "contact_name": null, "country_code": "TH", "english_name": "Elephant Sanctuary", "ticket_price": "免費或依業者而異", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 2, "opening_hours": {"daily": "09:00-18:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 240}, {"id": "29d3d00e-ed3b-4dc7-ae65-cdf1a12cb004", "fax": null, "name": "睡魔之家", "tags": null, "type": "attraction", "notes": null, "phone": null, "images": ["https://pfqvdacxowpgf