l, "google_maps_url": null, "duration_minutes": null}, {"id": "2ac5af96-314a-4d27-a232-19b8c666830b", "fax": null, "name": "中台禪寺", "tags": null, "type": "attraction", "notes": null, "phone": null, "images": null, "address": "南投縣埔里鎮中台路1號", "city_id": "nantou-698c1821-d3e7-4008-a70e-7633ba447409", "website": "http://www.ctworld.org.tw/", "category": "歷史文化 / History & Culture", "latitude": 23.9847, "is_active": true, "longitude": 120.9478, "region_id": null, "country_id": "taiwan-country-001", "created_at": "2026-01-09T03:43:44.063392+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "南投埔里的中台禪寺，規模宏大的現代佛寺建築。建築融合中西元素，金碧輝煌。大雄寶殿、四天王殿氣勢磅礡，佛像莊嚴。這裡不只是宗教場所，建築本身就是藝術品，吸引許多遊客參觀。", "contact_name": null, "country_code": "TW", "english_name": "Chung Tai Chan Monastery", "ticket_price": "免費", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 89, "opening_hours": {"daily": "08:00-17:30"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 90}, {"id": "2ad2042a-3508-4d59-9e27-5a8b188cbe85", "fax": null, "name": "曼谷夜市火車市場", "tags": ["夜市", "鐵道", "復古"], "type": "market", "notes": "拉差達、Jodd Fairs、Asiatique 各有特色，吃喝玩樂到深夜。", "phone": null, "images": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/thailand/2ad2042a-3508-4d59-9e27-5a8b188cbe85-1.jpeg", "https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/thailand/2ad2042a-3508-4d59-9e27-5a8b188cbe85-2.jpeg"], "address": null, "city_id": "bangkok", "website": null, "category": "購物 / Shopping", "latitude": 13.7649, "is_active": true, "longitude": 100.5733, "region_id": null, "country_id": "thailand", "created_at": "2025-12-06T01:24:38.00038+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "《曼谷夜市火車市場》建在廢棄的鐵道倉庫區,保留了生鏽的軌道與斑駁的車廂。攤商沿著鐵軌兩側擺設,販售從復古海報到手工皮件的各種物件。工業風的鐵皮屋頂下,串燒的煙霧與音樂混雜成獨特氛圍。這裡的二手古著攤位質量參差,需要耐心翻找才能挖到寶。週末人潮擁擠,平日反而更適合慢慢逛。不是傳統夜市的食物導向,而是帶有懷舊美學與次文化色彩的混合體。鐵道元素不是刻意營造,而是場地本身的記憶。", "contact_name": null, "country_code": "TH", "english_name": "Train Night Market", "ticket_price": "免費", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": {"daily": "18:00-00:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 180}, {"id": "2b2fac78-1cfe-4517-8d56-658bb4ed8285", "fax": null, "name": "統一宮", "tags": ["歷史", "政治", "胡志明市", "必去"], "type": "attraction", "notes": "南越總統府，越戰結束的歷史場景。坦克衝入大門的照片是經典。門票65,000越盾。建議請導遊。", "phone": null, "images": null, "address": null, "city_id": "ho-chi-minh", "website": null, "category": "活動體驗 / Activity", "latitude": 10.7769, "is_active": true, "longitude": 106.6953, "region_id": null, "country_id": "vietnam", "created_at": "2025-11-01T13:04:50.152339+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "胡志明市統一宮，原為南越總統府。1975年4月北越坦克衝破大門，標誌越戰結束。宮內保留1970年代原貌，辦公室、會議廳、地下戰情室都可參觀。這是越南統一的象徵，也是認識越戰歷史不可錯過的景點。建築本身融合東西方風格，庭園優美。", "contact_name": null, "country_code": "VN", "english_name": "Independence Palace", "ticket_price": "成人65,000越南盾", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": {"daily": "07:30-11:00, 13:00-16:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 90}, {"id": "2b366db8-af2d-4cf2-82ce-b9a45ad9269a", "fax": null, "name": "東照宮", "tags": ["UNESCO", "神社", "必遊", "建築"], "type": "attraction", "notes": "德川家康長眠之地，金碧輝煌的陽明門與「非禮勿視」三猿雕刻是必看重點。", "phone": null, "images": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/japan/2b366db8-af2d-4cf2-82ce-b9a45ad9269a-1.jpeg", "https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/japan/2b366db8-af2d-4cf2-8