y_id": null, "website": null, "category": "主題樂園 / Theme Park", "latitude": 34.0167, "is_active": true, "longitude": 108.9, "region_id": "cn_northwest", "country_id": "china", "created_at": "2025-12-05T14:47:40.776522+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "秦嶺野生動物園，中國知名景點，值得探訪。", "contact_name": null, "country_code": "CN", "english_name": "Qinling Wildlife Park", "ticket_price": "免費或依業者而異", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 23, "opening_hours": {"daily": "08:30-17:30"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 300}, {"id": "30c31a73-e21d-4e04-97f8-91061bbbb429", "fax": null, "name": "會安攝影行走", "tags": ["攝影", "導覽", "光影"], "type": "attraction", "notes": null, "phone": null, "images": null, "address": null, "city_id": "hoi-an", "website": null, "category": "活動體驗 / Activity", "latitude": null, "is_active": true, "longitude": null, "region_id": null, "country_id": "vietnam", "created_at": "2026-04-04T11:21:13.428+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "《會安攝影行走》由專業攝影師帶領，清晨或黃昏在古鎮尋找最佳光線與角度。從日本橋、古厝、河邊、市場到巷弄，捕捉會安的光影之美。攝影師會教你構圖、用光、時機，也會分享會安的故事與歷史。這不只是拍照，而是用鏡頭理解城市的方式。適合攝影愛好者，但初學者也歡迎。三小時行程約台幣1,000-1,500元。會安是攝影師的天堂——黃牆、綠窗、紅燈籠、柔和光線，每個角落都是畫面。", "contact_name": null, "country_code": "VN", "english_name": "Hoi An Photo Walk", "ticket_price": null, "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "google_maps_url": null, "duration_minutes": null}, {"id": "30ca8d51-d250-4679-b2b6-4a1a728fc75d", "fax": null, "name": "鹿野高台", "tags": null, "type": "attraction", "notes": null, "phone": null, "images": null, "address": "台東縣鹿野鄉永安村高台路42巷145號", "city_id": "02d6cb3c-b3d0-40c7-b283-d2d5f446ba1d", "website": null, "category": "自然風景 / Nature", "latitude": 22.9139, "is_active": true, "longitude": 121.1236, "region_id": null, "country_id": "taiwan-country-001", "created_at": "2026-01-09T03:36:28.944514+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "台東成功的鹿野高台，是熱氣球嘉年華的舉辦地。每年夏季，五彩繽紛的熱氣球在高台升空，吸引大批遊客。即使不是熱氣球季，高台視野開闊，可以俯瞰縱谷平原。這裡也是飛行傘起飛點，從空中欣賞台東之美。", "contact_name": null, "country_code": "TW", "english_name": "Luye Highland", "ticket_price": "免費（熱氣球體驗另計）", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 46, "opening_hours": {"daily": "全天開放，熱氣球季另有活動時間"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 120}, {"id": "30d38dc6-8921-4cdf-b6be-d63aea473ad6", "fax": null, "name": "King Ludwig Beerhall", "tags": null, "type": "food", "notes": null, "phone": null, "images": null, "address": null, "city_id": null, "website": null, "category": "景點 / Attraction", "latitude": 22.2792968, "is_active": true, "longitude": 114.1628907, "region_id": null, "country_id": "china", "created_at": "2025-12-06T05:00:51.323751+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "香港赤柱的德國啤酒屋，提供正宗巴伐利亞美食和精釀啤酒。德國豬腳、香腸拼盤、椒鹽脆餅，配上冰涼的啤酒，是最道地的德式體驗。餐廳氣氛輕鬆，週末常有樂隊表演。赤柱海邊位置，用餐後可以散步海濱。價格中等，人均約250-350港幣。", "contact_name": null, "country_code": "CN", "english_name": null, "ticket_price": "人均約250-350港幣", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 946, "opening_hours": {"daily": "12:00-23:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 120}, {"id": "30d6202d-e6e9-4bdb-8c55-e12bc40c454d", "fax": null, "name": "芽莊海鮮市場", "tags": ["海鮮市場", "代客料理", "新鮮"], "type": "attraction", "notes": null, "phone": null, "images": null, "address": null, "city_id": "nha-trang", "website": null, "category": "購物 / Shopping", "latitude": null, "is_active": true, "longitude": null, "region_id": null, "country_id": "vietnam", "created_at": "2026-04-04T11:24:22.289+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "《芽莊海鮮市場》在港口附近,新鮮漁獲每天早晨送達。挑選海鮮後,旁邊餐廳代客料理,只收加工費。龍蝦、螃蟹、魚、蝦、貝類應有盡有,價格比餐廳便宜一半。這是在地人的海鮮吃法——新鮮、便宜、大份量。", "contact_name": null, "country_code": "VN", "english_name": "Nha Trang Seafood Market", "ticket_price": null, "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "google_maps_url": null, "duration_minutes": null}, {"id": "30e2b328-e0bd-49c5-a5ed-49e25763ac47", "fax": null, "name": "峴港高爾夫", "tags": ["高爾夫", "球場", "高端"], "type": "attraction", "notes": null, "phone": null, "images": null, "address": null, "city_id": "da-nang", "website": null, "category": "活動體驗 / Activity", "latitude": null, "is_active": true, "longitude": null, "region_id": null, "country_id": "vietnam", "created_at": "2026-04-04T11:24:19.278+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "《峴港高爾夫》擁有多座國際級球場,面海背山,景觀壯麗。果嶺費比台灣便宜,設施現代,服務專業。這是峴港吸引高端旅客的策略——不只有海灘,還有高爾夫、度假村、Spa。峴港高爾夫證明:越南正在往高端旅遊市場發展。", "contact_name": null, "country_code": "VN", "english_name": "Da Nang Golf", "ticket_price": null, "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "google_maps_url": null, "duration_minutes": null}, {"id": "30e481f1-e645-4826-a8ad-9099660c6f62", "fax": null, "name": "直島", "tags": null, "type": "attraction", "notes": null, "phone": null, "images": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/japan/30e481f1-e645-4826-a8ad-9099660c6f62-1.jpeg", "https://p