5-12-06T01:27:01.641206+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "伊斯坦堡聖索菲亞大教堂，拜占庭建築傑作，建於537年。曾是東正教大教堂，鄂圖曼時期改為清真寺，現為博物館。巨大圓頂、金色馬賽克、基督教與伊斯蘭元素並存，見證1500年歷史變遷。", "contact_name": null, "country_code": "TR", "english_name": "Hagia Sophia", "ticket_price": "依官網而定", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": {"open": "09:00", "close": "19:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 90}, {"id": "343b295f-be51-42a0-95f6-aad3b2d8e8e7", "fax": null, "name": "人民廣場早茶體驗", "tags": ["茶文化", "休閒", "在地體驗"], "type": "attraction", "notes": "上海當地人的早茶文化體驗，品嚐各式點心和茶飲。感受上海老城區的悠閒氛圍，是了解在地生活的好機會。", "phone": null, "images": null, "address": null, "city_id": null, "website": null, "category": "活動體驗 / Activity", "latitude": 31.2304, "is_active": true, "longitude": 121.4737, "region_id": "cn_southwest", "country_id": "china", "created_at": "2025-12-05T07:30:52.408255+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "人民廣場早茶體驗，中國知名景點，值得探訪。", "contact_name": null, "country_code": "CN", "english_name": "People's Square Morning Tea", "ticket_price": "免費或依業者而異", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 5, "opening_hours": {"daily": "08:30-17:30"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 120}, {"id": "346ddd9b-1005-4aec-bb4a-c071f31e1633", "fax": null, "name": "大峽谷玻璃橋", "tags": null, "type": "attraction", "notes": "張家界大峽谷的玻璃吊橋，全長430米懸空在峽谷之上。挑戰膽量的刺激體驗，俯瞰深谷景色壯觀。", "phone": null, "images": null, "address": null, "city_id": null, "website": null, "category": "自然風景 / Nature", "latitude": 29.4333, "is_active": true, "longitude": 110.4333, "region_id": null, "country_id": "china", "created_at": "2025-12-06T01:24:51.659149+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "大峽谷玻璃橋，中國知名景點，值得探訪。", "contact_name": null, "country_code": "CN", "english_name": "Zhangjiajie Glass Bridge", "ticket_price": "免費或依業者而異", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": {"daily": "08:30-17:30"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": null}, {"id": "3471feb6-3ff3-4560-b301-0e32e03d4921", "fax": null, "name": "桜島", "tags": null, "type": "attraction", "notes": null, "phone": null, "images": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/japan/3471feb6-3ff3-4560-b301-0e32e03d4921-1.jpeg", "https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/japan/3471feb6-3ff3-4560-b301-0e32e03d4921-2.jpeg"], "address": null, "city_id": "kagoshima", "website": null, "category": "景點 / Attraction", "latitude": 31.5856, "is_active": true, "longitude": 130.6572, "region_id": "jp_kyushu", "country_id": "japan", "created_at": "2026-01-23T02:46:24.339376+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "鹿兒島櫻島，鹿兒島灣中的活火山，標高1,117公尺，至今仍持續噴煙。展望台、溶岩步道、櫻島蘿蔔、足湯。這是鹿兒島必訪景點，也是看活火山的好地方。渡輪24小時營業，建議預留半天。可搭配仙巖園、城山展望台一起遊覽。", "contact_name": null, "country_code": "JP", "english_name": "Sakurajima", "ticket_price": "免費或依業者而異", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 100, "opening_hours": {"daily": "全天開放"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 180}, {"id": "347b8194-5628-4d84-afe3-6926ea0cc355", "fax": null, "name": "會安燈籠工坊", "tags": ["燈籠", "手作", "工藝"], "type": "attraction", "notes": null, "phone": null, "images": null, "address": null, "city_id": "hoi-an", "website": null, "category": "活動體驗 / Activity", "latitude": null, "is_active": true, "longitude": null, "region_id": null, "country_id": "vietnam", "created_at": "2026-04-04T11:21:12.617+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "《會安燈籠工坊》讓你親手製作傳統絲綢燈籠。從選布料、剪裁、縫製到組裝，師傅會一步步指導。完成後可以帶回家，也可以在滿月夜放水燈。會安燈籠不只是商品，而是城市的象徵——夜晚降臨，整座古鎮被燈籠點亮，溫暖的黃光映照在河面上。親手做一盞燈籠，是用雙手理解這座城市美學的方式。工作坊通常兩小時，價格約台幣300-500元。這不是觀光噱頭，而是傳統工藝的傳承。", "contact_name": null, "country_code": "VN", "english_name": "Hoi An Lantern Workshop", "ticket_price": null, "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "google_maps_url": null, "duration_minutes": null}, {"id": "34836e1f-908a-44c1-8432-f0afdf7d9ef6", "fax": null, "name": "高千穗峽谷划船", "tags": ["峽谷", "划船", "瀑布"], "type": "attraction", "notes": "宮崎縣的峽谷絕景，火山岩形成的V字形峽谷。划船穿過瀑布下方是必體驗的活動。", "phone": null, "images": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/japan/34836e1f-908a-44c1-8432-f0afdf7d9ef6-1.jpeg", "https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/japan/34836e1f-908a-44c1-8432-f0afdf7d9ef6-2.jpeg"], "address": null, "city_id": "aso", "website": null, "category": "活動體驗 / Activity", "latitude": 32.7167, "is_active": true, "longitude": 131.3, "region_id": "jp_kyushu", "country_id": "japan", "created_at": "2025-12-12T05:45:47.662276+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "高千穗峽，宮崎高千穗町的V字形峽谷，阿蘇火山噴發形成的柱狀節理、真名井瀑布、翡翠綠溪水。可划船近距離看瀑布。租船30分鐘2,需排隊。秋季紅葉、夏季新綠最美。", "contact_name": null, "country_code": "JP", "english_name": "Takachiho Gorge Boat", "ticket_price": "免費或依業者而異", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 561, "opening_hours": {"daily": "10:00-18:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 30}, {"id": "34cad996-76e8-42e0-b431-b6d653cf7cb8", "fax": null, "name": "胡志明市大劇院", "tags": null, "type": "heritage", "notes": null, "phone": null, "images": null, "address": null, "city_id": "ho-chi-minh", "website": null, "category": "景點 / Attraction", "latitude": 10.8231, "is_active": true, "longitude": 106.6297, "region_id": null, "country_id": "vietnam", "created_at": "2025-12-06T01:24:45.251076+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "胡志明市大劇院，法國殖民時期建築，1900年建成。新古典主義風格，內部裝飾華麗，紅絲絨座椅、金色雕飾、水晶吊燈。現在是胡志明市歌劇院，演出越南傳統音樂、現代劇目、AOShow。建築外觀優雅，夜晚點燈後更顯華麗。這是胡志明市最美的殖民建築之一，也是體驗越南藝術文化的好地方。可購票看演出或參加導覽。", "contact_name": null, "country_code": "VN", "english_name": "Saigon Opera House", "ticket_price": "0", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": {"daily": "09:00-18:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": null}, {"id": "34cbec93-f59d-4e94-949a-2d598c74e6b0", "fax": null, "name": "總督府", "tags": ["法國殖民建築", "歷史", "僅外觀", "免費景點", "主席府"], "type": "attraction", "notes": "即現在的「主席府」。僅能外觀拍照，不可進入。胡志明高腳屋在庭園內，需購票參觀。", "phone": null, "images": null, "address": null, "city_id": null, "website": null, "category": "歷史文化 / History & Culture", "latitude": 21.0375, "is_active": true, "longitude": 105.8336, "region_id": null, "country_id": "vietnam", "created_at": "2026-03-17T08:28:02.02406+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "河內總督府，法國殖民時期興建，現為越南主席府。黃色建築、法式庭園、優雅華麗，是河內最美的法國殖民建築之一。現為越南國家主席辦公處，僅能外觀參觀，不對外開放。胡志明曾在此工作，但他選擇住在庭園內的簡樸高腳屋而非總督府。這是河內法國殖民時期權力象徵，也是認識越南近代史的好地方。免費外觀參觀，建議搭配胡志明陵、一柱廟一起遊覽。", "contact_name": null, "country_code": "VN", "english_name": null, "ticket_price": "免費（僅外觀）", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": {"notes": "不對外開放，僅能在外拍照。庭園內的胡志明高腳屋需購票參觀（25,000越南盾）", "regular": {"open": "僅外觀", "close": ""}}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 20}, {"id": "34d5fb84-9f9c-4776-9aaa-449fa1ad1ca7", "fax": null, "name": "大阪城", "tags": null, "type": "attraction", "notes": null, "phone": null, "images": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/japan/34d5fb84-9f9c-4776-9aaa-449fa1ad1ca7-1.jpeg", "https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/japan/34d5fb84-9f9c-4776-9aaa-449fa1ad1ca7-2.jpeg"], "address": null, "city_id": "osaka", "website": null, "category": "景點 / Attraction", "latitude": 34.6873, "is_active": true, "longitude": 135.5262, "region_id": "jp_kansai", "country_id": "japan", "created_at": "2026-01-23T00:37:05.675061+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "日本三大名城之一，由豐臣秀吉於1583年建造，是大阪的象徵地標。天守閣內部設有歷史博物館，展示豐臣秀吉生平與戰國文物，頂樓可360度俯瞰大阪市景。春季櫻花盛開時，大阪城公園湧入賞櫻人潮，夜間點燈更顯金碧輝煌。周邊設有大阪歷史博物館與大阪城公園梅林。", "contact_name": null, "country_code": "JP", "english_name": "Osaka Castle", "ticket_price": "天守閣600日圓，公園免費", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 1, "opening_hours": {"daily": "09:00-17:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 90}, {"id": "3506045b-56d1-4954-b85a-ca2e314b13a3", "fax": null, "name": "峴港書店", "tags": ["書店", "閱讀", "文化"], "type": "attraction", "notes": null, "phone": null, "images": null, "address": null, "city_id": "da-nang", "website": null, "category": "購物 / Shopping", "latitude": null, "is_active": true, "longitude": null, "region_id": null, "country_id": "vietnam", "created_at": "2026-04-04T11:24:19.845+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T