.7797, "is_active": true, "longitude": 106.7, "region_id": null, "country_id": "vietnam", "created_at": "2025-11-01T13:04:50.83683+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "胡志明市殖民時期的中央郵局，法式建築典雅華麗。挑高的大廳、彩繪玻璃、拱形天花板，展現19世紀建築之美。郵局至今仍在營運，可以寄明信片回家。這是胡志明市必訪的歷史建築。", "contact_name": null, "country_code": "VN", "english_name": "Central Post Office", "ticket_price": "免費參觀", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": {"daily": "07:00-19:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 30}, {"id": "3544fa70-cfb2-4b00-8e4b-5b76f261e8a3", "fax": null, "name": "聖淘沙島", "tags": ["娛樂", "主題樂園", "海灘", "必去", "親子"], "type": "attraction", "notes": "新加坡最大的娛樂島嶼，有環球影城、S.E.A海洋館、海灘。可搭乘纜車或輕軌前往，適合安排一整天。", "phone": null, "images": null, "address": null, "city_id": null, "website": null, "category": "自然風景 / Nature", "latitude": 1.2494, "is_active": true, "longitude": 103.8303, "region_id": null, "country_id": "singapore", "created_at": "2025-12-06T02:06:36.371189+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "新加坡聖淘沙島，度假與娛樂島嶼。環球影城、SEA海洋館、水上探險樂園、沙灘、賭場、高級度假村集中於此。纜車連接市區，島上有單軌電車接駁。白天玩樂園、晚上看時光之翼燈光秀，適合親子遊。這是新加坡最歡樂的地方，需要一整天才能玩透。", "contact_name": null, "country_code": "SG", "english_name": null, "ticket_price": "入島免費，各景點另計（環球影城約SGD 80起）", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 722, "opening_hours": {"daily": "島嶼全天開放，各設施營業時間不同"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 480}, {"id": "357cc6a3-c0c7-4a17-a2d2-81269b137cb4", "fax": null, "name": "河內蓮花水療", "tags": ["Spa", "按摩", "放鬆"], "type": "attraction", "notes": null, "phone": null, "images": null, "address": null, "city_id": "hanoi", "website": null, "category": "活動體驗 / Activity", "latitude": 21.0625982, "is_active": true, "longitude": 105.8234622, "region_id": null, "country_id": "vietnam", "created_at": "2026-04-04T11:17:39.05+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "《河內蓮花水療》結合越南傳統按摩與現代Spa技術。療程從足浴開始,使用香茅、薄荷等草藥。按摩師力道專業,會針對肩頸、腰背重點部位加強。環境乾淨舒適,價格比曼谷、峇里島便宜一半。河內的Spa不追求奢華裝潢,而是專注於療程本身——技術到位、環境舒適、價格合理。建議選擇舊城區的中價位Spa,避開過度觀光化的高價店。一個半小時的全身按摩約台幣600-800元,是旅行疲勞的最佳解方。", "contact_name": null, "country_code": "VN", "english_name": "Lotus Spa Hanoi", "ticket_price": null, "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "google_maps_url": null, "duration_minutes": null}, {"id": "35a746f5-41e2-4edc-8d93-6e7d8f6806d6", "fax": null, "name": "大浦天主堂", "tags": null, "type": "attraction", "notes": null, "phone": null, "images": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/japan/35a746f5-41e2-4edc-8d93-6e7d8f6806d6-1.jpeg", "https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/japan/35a746f5-41e2-4edc-8d93-6e7d8f6806d6-2.jpeg"], "address": null, "city_id": "nagasaki", "website": null, "category": "景點 / Attraction", "latitude": 32.7339, "is_active": true, "longitude": 129.8656, "region_id": "jp_kyushu", "country_id": "japan", "created_at": "2026-01-23T00:36:41.447801+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "長崎大浦天主堂，日本最古老的哥德式教堂，1864年建造，國寶建築。彩繪玻璃、尖塔、白牆，紀念日本26聖殉教者。隱れキリシタン歷史震撼。", "contact_name": null, "country_code": "JP", "english_name": "Oura Church", "ticket_price": "免費或依業者而異", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 2, "opening_hours": {"daily": "10:00-18:00"}, "deleted_reason": null, "google_maps_url": null, "dur