e": null, "images": ["https://images.unsplash.com/photo-1528360983277-13d401cdc186?w=800", "https://images.unsplash.com/photo-1480796927426-f609979314bd?w=800"], "address": null, "city_id": "kyoto", "website": null, "category": "景點 / Attraction", "latitude": null, "is_active": true, "longitude": null, "region_id": "jp_kansai", "country_id": "japan", "created_at": "2026-04-06T22:24:11.874405+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "這是極為罕見的舞妓見習（Maiko）體驗，由真正的置屋媽媽桑親自指導。不是一般的變裝體驗，而是學習成為舞妓的基礎訓練。從清晨開始，學習如何盤髮髻、塗白粉（白塗り）、畫眉毛、點唇紅。穿著正統的舞妓和服（非觀光用簡化版），學習走路方式（內八字、小碎步）、座姿、鞠躬禮儀。學習三味線基礎與簡單舞蹈動作。午餐體驗舞妓的便當文化。下午參觀茶屋，了解舞妓的一日作息。這是深入花街文化的獨特機會，讓你理解舞妓不是藝妓，而是學徒的嚴格訓練。", "contact_name": null, "country_code": "JP", "english_name": "Kyoto Maiko Apprentice Experience", "ticket_price": null, "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 0}, {"id": "38204869-a291-434c-8d98-c3bd1085ddce", "fax": null, "name": "森林精靈露台", "tags": ["森林", "市集", "童話", "夜景"], "type": "attraction", "notes": "新富良野王子飯店的童話小屋群，手工藝品店與咖啡廳藏身森林間，冬夜燈光夢幻。", "phone": null, "images": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/japan/38204869-a291-434c-8d98-c3bd1085ddce-1.jpeg", "https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/japan/38204869-a291-434c-8d98-c3bd1085ddce-2.jpeg"], "address": null, "city_id": "furano", "website": null, "category": "活動體驗 / Activity", "latitude": 43.3311, "is_active": true, "longitude": 142.3822, "region_id": "jp_hokkaido", "country_id": "japan", "created_at": "2025-10-28T06:41:24.541116+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "北海道森林精靈露台，富良野新富良野王子飯店內的手作工房村，15棟木屋、玻璃工藝、皮革、木工、蠟燭，森林中如精靈村。", "contact_name": null, "country_code": "JP", "english_name": "Ningle Terrace", "ticket_price": "免費或依業者而異", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 2, "opening_hours": {"daily": "10:00-18:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 60}, {"id": "38264f52-c456-4b53-b1f9-b95245d2800b", "fax": null, "name": "海女體驗", "tags": ["文化體驗", "海女", "UNESCO", "潛水", "傳統"], "type": "experience", "notes": "濟州海女文化被列為UNESCO無形文化遺產。可參加體驗活動了解海女的工作方式，甚至嘗試下水抓海鮮。部分海邊可看到海女現場作業。\n\n旅遊提示：牛島和城山浦有海女表演和體驗活動", "phone": null, "images": null, "address": null, "city_id": "jeju", "website": null, "category": "自然風景 / Nature", "latitude": 33.46, "is_active": true, "longitude": 126.94, "region_id": null, "country_id": "korea", "created_at": "2025-12-06T01:49:09.765721+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "濟州島海女博物館，展示海女文化的博物館。濟州海女徒手潛水採集海產，是UNESCO非物質文化遺產。博物館介紹海女歷史、工具、生活。附近有海女表演，可以看海女實際潛水捕撈。這是濟州獨有的文化，也是認識濟州女性堅韌精神的地方。", "contact_name": null, "country_code": "KR", "english_name": "Haenyeo Experience", "ticket_price": "成人1100韓元", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": {"daily": "09:00-18:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 60}, {"id": "3877949a-87e1-44e2-8171-cf6076c60faa", "fax": null, "name": "水之宮殿", "tags": ["宮殿", "水池", "建築", "歷史", "拍照"], "type": "heritage", "notes": "即Tirta Gangga水宮，建於1946年的皇家水上宮殿。有噴泉、雕像、荷花池。可在石階上拍美照。是峇里島東部的必訪景點。\n\n旅遊提示：人少好拍，建議早上去", "phone": null, "images": null, "address": null, "city_id": "bali", "website": null, "category": "自然風景 / Nature", "latitude": -8.2271303, "is_active": true, "longitude": 115.1919203, "region_id": null, "country_id": "indonesia", "created_at": "2025-12-06T02:06:54.660883+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updat