ulture", "latitude": 35.8562, "is_active": true, "longitude": 129.2247, "region_id": null, "country_id": "korea", "created_at": "2025-12-06T07:01:18.813365+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "慶州校村韓屋村，保留傳統韓屋聚落的村莊。慶州崔氏家族世居於此，韓屋、石牆、大門展現兩班貴族生活。可以體驗韓屋住宿、傳統茶道、韓服體驗。這裡比北村更清幽，遊客較少。村內有校村麵包店，紅豆麵包是招牌。這是認識慶州傳統建築與兩班文化的好地方，也是韓屋體驗的首選。適合慢遊，預留2-3小時。", "contact_name": null, "country_code": "KR", "english_name": "Gyeongju Gyochon Hanok Village", "ticket_price": "免費或依業者而異", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 776, "opening_hours": {"daily": "10:00-20:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 60}, {"id": "396ecb78-0168-4bbe-8527-05dd9430f611", "fax": null, "name": "和平紀念公園", "tags": null, "type": "park", "notes": null, "phone": null, "images": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/japan/396ecb78-0168-4bbe-8527-05dd9430f611-1.jpeg", "https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/japan/396ecb78-0168-4bbe-8527-05dd9430f611-2.jpeg"], "address": null, "city_id": "hiroshima", "website": null, "category": "自然風景 / Nature", "latitude": 34.3931715, "is_active": true, "longitude": 132.4523008, "region_id": "jp_chugoku", "country_id": "japan", "created_at": "2025-12-06T01:55:41.174973+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "長崎和平紀念公園，長崎原子彈爆炸遺址改建的公園。和平祈念像高9.7公尺，右手指天、左手平伸、閉眼。折鶴塔、和平噴泉、各國贈送的和平紀念碑都在園內。", "contact_name": null, "country_code": "JP", "english_name": "Peace Memorial Park", "ticket_price": "成人300-500日圓", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": {"daily": "09:00-17:00"}, "deleted_reason": null, "google_maps_url": null, "duration