site": null, "category": "景點 / Attraction", "latitude": null, "is_active": true, "longitude": null, "region_id": null, "country_id": "thailand", "created_at": "2026-04-06T22:24:02.795028+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "不是騎大象，而是真正理解並協助大象保育。在專業獸醫和訓練師陪同下，為大象準備食物、餵食、洗澡，並了解每隻大象的救援故事。", "contact_name": null, "country_code": "TH", "english_name": "Chiang Mai Elephant Sanctuary VIP Keeper Experience", "ticket_price": null, "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 0}, {"id": "3ae3f50d-a0fe-4ef8-bc5a-2ca7b909704c", "fax": null, "name": "六合夜市", "tags": null, "type": "attraction", "notes": null, "phone": null, "images": null, "address": "高雄市新興區六合二路", "city_id": "b4e5f406-cf71-4c32-a2e4-183c39038442", "website": null, "category": "購物 / Shopping", "latitude": 22.6318, "is_active": true, "longitude": 120.2986, "region_id": null, "country_id": "taiwan-country-001", "created_at": "2026-01-09T03:31:23.908376+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "高雄六合夜市，高雄最老字號的觀光夜市。木瓜牛奶創始店、烤魷魚、海鮮粥、臭豆腐、鄭老牌木瓜牛奶都是經典。夜市不長約300公尺，但攤位密集，美食集中度高。靠近高雄車站，交通方便，是外地遊客認識高雄夜市文化的第一站。雖然觀光化明顯，但價格合理，仍保留著南台灣夜市的熱情。", "contact_name": null, "country_code": "TW", "english_name": "Liuhe Night Market", "ticket_price": "免費入場", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 30, "opening_hours": {"daily": "17:00-01:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 90}, {"id": "3b0df56c-4b0a-483f-837f-dd596df732f8", "fax": null, "name": "倉敷美觀地區", "tags": ["UNESCO候選", "運河", "古街", "必訪"], "type": "attraction", "notes": "江戶時代保存完整的運河商業區，建議安排3小時漫步，白天和夜晚各有風情", "phone": null, "images": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/japan/3b0df56c-4b0a-483f-837f-dd596df732f8-1.jpeg"], "address": null, "city_id": null, "website": "https://www.kurashiki-tabi.jp/", "category": "歷史文化 / History & Culture", "latitude": 34.6662, "is_active": true, "longitude": 133.9181, "region_id": "jp_chugoku", "country_id": "japan", "created_at": "2026-03-17T03:16:16.356483+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "江戶時代保存完整的運河商業區，白壁黑瓦的倉庫群倒映在運河中。石板路在腳下延伸，柳樹垂在水邊，這是日本重要傳統建築保存地區。白天漫步古街，夜晚欣賞點燈後的浪漫，倉敷在不同時刻呈現不同的美。", "contact_name": null, "country_code": "JP", "english_name": "Kurashiki Bikan Historical Quarter", "ticket_price": "免費（進入倉敷民藝館等館舍需另購票）", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": {"daily": "全天開放，街道商店約10:00-18:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 180}, {"id": "3b475683-0be1-4331-93e7-b4ace6eab4ca", "fax": null, "name": "夜市", "tags": ["夜市", "週末市集", "在地生活"], "type": "attraction", "notes": null, "phone": null, "images": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/thailand/3b475683-0be1-4331-93e7-b4ace6eab4ca-1.jpeg", "https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/thailand/3b475683-0be1-4331-93e7-b4ace6eab4ca-2.jpeg"], "address": null, "city_id": "chiang-mai", "website": null, "category": "活動體驗 / Activity", "latitude": 18.9082311, "is_active": true, "longitude": 98.9494417, "region_id": null, "country_id": "thailand", "created_at": "2025-10-27T15:26:40.818404+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "《夜市》在清邁，夜市不是單一地點，而是一種生活節奏。週六夜市在Wualai路，週日夜市在Ratchadamnoen路，平日則有Night Bazaar。天色轉暗後醒來，長街兩側攤位依序點亮，木雕、銀飾、手工皂與棉麻衣物在暖黃燈泡下排列成行。烤肉串的煙霧與芒果糯米飯的椰香交織，人群在攤位間緩步穿梭。這裡既非觀光包裝的夜間市集，也不是純粹本地人的菜市場，而是兩者之間的模糊地帶——泰北手作者在此尋找客源，旅人在異國街燈下練習殺價。夜市的節奏鬆散而真實，沒有華麗舞台，只有日常商業在夜幕中自然延伸的樣貌。", "contact_name": null, "country_code": "TH", "english_name": "Night Market", "ticket_price": "免費或依業者而異", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 2, "opening_hours": {"daily": "18:00-23:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 120}, {"id": "3b508f18-67a1-4ab9-97a8-0570332b275c", "fax": null, "name": "羅馬金宮劇場人妖秀", "tags": ["表演", "文化", "夜生活", "必遊"], "type": "表演秀", "notes": null, "phone": null, "images": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/thailand/3b508f18-67a1-4ab9-97a8-0570332b275c-1.jpg", "https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/thailand/3b508f18-67a1-4ab9-97a8-0570332b275c-2.jpg"], "address": null, "city_id": "pattaya", "website": null, "category": "景點 / Attraction", "latitude": 12.9046064, "is_active": true, "longitude": 100.8775011, "region_id": null, "country_id": "thailand", "created_at": "2026-03-29T11:41:10.003391+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "《羅馬金宮劇場》模仿古羅馬競技場外觀，是芭達雅規模最大的人妖秀場。演出融合歌舞、特技、華麗服裝，演員妝容精緻、身材姣好，演技專業。每晚兩場表演，曲目涵蓋泰國、中國、韓國、歐美流行歌曲。演出後可與演員合照，是體驗泰國特色文化、適合全家觀賞的娛樂節目。", "contact_name": null, "country_code": "TH", "english_name": "Colosseum Show Pattaya", "ticket_price": null, "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": "18:00-23:00", "deleted_reason": null, "google_maps_url": null, "duration_minutes": 90}, {"id": "3b9fb939-129b-470a-bc92-c0b9136b11e6", "fax": null, "name": "可可島", "tags": ["離島", "浮潛", "水上活動", "珊瑚", "一日遊"], "type": "attraction", "notes": "關島南部的私人小島，搭船約10分鐘。有浮潛、香蕉船、水上摩托車等水上活動。珊瑚礁生態豐富，海水能見度極高。是關島水上活動的最佳去處。\n\n旅遊提示：建議參加一日遊套裝，含船票和水上活動", "phone": null, "images": null, "address": 