": null, "duration_minutes": 20}, {"id": "433dbb14-1db2-444a-9dcd-793ca9ca2165", "fax": null, "name": "濱海道", "tags": ["自然", "健行"], "type": "attraction", "notes": "釜山海雲台的海岸散步道，連接海雲台和松亭海灘。沿途海景壯觀，是散步和慢跑的好地方。", "phone": null, "images": null, "address": null, "city_id": "busan", "website": null, "category": "活動體驗 / Activity", "latitude": 35.15, "is_active": true, "longitude": 129.15, "region_id": null, "country_id": "korea", "created_at": "2025-10-27T15:26:40.818404+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "濟州濱海道，濟州偶來小路代表路線之一。沿海岸線健行步道景色壯麗，玄武岩海岸、藍色大海、油菜花田、橘子園、燈塔，春天櫻花粉嫩、秋天芒草搖曳。難度適中，沿途有咖啡廳、休憩點。這是徒步愛好者的天堂，也是認識濟州海岸風光的最佳方式。建議穿著舒適鞋子，攜帶水與點心。步行約4-6小時。", "contact_name": null, "country_code": "KR", "english_name": "Coastal Path", "ticket_price": "免費或依業者而異", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 1, "opening_hours": {"daily": "全天開放"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 180}, {"id": "434984c7-e216-4cce-8abd-4ee033b3ca55", "fax": null, "name": "高千穗峽谷", "tags": ["必去", "峽谷", "瀑布", "九州", "宮崎"], "type": "attraction", "notes": "V 字峽谷中的瀑布傾瀉而下，划船穿越峽谷是最佳體驗方式。", "phone": null, "images": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/workspace-files/attractions/1767162447630_dygmol.jpg"], "address": null, "city_id": "aso", "website": null, "category": "景點 / Attraction", "latitude": 32.7128, "is_active": true, "longitude": 131.3061, "region_id": "jp_kyushu", "country_id": "japan", "created_at": "2025-12-17T03:11:57.904376+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "高千穗峽，宮崎高千穗町的V字形峽谷，阿蘇火山噴發形成的柱狀節理、真名井瀑布、翡翠綠溪水。可划船近距離看瀑布。租船30分鐘2,需排隊。秋季紅葉、夏季新綠最美。", "contact_name": null, "country_code": "JP", "english_name": "Takachiho Gorge", "ticket_price": "免費或依業者而異", "workspace_id": "