ges": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/japan/43b830a3-425f-4400-b085-44f36f6e290b-1.jpeg", "https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/japan/43b830a3-425f-4400-b085-44f36f6e290b-2.jpeg"], "address": null, "city_id": "kanazawa", "website": null, "category": "自然風景 / Nature", "latitude": 36.775, "is_active": true, "longitude": 136.7667, "region_id": "jp_chubu", "country_id": "japan", "created_at": "2025-12-05T04:43:38.422857+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "石川千里濱渚海濱公路，日本唯一可以開車行駛的沙灘，全長約8公里。細緻堅實的沙子可承受車輛重量，開車、騎自行車、散步都可以。海風、海浪、日本海全景，體驗獨特。免費通行，建議退潮時前往。夏季適合玩水。", "contact_name": null, "country_code": "JP", "english_name": "Chirihama Nagisa Driveway", "ticket_price": "免費或依業者而異", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": {"daily": "全天開放"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 60}, {"id": "43bee575-c988-4bea-a9b6-b9994e1c492d", "fax": null, "name": "土俗村蔘雞湯", "tags": null, "type": "food", "notes": null, "phone": null, "images": null, "address": null, "city_id": "seoul", "website": null, "category": "景點 / Attraction", "latitude": 37.5776803, "is_active": true, "longitude": 126.9715276, "region_id": null, "country_id": "korea", "created_at": "2025-12-06T01:49:08.464504+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "土俗村蔘雞湯，景福宮旁最有名的蔘雞湯餐廳，1983年開業。整隻童雞塞入糯米、紅棗、栗子、人蔘燉煮，湯頭濃郁滋補。排隊名店，用餐尖峰需等1-2小時。這是首爾必吃美食，也是韓國傳統補品代表。一碗約2.5萬韓元。夏天最熱門。", "contact_name": null, "country_code": "KR", "english_name": "Tosokchon Samgyetang", "ticket_price": "免費或依業者而異", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": {"daily": "10:00-20:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": null}, {"id": "43ef5ab5-c4ee-4f8f-b7df-be72c62cb209", "fax": null, "name": "胡志明市動物園", "tags": ["動物園", "植物園", "親子"], "type": "attraction", "notes": null, "phone": null, "images": null, "address": null, "city_id": "ho-chi-minh", "website": null, "category": "活動體驗 / Activity", "latitude": 10.7878424, "is_active": true, "longitude": 106.7063352, "region_id": null, "country_id": "vietnam", "created_at": "2026-04-04T11:19:46.247+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "《胡志明市動物園》建於1865年,是世界最古老的動物園之一。園區混合動物展示與植物園,老樹參天,環境清幽。動物種類不多,展區設計老舊,但正因如此保有某種復古氛圍。週末家庭遊客眾多,平日則是退休老人散步的地方。這不是現代化的野生動物園,而是城市歷史的一部分——法國人建造它,越南人使用它,至今依然運作。門票便宜,適合帶孩子來消磨半天。", "contact_name": null, "country_code": "VN", "english_name": "Saigon Zoo and Botanical Gardens", "ticket_price": null, "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "google_maps_url": null, "duration_minutes": null}, {"id": "441f9de1-29b8-4152-9c40-55cd49a8c4b8", "fax": null, "name": "桂林米粉", "tags": null, "type": "food", "notes": null, "phone": null, "images": null, "address": null, "city_id": null, "website": null, "category": "景點 / Attraction", "latitude": 25.2744, "is_active": true, "longitude": 110.299, "region_id": "cn_southwest", "country_id": "china", "created_at": "2025-12-06T02:12:19.15133+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "桂林米粉，中國知名景點，值得探訪。", "contact_name": null, "country_code": "CN", "english_name": null, "ticket_price": "免費或依業者而異", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 509, "opening_hours": {"daily": "08:30-17:30"}, "deleted_reason": null, "google_maps_url": null, "duration_