.jpeg", "https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/thailand/46cee1b3-d093-4cb5-a988-819f18e56134-2.jpeg"], "address": null, "city_id": "bangkok", "website": null, "category": "活動體驗 / Activity", "latitude": 13.7563, "is_active": true, "longitude": 100.5018, "region_id": null, "country_id": "thailand", "created_at": "2025-10-28T08:53:13.904914+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "《暹羅商圈》集結Siam Paragon、Central World、MBK等超級購物中心。泰國設計品牌、國際精品、海洋世界水族館、美食街，BTS暹羅站交通便利，曼谷最潮購物區。", "contact_name": null, "country_code": "TH", "english_name": "Siam Square", "ticket_price": "免費或依業者而異", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 9, "opening_hours": {"daily": "09:00-18:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 240}, {"id": "46d7b557-de6a-4d0a-b1ae-c6b136b455d2", "fax": null, "name": "美功鐵道市集", "tags": ["市集", "鐵道", "在地生活"], "type": "shopping", "notes": "從曼谷市區需1.5小時車程。建議搭配安帕瓦水上市場一日遊。火車時刻表可能調整請確認。注意安全不要太靠近軌道。", "phone": null, "images": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/thailand/46d7b557-de6a-4d0a-b1ae-c6b136b455d2-1.jpeg", "https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/thailand/46d7b557-de6a-4d0a-b1ae-c6b136b455d2-2.jpeg"], "address": null, "city_id": "bangkok", "website": null, "category": "景點 / Attraction", "latitude": 13.7524938, "is_active": true, "longitude": 100.4935089, "region_id": null, "country_id": "thailand", "created_at": "2025-12-06T08:00:05.134985+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "《美功鐵道市集》存在於鐵軌與生活的縫隙之間。攤商在枕木兩側鋪開新鮮蔬果、醃漬海鮮與香料，當火車鳴笛逼近，遮陽棚像摺紙般快速收起,列車以不到半公尺的距離緩緩駛過攤位,車身幾乎要刮到懸掛的香蕉串。這不是為觀光設計的表演，而是數十年來在地居民與國營鐵路協商出的日常節奏——每天八班次，精準到分鐘的默契。站在月台看火車離去後攤販瞬間復位，你會理解曼谷人如何在有限空間裡創造最大效益，那是一種務實又充滿韌性的生存美學。", "contact_name": null, "country_code": "TH", "english_name": null, "ticket_price": "免費或依業者而異", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 470, "opening_hours": {"daily": "09:00-18:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 180}, {"id": "46fe9a15-53ed-4315-83ff-b78fffd5b795", "fax": null, "name": "柳廚房 La Yeon", "tags": null, "type": "food", "notes": null, "phone": null, "images": null, "address": null, "city_id": "seoul", "website": null, "category": "景點 / Attraction", "latitude": 37.5555154, "is_active": true, "longitude": 127.0051801, "region_id": null, "country_id": "korea", "created_at": "2025-12-06T01:49:07.687226+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "柳廚房LaYeon，新羅酒店內米其林三星韓式FineDining，主廚林正植將傳統宮廷料理現代化。從食材到擺盤都極致講究，套餐約20-30萬韓元。這是首爾最頂級的韓式餐廳，也是美食愛好者朝聖地。建議提前數週預訂。正裝為佳。", "contact_name": null, "country_code": "KR", "english_name": "La Yeon", "ticket_price": "免費或依業者而異", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": {"daily": "10:00-20:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": null}, {"id": "47356a0a-1201-4a18-b0c1-35e67928ac38", "fax": null, "name": "富良野起司工房", "tags": null, "type": "attraction", "notes": null, "phone": null, "images": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/japan/47356a0a-1201-4a18-b0c1-35e67928ac38-1.jpeg", "https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/japan/47356a0a-1201-4a18-b0c1-35e67928ac38-2.jpeg"], "address": null, "city_id": "furano", "website": null, "category": "景點 / Attraction", "latitude": 43.3428, "is_active": true, "longitude": 142.3831, "region_id": "jp_hokkaido", "country_id": "japan", "created_at": "2025-12-06T01:24:29.539855+0