3+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "象島，埃及古文明遺跡，見證法老王朝數千年歷史，展現古埃及建築藝術與文化成就。", "contact_name": null, "country_code": "EG", "english_name": "Elephantine Island", "ticket_price": "依官網而定", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": {"open": "08:00", "close": "17:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 90}, {"id": "47945f7c-ecc2-4313-b099-1975aef2618e", "fax": null, "name": "虎白", "tags": null, "type": "food", "notes": null, "phone": null, "images": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/japan/47945f7c-ecc2-4313-b099-1975aef2618e-1.jpeg", "https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/japan/47945f7c-ecc2-4313-b099-1975aef2618e-2.jpeg"], "address": null, "city_id": "tokyo", "website": null, "category": "景點 / Attraction", "latitude": 35.6651148, "is_active": true, "longitude": 139.7097317, "region_id": "jp_kanto", "country_id": "japan", "created_at": "2025-12-06T01:49:03.223025+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "金澤虎白，金澤米其林三星懷石料理，主廚小泉瑛人專注於加賀料理的現代詮釋。食材講究、擺盤藝術，套餐約30,000-50,這是金澤最頂級的餐廳，也是美食愛好者朝聖地。建議提前數月預訂。正裝為佳。午餐較便宜。", "contact_name": null, "country_code": "JP", "english_name": "Kohaku", "ticket_price": "免費或依業者而異", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": {"daily": "10:00-18:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": null}, {"id": "47b4b51b-09b7-4dc5-91d6-56fd2e091d71", "fax": null, "name": "天龍寺", "tags": null, "type": "temple", "notes": "嵐山最重要的禪寺，曹源池庭園以嵐山為借景，是日本庭園藝術的典範。", "phone": null, "images": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/pub