市區的山，纜車+迷你纜車登頂。360度俯瞰札幌市區、石狩灣、夜景璀璨。這是札幌必訪景點，也是看夜景的好地方。纜車來回2,100日圓，建議傍晚前往看日落與夜景。可搭配大通公園、圓山動物園一起遊覽。山頂有餐廳可邊用餐邊看夜景。", "contact_name": null, "country_code": "JP", "english_name": "Mt. Moiwa Ropeway", "ticket_price": "免費或依業者而異", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 3, "opening_hours": {"daily": "全天開放"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 90}, {"id": "53526df4-0e41-4597-8b0d-04cbfa001483", "fax": null, "name": "富國島沙灘", "tags": ["海灘", "富國島", "日落"], "type": "beach", "notes": "越南馬爾地夫，白沙灘與夕陽美景，世界最長跨海纜車。", "phone": null, "images": null, "address": null, "city_id": "phu-quoc", "website": null, "category": "自然風景 / Nature", "latitude": 10.2268, "is_active": true, "longitude": 103.958, "region_id": null, "country_id": "vietnam", "created_at": "2025-12-06T01:55:54.42288+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "富國島海灘，富國島西岸最長的海灘，長約20公里。白沙灘、清澈海水、日落美景，度假氛圍濃厚。JW Marriott、InterContinental、Vinpearl等五星飯店都在這裡。這是富國島必訪景點，也是看日落的好地方。免費參觀，建議預留半天。可搭配富國島夜市一起遊覽。傍晚夕陽時最美。可SUP、浮潛、香蕉船。", "contact_name": null, "country_code": "VN", "english_name": "Phu Quoc Beach", "ticket_price": "免費", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 634, "opening_hours": {"daily": "全天開放"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 480}, {"id": "535ebd72-3132-4cb0-ba32-450e00a0b68b", "fax": null, "name": "螢⽕蟲船遊之旅", "tags": null, "type": "attraction", "notes": null, "phone": null, "images": null, "address": null, "city_id": null, "website": null, "category": "景點 / Attraction", "latitude": null, "is_active": true, "longitude": null, "region_id": null, "country_id": "malaysia", "created_at": "2026-04-10T06:49:18.654724+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by