eated_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "《書街》Nguyen Van Binh Book Street 是胡志明市中心的行人徒步書街,兩側是書店、咖啡館與出版社。週末有戶外書市,獨立出版品、二手書、藝術書籍攤位林立。這裡不只賣書,還有讀書會、作家簽書會、文學講座。夜晚點燈後氛圍溫馨,年輕人坐在街邊階梯上看書聊天。書街的存在證明:即使在數位時代,紙本閱讀依然有其魅力。這是胡志明文青的聚集地,也是城市文化品味的指標。", "contact_name": null, "country_code": "VN", "english_name": "Nguyen Van Binh Book Street", "ticket_price": null, "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "google_maps_url": null, "duration_minutes": null}, {"id": "564eb1e9-2445-467c-959c-8f1bdf5788b3", "fax": null, "name": "檳城娘惹博物館", "tags": ["博物館", "娘惹文化", "建築", "歷史", "檳城"], "type": "museum", "notes": "又稱僑生博物館，展示海峽華人（峇峇娘惹）文化。建築本身是19世紀富商大宅，有精美的瓷磚和木雕。是了解娘惹文化的最佳去處。\n\n旅遊提示：有導覽團講解，更能了解文化背景", "phone": null, "images": null, "address": null, "city_id": "penang", "website": null, "category": "歷史文化 / History & Culture", "latitude": 5.4141, "is_active": true, "longitude": 100.3288, "region_id": null, "country_id": "malaysia", "created_at": "2025-12-06T02:06:44.30564+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "檳城或馬六甲娘惹博物館，展示峇峇娘惹文化。傳統服飾、家具、瓷器、珠寶、婚嫁習俗都有展示。老宅建築本身也是文化財。這是認識娘惹文化的最佳場所，也是檳城/馬六甲必訪景點。門票約20馬幣，建議預留1-2小時。可搭配喬治市老街或雞場街一起遊覽。", "contact_name": null, "country_code": "MY", "english_name": null, "ticket_price": "成人5-20馬幣", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 829, "opening_hours": {"closed": "週一", "tue_sun": "09:00-18:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 60}, {"id": "5650edbf-5744-4688-99be-a12586dc8170", "fax": null, "name": "河內老城區三十六行街", "tags": ["老街", "購物", "河內"], "type": "shopping", "notes": "千年歷史的商業街區，每條街專賣特定商品如絲綢、銀器、藥材等。週末有步行街夜市。", "phone": null, "images": null, "address": null, "city_id": "hanoi", "website": null, "category": "景點 / Attraction", "latitude": 21.034, "is_active": true, "longitude": 105.85, "region_id": null, "country_id": "vietnam", "created_at": "2025-12-06T08:00:07.635742+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "河內老城區36街，河內最古老的商業區，因36種手工行業得名。每條街專賣一種商品：錫器街、絲綢街、藥材街、鞋街、銀器街等。狹窄街道兩旁是法式殖民建築與傳統筒狀屋。摩托車、人力車、攤販穿梭其間，充滿活力。這是體驗越南庶民生活的最佳地點，也是河內必訪景點。建議步行或騎自行車慢遊，預留半天。", "contact_name": null, "country_code": "VN", "english_name": null, "ticket_price": "0", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 377, "opening_hours": {"open": "全天開放"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 180}, {"id": "566d730a-f536-420b-a4fd-8924068d451f", "fax": null, "name": "南普陀寺", "tags": null, "type": "temple", "notes": null, "phone": null, "images": null, "address": null, "city_id": null, "website": null, "category": "歷史文化 / History & Culture", "latitude": 24.5438732, "is_active": true, "longitude": 118.0768065, "region_id": null, "country_id": "china", "created_at": "2025-12-06T01:13:27.025374+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "南普陀寺，中國佛教或道教寺廟，展現中國傳統宗教建築藝術與文化。", "contact_name": null, "country_code": "CN", "english_name": "Nanputuo Temple", "ticket_price": "成人10-30元", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": {"daily": "08:00-17:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": null}, {"id": "5678d110-54b9-41e1-b952-582484cdf450", "fax": null, "name": "Ultraviolet", "tags": null, "type": "food", "notes": null, "phone": null, "images": null, "address": null, "city_id": null, "website": null, "category": "景點 / Attraction", "latitude": 31.2312707, "is_active": true, "longitude": 121.4700152, "region_id": "cn_east", "country_id": "china", "created_at": "2025-12-06T01:49:14.386579+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "上海外灘Ultraviolet，法國名廚Paul Pairet的實驗性餐廳，全球首家多感官用餐體驗。每晚僅一桌10位客人，20道菜配合燈光、音樂、影像、氣味變化。用餐過程如同藝術表演，顛覆傳統餐飲概念。米其林三星，需提前數月預訂，價格昂貴但體驗獨一無二。", "contact_name": null, "country_code": "CN", "english_name": "Ultraviolet by Paul Pairet", "ticket_price": "套餐約6000-8000元/人（含酒配餐更高）", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": {"closed": "週日、週一", "tue_sat": "僅晚餐，每晚一場約18:30開始"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 240}, {"id": "568a10c8-3276-464d-97a0-b971e794d5ca", "fax": null, "name": "布城粉紅清真寺", "tags": ["清真寺", "粉紅", "地標", "必訪"], "type": "attraction", "notes": null, "phone": null, "images": ["https://wzvwmawpkapcmkfmkvav.supabase.co/storage/v1/object/public/resources/attractions/568a10c8-3276-464d-97a0-b971e794d5ca/1775804410461_zzeronucmv.jpg"], "address": "", "city_id": null, "website": "http://www.majlisagama.gov.my/", "category": "歷史文化 / History & Culture", "latitude": 2.9364, "is_active": true, "longitude": 101.6941, "region_id": null, "country_id": "malaysia", "created_at": "2026-03-17T04:57:19.278377+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "馬來西亞最美的清真寺之一，粉紅色的圓頂與尖塔在陽光下格外夢幻。清真寺建在人工湖畔，倒影映照在水面上，形成完美的對稱畫面。這座融合波斯與馬來建築風格的清真寺，不只是宗教場所，更是布城的地標與藝術品。", "contact_name": null, "country_code": "MY", "english_name": "Putra Mosque", "ticket_price": "免費（外觀參觀）", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": {"daily": "09:00-18:00（祈禱時間不開放）"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 60}, {"id": "56b8b64f-62a7-42ee-909d-ede3d