ps://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/thailand/5d7dcc91-5a8e-4123-8c85-e6d4eb5856c9-2.jpeg"], "address": null, "city_id": "krabi", "website": null, "category": "自然風景 / Nature", "latitude": 7.7407, "is_active": true, "longitude": 98.7784, "region_id": null, "country_id": "thailand", "created_at": "2025-12-06T07:11:12.134572+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "皮皮島，安達曼海上的熱帶天堂。碧綠海水、白沙灘、石灰岩峭壁，景色如畫。瑪雅灣因電影《海灘》聲名大噪。浮潛、深潛都很棒，海底珊瑚豐富。從普吉或喀比搭船約2小時。大PP島有住宿，小PP島是浮潛聖地。這是泰國最美的島嶼之一。", "contact_name": null, "country_code": "TH", "english_name": "Phi Phi Islands", "ticket_price": "國家公園費400泰銖，船票約450-1200泰銖", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 202, "opening_hours": {"daily": "全天，船班約08:00-17:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 480}, {"id": "5d88575b-9bf8-4a83-b9b3-27ecfdd7f4e7", "fax": null, "name": "蘭納民俗博物館", "tags": ["博物館", "文化", "蘭納", "歷史"], "type": "attraction", "notes": "清邁三大國王紀念碑旁的博物館，展示泰北蘭納王國的歷史文化。傳統建築和文物展現清邁獨特的文化底蘊。", "phone": null, "images": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/thailand/5d88575b-9bf8-4a83-b9b3-27ecfdd7f4e7-1.jpeg", "https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/thailand/5d88575b-9bf8-4a83-b9b3-27ecfdd7f4e7-2.jpeg"], "address": null, "city_id": "chiang-mai", "website": null, "category": "歷史文化 / History & Culture", "latitude": 18.7874, "is_active": true, "longitude": 98.9867, "region_id": null, "country_id": "thailand", "created_at": "2025-10-28T06:44:15.619797+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "《蘭納民俗博物館》完整展示北泰傳統文化，服飾、工藝、建築、宗教文物。互動式展覽了解蘭納王國歷史，定期舉辦傳統音樂、舞蹈表演，是認識清邁文化根源的最佳場所。", "contact_name": null, "country_code": "TH", "engl