muvnsn.supabase.co/storage/v1/object/public/attractions/japan/6064006c-d92d-4d00-b695-0e21e26f7529-1.jpg", "https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/japan/6064006c-d92d-4d00-b695-0e21e26f7529-2.jpg"], "address": null, "city_id": "yamagata", "website": null, "category": "自然風景 / Nature", "latitude": 38.5704194, "is_active": true, "longitude": 140.5300687, "region_id": "jp_tohoku", "country_id": "japan", "created_at": "2026-04-01T08:26:43.227962+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "《銀山溫泉》是大正浪漫風情的溫泉街，木造三、四層樓旅館沿銀山川兩岸排列，黃昏點燈後，煤氣燈映照在雪白溪水與積雪屋簷上，彷彿穿越時空回到百年前。這裡曾是江戶時代銀礦開採地，溫泉街保留當時建築樣式，能登屋旅館的螺旋階梯、古山閣的紅色橋樑都是經典拍攝點。冬季雪景最為夢幻，是動畫《神隱少女》油屋的靈感來源之一。溫泉街僅500公尺,適合漫步、泡足湯、品嚐溫泉饅頭，感受懷舊靜謐的氛圍。", "contact_name": null, "country_code": "JP", "english_name": "Ginzan Onsen", "ticket_price": null, "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "google_maps_url": null, "duration_minutes": null}, {"id": "606f9920-5808-4fd0-99fc-1553908a601f", "fax": null, "name": "士林夜市", "tags": null, "type": "attraction", "notes": null, "phone": null, "images": null, "address": "台北市士林區基河路101號", "city_id": "36e5e6b9-03c4-467e-b14a-0e5bbab0b3df", "website": null, "category": "購物 / Shopping", "latitude": 25.0879, "is_active": true, "longitude": 121.5243, "region_id": null, "country_id": "taiwan-country-001", "created_at": "2026-01-09T03:31:23.908376+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "台北最大、最有名的觀光夜市，超過500個攤位。大腸包小腸、臭豆腐、蚵仔煎、雞排，各式台灣小吃應有盡有。除了美食，還有撈魚、射飛鏢等夜市遊戲。人潮洶湧，最能感受台灣夜市文化的熱鬧氛圍。", "contact_name": null, "country_code": "TW", "english_name": "Shilin Night Market", "ticket_price": "免費入場", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 5, "opening_hours": {"daily": "16:00-00:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 120}, {"id": "609e5aae-f056-4d62-a017-f5e835369601", "fax": null, "name": "瑞巖寺", "tags": ["寺廟", "歷史", "文化", "國寶"], "type": "attraction", "notes": null, "phone": null, "images": ["https://wzvwmawpkapcmkfmkvav.supabase.co/storage/v1/object/public/resources/attractions/609e5aae-f056-4d62-a017-f5e835369601/1775617305953_p8egxw2mu67.png"], "address": "", "city_id": "sendai", "website": null, "category": "歷史文化 / History & Culture", "latitude": 38.3721758, "is_active": true, "longitude": 141.0595579, "region_id": "jp_tohoku", "country_id": "japan", "created_at": "2026-04-01T08:25:11.18359+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "《瑞巖寺》是伊達家族的菩提寺，創建於828年，現存建築由伊達政宗於1609年重建，融合禪宗與桃山文化的華麗。入口杉木參道兩側岩壁鑿有百餘座佛龕，是修行僧侶的遺跡。本堂內部的障壁畫、金碧輝煌的欄間雕刻，展現戰國大名的權勢與美學。寺內寶物館藏有伊達家族文物，春天的枝垂櫻與秋日紅葉為古寺增添季節風情。", "contact_name": null, "country_code": "JP", "english_name": "Zuiganji Temple", "ticket_price": null, "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "google_maps_url": null, "duration_minutes": null}, {"id": "60a2abf1-ebbd-451d-8b55-e058e935f093", "fax": null, "name": "高野山佛教靜修三日", "tags": ["養生靜修", "頂級體驗"], "type": "attraction", "notes": "頂級體驗 | 養生靜修 | 價位: | 難度:None", "phone": null, "images": ["https://images.unsplash.com/photo-1545569341-9eb8b30979d9?w=800", "https://images.unsplash.com/photo-1528360983277-13d401cdc186?w=800"], "address": null, "city_id": "osaka", "website": null, "category": "景點 / Attraction", "latitude": null, "is_active": true, "longitude": null, "region_id": "jp_kansai", "country_id": "japan", "created_at": "2026-04-06T22:24:13.030759+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "在日本真言宗總本山高野山，體驗三日兩夜的深度佛教靜修。高野山是空海大師（弘法大師）於1200年前開創的聖地，至今有117座寺廟。入住傳統寺院宿坊（Shukubo），與僧侶共同生活。清晨5:30參加朝勤（早課），聆聽僧侶誦經與梵唄。早餐享用精進料理（佛教素食），學習正念飲食。上午學習阿字觀冥想（真言宗獨特禪法）與抄經（寫經）。午後參訪奧之院、金剛峯寺、壇上伽藍等聖地。晚上參加夜間參拜與火供儀式。這是深度的心靈淨化與靈性成長之旅。", "contact_name": null, "country_code": "JP", "english_name": "Mt. Koya Buddhist Retreat 3 Days", "ticket_price": null, "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 0}, {"id": "60a74336-87a6-4d6a-aa60-7b4ce5ea8635", "fax": null, "name": "書寫山圓教寺", "tags": null, "type": "attraction", "notes": null, "phone": null, "images": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/japan/60a74336-87a6-4d6a-aa60-7b4ce5ea8635-1.jpeg", "https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/japan/60a74336-87a6-4d6a-aa60-7b4ce5ea8635-2.jpeg"], "address": null, "city_id": "himeji", "website": null, "category": "景點 / Attraction", "latitude": 34.8833, "is_active": true, "longitude": 134.6333, "region_id": "jp_kansai", "country_id": "japan", "created_at": "2026-01-23T02:43:34.826642+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "書寫山圓教寺，日本佛教寺院，展現日本傳統寺廟建築與庭園造景之美。", "contact_name": null, "country_code": "JP", "english_name": "Engyoji Temple", "ticket_price": "免費或300-500日圓", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 100, "opening_hours": {"daily": "06:00-17:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 120}, {"id": "60fa72ec-ac6f-4243-bc28-ffbc2e86399e", "fax": null, "name": "圓山動物園", "tags": ["動物園", "親子", "北極熊"], "type": "attraction", "notes": null, "phone": null, "images": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attra