s_url": null, "duration_minutes": 240}, {"id": "6d1828cf-468d-406a-8e58-df83d3d3b464", "fax": null, "name": "偶來小路", "tags": ["徒步", "海岸", "田園", "自然", "治癒"], "type": "attraction", "notes": "濟州環島徒步路線，共26條路線（425公里）。每條路線約3-6小時，沿途有海岸、田園、村落風光。以藍橘色標誌指引方向。是深度體驗濟州的最佳方式。\n\n旅遊提示：初次建議走7號路線（牛島周邊）或10號路線", "phone": null, "images": null, "address": null, "city_id": "jeju", "website": null, "category": "活動體驗 / Activity", "latitude": 33.2348963, "is_active": true, "longitude": 126.3144371, "region_id": null, "country_id": "korea", "created_at": "2025-12-06T07:01:16.660748+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "濟州偶來小路，環繞濟州島的徒步路線系統，全長約425公里，分為26條路線。沿海步道、森林步道、火山地形，每條路線都有獨特風景。難度從簡單到困難都有，適合各種體能。這是認識濟州島自然景觀的最佳方式，也是體驗慢旅行的好選擇。建議選擇1-2條路線體驗，單條約需4-6小時。沿途有偶來標誌指引。", "contact_name": null, "country_code": "KR", "english_name": "Olle Trail", "ticket_price": "免費或依業者而異", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 567, "opening_hours": {"daily": "10:00-20:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 180}, {"id": "6d4fab40-e434-407e-a21d-32a2246e4dd5", "fax": null, "name": "白楊步道", "tags": null, "type": "attraction", "notes": null, "phone": null, "images": null, "address": "花蓮縣秀林鄉天祥", "city_id": "769364e9-d3e2-474f-bc80-0184c00e6d9e", "website": null, "category": "景點 / Attraction", "latitude": 24.1833, "is_active": true, "longitude": 121.4889, "region_id": null, "country_id": "taiwan-country-001", "created_at": "2026-01-09T03:43:44.063392+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "太魯閣國家公園內的步道，沿著立霧溪支流而行。溪水清澈，大理石峽谷壯觀。步道平緩好走，終點是白楊瀑布和水簾洞。穿過隧道，瀑布從洞頂傾瀉而下，是太魯閣必訪的秘境步道。", "contact_name": null, "country_code": "TW", "english_name": "Baiyang Trail", "ticket_price": "免費（需申請）", "workspace_id": "8ef05a74-1f87-48ab