tps://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/thailand/6e07fb06-432d-4d54-9dfe-a07a10ba6ffa-2.jpeg"], "address": null, "city_id": "bangkok", "website": null, "category": "景點 / Attraction", "latitude": 13.7563, "is_active": true, "longitude": 100.5018, "region_id": null, "country_id": "thailand", "created_at": "2025-12-06T02:12:34.477319+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "《曼谷半島酒店》佇立湄南河畔超過半世紀,被譽為亞洲最佳酒店之一。酒店私人接駁船穿梭河面,是最優雅的交通方式。河景套房擁有落地窗,昭披耶河風光與對岸鄭王廟盡收眼底。The Lobby下午茶以三層架呈現精緻點心,搭配河景,是曼谷最經典的午後體驗。泰式餐廳Thiptara位於河畔露台,燭光晚餐浪漫指數破表。酒店泳池、Spa、健身房設施完善,服務細膩周到,是曼谷奢華住宿的標竿。", "contact_name": null, "country_code": "TH", "english_name": null, "ticket_price": "免費或依業者而異", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 590, "opening_hours": {"daily": "全天開放"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": null}, {"id": "6e2c2234-5b85-49a1-8151-e189875b2cac", "fax": null, "name": "首里城公園", "tags": ["世界遺產", "琉球王國", "重建中", "守禮門", "歷史文化", "沖繩象徵", "城牆遺跡", "夕陽美景"], "type": "landmark", "notes": "正殿重建中但大部分區域可參觀。從那霸機場單軌電車約30分鐘。門票400日圓。", "phone": null, "images": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/japan/6e2c2234-5b85-49a1-8151-e189875b2cac-1.jpeg", "https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/japan/6e2c2234-5b85-49a1-8151-e189875b2cac-2.jpeg"], "address": null, "city_id": "naha", "website": "https://oki-park.jp/shurijo/", "category": "歷史文化 / History & Culture", "latitude": 26.2172, "is_active": true, "longitude": 127.7192, "region_id": "jp_okinawa", "country_id": "japan", "created_at": "2025-12-06T07:38:12.669798+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "那霸首里城，琉球王國王宮，UNESCO世界文化遺產。守禮門、歡會門、瑞泉門、園比屋武御