5689.jpeg?auto=compress&cs=tinysrgb&h=650&w=940", "https://images.pexels.com/photos/20117729/pexels-photo-20117729.jpeg?auto=compress&cs=tinysrgb&h=650&w=940"], "address": null, "city_id": "wakayama", "website": null, "category": "景點 / Attraction", "latitude": 33.675, "is_active": true, "longitude": 135.35, "region_id": "jp_kansai", "country_id": "japan", "created_at": "2026-01-23T02:48:42.820676+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "和歌山三段壁，高50-60公尺的海蝕斷崖，綿延2公里。太平洋海浪拍打崖壁，景觀壯麗。可搭電梯下到海蝕洞窟，近距離感受海浪威力。這是白濱南部代表景點，也是看夕陽的好地方。展望台免費，洞窟建議傍晚前往，夕陽將海面染成金色。注意安全，勿越過護欄。", "contact_name": null, "country_code": "JP", "english_name": "Sandanbeki", "ticket_price": "免費或依業者而異", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 100, "opening_hours": {"daily": "10:00-18:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 45}, {"id": "75e1527d-a11c-4bc2-ab38-666ef239f715", "fax": null, "name": "天后宮", "tags": ["華人寺廟", "媽祖", "盤香"], "type": "attraction", "notes": null, "phone": null, "images": null, "address": null, "city_id": "ho-chi-minh", "website": null, "category": "歷史文化 / History & Culture", "latitude": 10.980744, "is_active": true, "longitude": 106.654802, "region_id": null, "country_id": "vietnam", "created_at": "2026-04-04T11:19:46.49+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "《天后宮》是胡志明最重要的華人寺廟,建於19世紀,供奉媽祖。寺廟建築採閩南風格,紅牆黑瓦,屋脊有精緻剪黏裝飾。殿內香煙繚繞,巨大的盤香從天花板垂掛,燃燒時間可達數週。信眾多是華人後代,農曆初一十五人潮眾多。這裡不是觀光景點,而是真實的宗教空間——越南華人在此維繫信仰與文化認同。天后宮證明:胡志明是移民城市,多元文化在此共存。", "contact_name": null, "country_code": "VN", "english_name": "Thien Hau Temple", "ticket_price": null, "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "google_maps_url": null, "duration_minutes": null}, {"id": "75ea412b-c0b0-42ca-b0ff-4682549241bb", "fax": null, "name": "景德鎮青花瓷繪製與燒窯", "tags": ["工藝體驗", "頂級體驗"], "type": "attraction", "notes": "頂級體驗 | 工藝體驗 | 價位: | 難度:None", "phone": null, "images": ["https://images.unsplash.com/photo-1610701596007-11502861dcfa?w=800", "https://images.unsplash.com/photo-1578749556568-bc2c40e68b61?w=800"], "address": null, "city_id": "shanghai", "website": null, "category": "景點 / Attraction", "latitude": null, "is_active": true, "longitude": null, "region_id": null, "country_id": "china", "created_at": "2026-04-06T22:24:10.302027+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "景德鎮是中國瓷都，有1700年製瓷歷史，青花瓷是其代表作，以白底藍花、釉下彩繪聞名於世。在上海的景德鎮陶瓷藝術館，跟隨景德鎮陶瓷大師學習青花瓷繪製。使用景德鎮高嶺土瓷坯，以天然鈷料（青花料）繪製傳統圖案：纏枝蓮、雲龍紋、山水、花鳥。學習分水技法（深淺層次）、勾線技法，完成繪製後施透明釉，送往景德鎮以1320度高溫燒製。完成作品如茶杯、盤子或花瓶，呈現青花特有的幽藍色澤。", "contact_name": null, "country_code": "CN", "english_name": "Jingdezhen Blue & White Porcelain Painting", "ticket_price": null, "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 0}, {"id": "761cbf9d-a16b-42ab-adc9-6dd7cf2fc08c", "fax": null, "name": "四島遊", "tags": ["跳島", "浮潛", "喀比"], "type": "attraction", "notes": "甲米經典跳島行程，雞島、管子島、莫島、波達島。", "phone": null, "images": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/thailand/761cbf9d-a16b-42ab-adc9-6dd7cf2fc08c-1.jpeg", "https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/thailand/761cbf9d-a16b-42ab-adc9-6dd7cf2fc08c-2.jpeg"], "address": null, "city_id": "krabi", "website": null, "category": "自然風景 / Nature", "latitude": 7.95, "is_active": true, "longitude": 98.8167, "region_id": null, "country_id": "thailand", "created_at": "2025-12-06T01:55:51.952009+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "《四島遊》喀比最經典的跳島行程，串聯雞島、管子島、莫島、波達島四座絕美島嶼。雞島因形似雞頭而得名，退潮時沙洲連接兩島可步行。行程包含浮潛、游泳、沙灘午餐，可搭長尾船或快艇出發。11-4月乾季海況最佳。", "contact_name": null, "country_code": "TH", "english_name": "Four Islands Tour", "ticket_price": "免費或依業者而異", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": {"daily": "全天開放"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 480}, {"id": "7655045d-8447-4252-a7cf-f2bef7af5ae6", "fax": null, "name": "落日亭", "tags": ["夕陽", "觀景", "攝影"], "type": "attraction", "notes": null, "phone": null, "images": null, "address": null, "city_id": null, "website": null, "category": "自然風景 / Nature", "latitude": 22.338, "is_active": true, "longitude": 120.352, "region_id": null, "country_id": "taiwan-country-001", "created_at": "2026-03-17T03:12:44.571464+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "小琉球西側觀賞夕陽的最佳位置。站在涼亭裡，視線毫無遮擋地延伸到海平面，夕陽將台灣海峽染成金黃與橙紅。島嶼西岸的平靜，讓日落時分格外動人，是結束一天行程最好的句點。", "contact_name": null, "country_code": "TW", "english_name": "Sunset Pavilion", "ticket_price": "免費", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": {"daily": "全天開放"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 30}, {"id": "765ff5ff-2aa7-42f5-a959-2acc37a53c54", "fax": null, "name": "龍橋", "tags": ["地標", "夜景", "表演", "必訪"], "type": "attraction", "notes": "峴港地標，週六週日晚上21:00有噴火和噴水表演", "phone": null, "images": null, "address": null, "city_id": null, "website": null, "category": "歷史文化 / History & Culture", "latitude": 16.0544, "is_active": true, "longitude": 108.2272, "region_id": null, "country_id": "vietnam", "created_at": "2026-03-17T03:15:31.816252+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, 