pabase.co/storage/v1/object/public/attractions/japan/773134dd-18b1-44f3-868b-1c0300d67aea-2.jpeg"], "address": null, "city_id": "osaka", "website": null, "category": "活動體驗 / Activity", "latitude": 34.6523697, "is_active": true, "longitude": 135.4666167, "region_id": "jp_kansai", "country_id": "japan", "created_at": "2025-12-06T06:44:04.189791+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "札幌北村餐廳，札幌老字號成吉思汗烤肉餐廳。新鮮羊肉、特製醬汁、鐵鍋燒烤，羊肉鮮嫩無羶味。這是札幌必吃美食，也是體驗北海道羊肉文化的好地方。一餐約3,000-5,建議晚餐前往。需提前預約，很受歡迎。", "contact_name": null, "country_code": "JP", "english_name": "Kitamura", "ticket_price": "免費或依業者而異", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 149, "opening_hours": {"daily": "11:00-22:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": null}, {"id": "774e1e1f-a75d-4fd5-995e-4127a75a3e01", "fax": null, "name": "鳴門漩渦", "tags": ["漩渦", "奇觀", "必遊", "自然"], "type": "attraction", "notes": "世界三大潮流之一，最大漩渦直徑 20 公尺，觀潮船或玻璃步道都能近距離觀賞。", "phone": null, "images": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/japan/774e1e1f-a75d-4fd5-995e-4127a75a3e01-1.jpeg", "https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/japan/774e1e1f-a75d-4fd5-995e-4127a75a3e01-2.jpeg"], "address": null, "city_id": "wakayama", "website": null, "category": "自然風景 / Nature", "latitude": 34.2344, "is_active": true, "longitude": 134.6481, "region_id": "jp_shikoku", "country_id": "japan", "created_at": "2025-10-28T06:33:55.152276+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "德島鳴門漩渦，鳴門海峽的潮汐漩渦，直徑最大20公尺。可搭觀潮船近距離觀賞、或走渦之道俯瞰。觀潮船約1,需查潮汐表，大潮時漩渦最大。", "contact_name": null, "country_code": "JP", "english_name": "Naruto Whirlpools", "ticket_price": "免費或依業者而異", "workspace_id": "8ef05a74-1f87-48ab