ish_name": "Bat Trang Ceramic Making & Inlay Craft", "ticket_price": null, "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 0}, {"id": "77c019f3-a597-49c4-8333-e9ca8694ed42", "fax": null, "name": "占婆雕刻博物館", "tags": ["占婆", "雕刻", "印度教"], "type": "attraction", "notes": null, "phone": null, "images": null, "address": null, "city_id": "da-nang", "website": null, "category": "歷史文化 / History & Culture", "latitude": 16.0601209, "is_active": true, "longitude": 108.223084, "region_id": null, "country_id": "vietnam", "created_at": "2026-04-04T11:24:17.73+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "《占婆雕刻博物館》收藏世界最完整的占婆藝術品,從7世紀到15世紀的神像、祭壇、建築構件。占婆王國曾統治越南中部,信奉印度教與佛教,藝術風格融合印度與在地元素。館藏精美,值得花兩小時細看。這是理解越南多元文化的窗口——越南不只是越族,還有占族、華族、高棉族等多元族群。", "contact_name": null, "country_code": "VN", "english_name": "Museum of Cham Sculpture", "ticket_price": null, "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "google_maps_url": null, "duration_minutes": null}, {"id": "77c900fd-1d45-4ca5-ac3a-a8bb005be712", "fax": null, "name": "Max 泰拳比賽", "tags": ["表演", "文化", "運動", "刺激"], "type": "表演秀", "notes": null, "phone": null, "images": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/thailand/77c900fd-1d45-4ca5-ac3a-a8bb005be712-1.jpg", "https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/thailand/77c900fd-1d45-4ca5-ac3a-a8bb005be712-2.jpg"], "address": null, "city_id": "pattaya", "website": null, "category": "景點 / Attraction", "latitude": 12.9289141, "is_active": true, "longitude": 100.8991485, "region_id": null, "country_id": "thailand", "created_at": "2026-03-29T11:41:11.28046+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "《Max 泰拳》是芭達雅知名的泰拳競技場,每週三、六舉辦職業泰拳比賽。拳手來自泰國各地,實力堅強、比賽激烈。賽前有傳統拜師儀式、音樂伴奏,呈現泰拳文化精髓。觀眾席距離擂台近,能感受拳拳到肉的震撼。對武術愛好者、想體驗泰國國技魅力的旅客,是不可錯過的文化體驗。", "contact_name": null, "country_code": "TH", "english_name": "Max Muay Thai", "ticket_price": null, "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": "19:00-23:00", "deleted_reason": null, "google_maps_url": null, "duration_minutes": 150}, {"id": "77cf0e1c-f9e8-45b4-8388-c9b38fd2b1eb", "fax": null, "name": "三鷹吉卜力美術館", "tags": ["吉卜力", "動畫", "龍貓"], "type": "attraction", "notes": "宮崎駿動畫世界，龍貓公車可讓小朋友乘坐，屋頂機器兵是必拍打卡點。", "phone": null, "images": ["https://images.pexels.com/photos/1308648/pexels-photo-1308648.jpeg?auto=compress&cs=tinysrgb&h=650&w=940", "https://images.pexels.com/photos/20967/pexels-photo.jpg?auto=compress&cs=tinysrgb&h=650&w=940", "https://images.pexels.com/photos/69903/pexels-photo-69903.jpeg?auto=compress&cs=tinysrgb&h=650&w=940", "https://images.pexels.com/photos/135018/pexels-photo-135018.jpeg?auto=compress&cs=tinysrgb&h=650&w=940", "https://images.pexels.com/photos/2574476/pexels-photo-2574476.jpeg?auto=compress&cs=tinysrgb&h=650&w=940"], "address": null, "city_id": "tokyo", "website": null, "category": "歷史文化 / History & Culture", "latitude": 35.6963, "is_active": true, "longitude": 139.5703, "region_id": "jp_kanto", "country_id": "japan", "created_at": "2025-12-06T07:11:00.574378+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "東京三鷹吉卜力美術館，宮崎駿吉卜力工作室主題美術館。展示動畫製作過程、原畫、龍貓巴士、短篇動畫放映。建築由宮崎駿設計，處處是巧思與童趣。這是吉卜力迷朝聖地，也是認識動畫藝術的好地方。需提前一個月官網預約。", "contact_name": null, "country_code": "JP", "english_name": "Ghibli Museum", "ticket_price": "成人500-1000日圓", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order":