ion", "latitude": 13.74175, "is_active": true, "longitude": 100.5107544, "region_id": null, "country_id": "thailand", "created_at": "2025-12-06T01:24:38.127413+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "《唐人街耀華力路》在日落後才真正甦醒,金店的招牌燈與路邊攤的火光交織成視覺奇觀。這裡的潮州移民後代經營著家族生意,從中藥行到金飾店,店面狹小但貨品密度驚人。街頭小吃攤販售魚翅湯、燕窩與豬腳飯,價格親民但口味扎實。巷弄深處的老茶室仍維持上世紀的裝潢,天花板吊扇緩慢旋轉,老人們用潮州話交談。這不是為觀光而存在的場景,而是真實的移民社區,保有自己的節奏與邏輯。混亂,但生猛有力。", "contact_name": null, "country_code": "TH", "english_name": "Chinatown Yaowarat", "ticket_price": "免費或依業者而異", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": {"daily": "09:00-18:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": null}, {"id": "7803f601-b60e-4c04-97c5-54d8c9a05ab8", "fax": null, "name": "光明頂", "tags": null, "type": "viewpoint", "notes": null, "phone": null, "images": null, "address": null, "city_id": null, "website": null, "category": "景點 / Attraction", "latitude": 30.1346774, "is_active": true, "longitude": 118.1640111, "region_id": null, "country_id": "china", "created_at": "2025-12-06T02:12:21.611722+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "光明頂，中國知名景點，值得探訪。", "contact_name": null, "country_code": "CN", "english_name": null, "ticket_price": "免費或依業者而異", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 219, "opening_hours": {"daily": "08:30-17:30"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": null}, {"id": "780bca91-b1a8-4557-9119-b4d62991d155", "fax": null, "name": "龍卷地獄", "tags": null, "type": "attraction", "notes": null, "phone": null, "images": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/japan/780bca91-b1a8-4557-9119-b4d62991d155-1.jpeg", "htt