": false, "display_order": 0, "opening_hours": {"daily": "10:00-18:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 120}, {"id": "83908c47-250b-40aa-a512-55f0c631217a", "fax": null, "name": "黑部水壩", "tags": ["水壩", "壯觀", "彩虹", "工程"], "type": "attraction", "notes": null, "phone": null, "images": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/japan/83908c47-250b-40aa-a512-55f0c631217a-1.jpeg", "https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/japan/83908c47-250b-40aa-a512-55f0c631217a-2.jpeg"], "address": null, "city_id": "toyama", "website": null, "category": "活動體驗 / Activity", "latitude": 36.5666941, "is_active": true, "longitude": 137.6636386, "region_id": "jp_chubu", "country_id": "japan", "created_at": "2025-10-28T06:35:52.170262+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "高186公尺的《黑部水壩》是日本最高水壩，建造耗時7年犧牲171人生命。6-10月觀光放水每秒10噸水量氣勢磅礴，彩虹橫跨其間，展望台俯瞰立山連峰倒映翡翠色湖面。", "contact_name": null, "country_code": "JP", "english_name": "Kurobe Dam", "ticket_price": "免費或依業者而異", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 2, "opening_hours": {"daily": "10:00-18:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 120}, {"id": "839944ed-c0e2-4c72-9b7b-e08cfb7c0e84", "fax": null, "name": "芽莊烹飪課程", "tags": ["烹飪課程", "海鮮", "文化"], "type": "attraction", "notes": null, "phone": null, "images": null, "address": null, "city_id": "nha-trang", "website": null, "category": "活動體驗 / Activity", "latitude": null, "is_active": true, "longitude": null, "region_id": null, "country_id": "vietnam", "created_at": "2026-04-04T11:24:22.769+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "《芽莊烹飪課程》從市場導覽開始,主廚帶你認識越南海鮮料理。親手製作春捲、海鮮粥、烤魚、越式甜點。完成後一起用餐