0/pexels-photo-952670.jpeg?auto=compress&cs=tinysrgb&h=650&w=940", "https://images.pexels.com/photos/20759131/pexels-photo-20759131.jpeg?auto=compress&cs=tinysrgb&h=650&w=940"], "address": null, "city_id": "toyako", "website": null, "category": "活動體驗 / Activity", "latitude": 42.8656164, "is_active": true, "longitude": 140.6928032, "region_id": "jp_hokkaido", "country_id": "japan", "created_at": "2025-10-28T06:41:25.438202+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "《二世谷》擁有世界頂級粉雪，年降雪量15公尺，滑道總長70公里。Grand Hirafu、Hanazono、Annupuri、Village四大雪場連結，背景羊蹄山如富士山倒影，國際滑雪者天堂。", "contact_name": null, "country_code": "JP", "english_name": "Niseko United", "ticket_price": "免費或依業者而異", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 1, "opening_hours": {"daily": "10:00-18:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 480}, {"id": "848d1291-4356-4d4f-af93-b9fa146cffc3", "fax": null, "name": "二條城", "tags": null, "type": "attraction", "notes": null, "phone": null, "images": ["https://images.pexels.com/photos/31040541/pexels-photo-31040541.jpeg?auto=compress&cs=tinysrgb&h=650&w=940", "https://images.pexels.com/photos/31417180/pexels-photo-31417180.jpeg?auto=compress&cs=tinysrgb&h=650&w=940", "https://images.pexels.com/photos/19191148/pexels-photo-19191148.jpeg?auto=compress&cs=tinysrgb&h=650&w=940", "https://images.pexels.com/photos/2350366/pexels-photo-2350366.jpeg?auto=compress&cs=tinysrgb&h=650&w=940", "https://images.pexels.com/photos/31002203/pexels-photo-31002203.jpeg?auto=compress&cs=tinysrgb&h=650&w=940"], "address": null, "city_id": "kyoto", "website": null, "category": "景點 / Attraction", "latitude": 35.0142, "is_active": true, "longitude": 135.7481, "region_id": "jp_kansai", "country_id": "japan", "created_at": "2026-01-23T00:37:30.470734+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "德川家康於1603年建造的京都城郭,見證江戶幕府興衰，是世界文化遺產。二之丸御殿「鶯鳴地板」可發出如鳥叫聲響，是防盜機關。豪華障壁畫展現狩野派繪畫藝術，本丸御殿庭園四季景致各異。春季櫻花、秋季紅葉與夜間點燈美不勝收。是了解德川幕府歷史與日本城郭建築的重要景點。", "contact_name": null, "country_code": "JP", "english_name": "Nijo Castle", "ticket_price": "1300日圓", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 7, "opening_hours": {"daily": "08:45-17:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 90}, {"id": "849b4430-d6ac-4aca-9f95-dc4053109103", "fax": null, "name": "河內城隍廟", "tags": ["道教", "古寺", "西湖"], "type": "attraction", "notes": null, "phone": null, "images": null, "address": null, "city_id": "hanoi", "website": null, "category": "歷史文化 / History & Culture", "latitude": 21.0430101, "is_active": true, "longitude": 105.8364191, "region_id": null, "country_id": "vietnam", "created_at": "2026-04-04T11:17:39.367+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "《河內城隍廟》Quan Thanh Temple 建於11世紀,供奉道教神祇玄天上帝。寺廟位於西湖畔,紅牆黑瓦掩映在樹蔭中,氣氛寧靜肅穆。主殿內有尊重達四噸的銅鑄玄天上帝像,是越南最大的道教神像之一。寺內保留清代石碑、木雕、銅鐘等文物。這裡遊客稀少,多是在地信眾前來參拜,是體驗越南宗教生活的好地點。清晨或傍晚前往最合適,陽光穿過樹葉灑在紅牆上,構成經典畫面。河內的道教寺廟不多,城隍廟是其中最重要的一座。", "contact_name": null, "country_code": "VN", "english_name": "Quan Thanh Temple", "ticket_price": null, "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "google_maps_url": null, "duration_minutes": null}, {"id": "84e10c9f-c04d-470b-8e1e-87ac1acf4d78", "fax": null, "name": "自由女神像", "tags": ["自由女神", "台場", "攝影"], "type": "attraction", "notes": "台場的複製版自由女神像，原為法國紀念品。配上彩虹橋和東京灣夜景，是人氣拍照點。", "phone": null, "images": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/japan/84e10c9f-c04d-470b-8e1e-87ac1acf4d78-1.jpeg", "https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/japan/84e10c9f-c04d-470b-8e1e-87ac1acf4d78-2.jpeg"], "address": null, "city_id": "tokyo", "website": null, "category": "地標建築 / Landmark", "latitude": 35.6267, "is_active": true, "longitude": 139.775, "region_id": "jp_kanto", "country_id": "japan", "created_at": "2025-12-06T07:10:59.716517+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "東京台場自由女神像，台場海濱公園的自由女神像複製品，1998年法國贈送。彩虹大橋背景，景色浪漫。這是台場必訪景點，也是拍照打卡聖地。免費參觀，建議預留30分鐘。可搭配台場海濱公園、DiverCity一起遊覽。夜晚點燈與彩虹大橋同框最美。", "contact_name": null, "country_code": "JP", "english_name": "Statue of Liberty (Tokyo)", "ticket_price": "免費或依業者而異", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 270, "opening_hours": {"daily": "10:00-18:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": null}, {"id": "850d4b98-99b0-4e31-a229-45290d15c16d", "fax": null, "name": "蒲屏皇宮", "tags": ["皇宮", "花園", "溫帶植物"], "type": "heritage", "notes": "皇室冬季行宮，玫瑰園美麗。位於素帖山，可與雙龍寺一起遊覽。門票50泰銖。需穿長褲。", "phone": null, "images": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/thailand/850d4b98-99b0-4e31-a229-45290d15c16d-1.jpeg", "https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/thailand/850d4b98-99b0-4e31-a229-45290d15c16d-2.jpeg"], "address": null, "city_id": "chiang-mai", "website": null, "category": "自然風景 / Nature", "latitude": 18.8044864, "is_active": true, "longitude": 98.8994489, "region_id": null, "country_id": "thailand", "created_at": "2025-12-06T01:24:39.692953+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "《蒲屏皇宮》Bhubing Palace 是泰國皇室的冬季行宮,位於素帖山上,海拔1300公尺。皇室不在時對外開放,園區內種滿溫帶花卉——玫瑰、鼠尾草、繡球花,在泰國炎熱氣候中顯得格外珍貴。建築採蘭納風格,柚木結構與金色屋頂,低調但精緻。園區步道平緩,適合悠閒漫步,空氣涼爽清新。這裡不是華麗的皇宮,而是實用的度假居所——泰皇來此休養,因此設計著重舒適而非炫耀。從清邁市區開車約一小時,可與雙龍寺安排半日遊。穿著需端莊,禁止短褲背心。", "contact_name": null, "country_code": "TH", "english_name": "Bhubing Palace", "ticket_price": "免費或依業者而異", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": {"daily": "08:00-17:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 60}, {"id": "852908ff-fee9-41f8-8e71-8caa220a51ac", "fax": null, "name": "東北角海岸", "tags": ["海岸", "公路", "地質", "風景區", "北部"], "type": "scenic", "notes": "從瑞芳到宜蘭的海岸風景區，沿途有南雅奇岩、陰陽海、金瓜石、九份等景點。海蝕地形多變，是地質愛好者的天堂。", "phone": null, "images": null, "address": null, "city_id": null, "website": null, "category": "自然風景 / Nature", "latitude": 25.1167, "is_active": true, "longitude": 121.9167, "region_id": null, "country_id": "taiwan-country-001", "created_at": "2025-12-16T06:49:57.996767+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "新北東北角海岸，從瑞芳鼻頭角到宜蘭頭城的海岸線。鼻頭角步道可以看到海蝕平台、海蝕洞；南雅奇岩的岩石紋理像豆腐；龍洞是攀岩聖地；福隆有金黃沙灘；三貂角燈塔是台灣極東點。這段海岸公路景色變化豐富，每個轉彎都是驚喜。夏天戲水、冬天看浪，東北角四季皆美。", "contact_name": null, "country_code": "TW", "english_name": "Northeast Coast", "ticket_price": "免費（部分景點收費）", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 351, "opening_hours": {"note": "冬季東北季風強勁，注意安全", "daily": "全天開放", "lighthouse": "09:00-17:00（週一休）", "summer_beaches": "海水浴場5-9月08:00-18:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 360}, {"id": "8532aafd-1cf4-4f07-b9ae-f32129e5300f", "fax": null, "name": "川越時之鐘", "tags": null, "type": "attraction", "notes": null, "phone": null, "images": ["https://wzvwmawpkapcmkfmkvav.supabase.co/storage/v1/object/public/resources/attractions/8532aafd-1cf4-4f07-b9ae-f32129e5300f/1775722319487_nevanadrb4n.webp"], "address": "", "city_id": null, "website": null, "category": "景點 / Attraction", "latitude": null, "is_active": true, "longitude": null, "region_id":