l, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "地獄溫泉巡禮，日本溫泉鄉，泉質優良，是放鬆身心的絕佳溫泉勝地。", "contact_name": null, "country_code": "JP", "english_name": "Beppu Hells", "ticket_price": "約500-1500日圓/人", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 1, "opening_hours": {"daily": "依溫泉業者營業時間"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 180}, {"id": "8672953c-83f5-499d-9795-a3326e714e5c", "fax": null, "name": "熊野古道", "tags": null, "type": "attraction", "notes": null, "phone": null, "images": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/japan/8672953c-83f5-499d-9795-a3326e714e5c-1.jpeg", "https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/japan/8672953c-83f5-499d-9795-a3326e714e5c-2.jpeg"], "address": null, "city_id": "wakayama", "website": null, "category": "景點 / Attraction", "latitude": 33.75, "is_active": true, "longitude": 135.7833, "region_id": "jp_kansai", "country_id": "japan", "created_at": "2026-01-23T02:46:27.331251+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "和歌山熊野古道，UNESCO世界文化遺產，平安時代的朝聖之路，連接京都與熊野三山。石疊古道、杉木林、王子社，充滿靈性。中邊路最熱門，大門坂石階最美。", "contact_name": null, "country_code": "JP", "english_name": "Kumano Kodo", "ticket_price": "免費或依業者而異", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 100, "opening_hours": {"daily": "10:00-18:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 240}, {"id": "8688b730-6a7e-4785-8953-6c1ebc72521f", "fax": null, "name": "郡上八幡城", "tags": null, "type": "attraction", "notes": null, "phone": null, "images": ["https://wzvwmawpkapcmkfmkvav.supabase.co/storage/v1/object/public/resources/attractions/8688b730-6a7e-4785-8953-6c1ebc72521f/1775740909606_4cfw59ud2