-9bfeb423935d", "data_verified": false, "display_order": 332, "opening_hours": {"daily": "09:00-22:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 180}, {"id": "87a7f176-592c-44b3-923e-f5c30651f330", "fax": null, "name": "奧林匹克博物館", "tags": null, "type": "museum", "notes": null, "phone": null, "images": null, "address": null, "city_id": null, "website": null, "category": "歷史文化 / History & Culture", "latitude": 39.989116, "is_active": true, "longitude": 116.3902855, "region_id": null, "country_id": "china", "created_at": "2025-12-06T01:13:28.2697+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "奧林匹克博物館，中國博物館，展示中國歷史文化藝術與科學知識。", "contact_name": null, "country_code": "CN", "english_name": "Olympic Museum", "ticket_price": "免費或20-50元", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": {"closed": "週一", "tue_sun": "09:00-17:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": null}, {"id": "87ae968e-fcc4-44b0-aa96-7541f19d33e0", "fax": null, "name": "達邦部落", "tags": ["原住民", "鄒族", "部落", "文化"], "type": "attraction", "notes": "鄒族傳統部落，建議安排2-3小時體驗部落文化", "phone": null, "images": null, "address": "嘉義縣阿里山鄉達邦村", "city_id": null, "website": null, "category": "活動體驗 / Activity", "latitude": 23.458, "is_active": true, "longitude": 120.741, "region_id": null, "country_id": "taiwan-country-001", "created_at": "2026-03-17T03:13:22.597861+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "在達邦，時間走得特別慢。這是阿里山鄒族文化的核心聚落，保存著完整的傳統建築和生活方式。山豬肉在火上慢烤，竹筒飯散發著竹子的清香，部落導覽員會帶你認識鄒族的戰祭文化、傳統建築工法，以及他們如何與山林共存的生活智慧。這不只是觀光，是一次真實的文化相遇。", "contact_name": null, "country_code": "TW", "english_name": "Dabang Tribe", "ticket_price": "部落導覽費用約500-800元/人", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": {"daily": "需提前預約部落導覽"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 180}, {"id": "87c8a9ac-82c7-4a67-aa06-24e587cc4465", "fax": null, "name": "上野公園", "tags": null, "type": "attraction", "notes": null, "phone": null, "images": ["https://images.pexels.com/photos/20607245/pexels-photo-20607245.jpeg?auto=compress&cs=tinysrgb&h=650&w=940", "https://images.pexels.com/photos/30487720/pexels-photo-30487720.jpeg?auto=compress&cs=tinysrgb&h=650&w=940", "https://images.pexels.com/photos/30487721/pexels-photo-30487721.jpeg?auto=compress&cs=tinysrgb&h=650&w=940", "https://images.pexels.com/photos/34546164/pexels-photo-34546164.jpeg?auto=compress&cs=tinysrgb&h=650&w=940", "https://images.pexels.com/photos/27595761/pexels-photo-27595761.jpeg?auto=compress&cs=tinysrgb&h=650&w=940"], "address": null, "city_id": "tokyo", "website": null, "category": "景點 / Attraction", "latitude": 35.7146, "is_active": true, "longitude": 139.7744, "region_id": "jp_kanto", "country_id": "japan", "created_at": "2026-01-23T00:38:30.671089+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "東京上野公園，東京最大的公園，春天賞櫻名所。約1000棵櫻花樹盛開時，整個公園被粉色花海覆蓋。園內有東京國立博物館、國立西洋美術館、上野動物園、不忍池。這是東京文化藝術中心，也是春天必訪景點。建議平日或早上前往，可搭配阿美橫丁、谷中銀座遊覽。", "contact_name": null, "country_code": "JP", "english_name": "Ueno Park", "ticket_price": "成人300-500日圓", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 10, "opening_hours": {"daily": "09:00-17:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 120}, {"id": "87fc1166-a862-4688-a74c-88e5908049f1", "fax": null, "name": "四川博物院", "tags": ["博物館", "免費", "張大千", "青銅器", "歷史"], "type": "attraction", "notes": "免費需預約，週一閉館", "phone": null, "images": null, "address": "成都市青羊區浣花南路251號", "city_id": null, "website": null, "category": "歷史文化 / History & Cu