age/v1/object/public/attractions/thailand/893b84db-d3b8-4ce8-b329-668824fe99f2-2.jpeg"], "address": null, "city_id": "chiang-mai", "website": null, "category": "景點 / Attraction", "latitude": 18.7963157, "is_active": true, "longitude": 98.9645238, "region_id": null, "country_id": "thailand", "created_at": "2025-12-06T01:24:39.299533+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "《尼曼區》Nimmanhaemin 是清邁的文青聚落，狹窄巷弄裡擠滿獨立咖啡館、設計選物店與手沖咖啡館。這裡的店面流動率極高，三個月後再訪往往已換上新面孔，但正是這種不穩定性造就了創意的密度。下午時段咖啡館坐滿帶著筆電工作的數位遊牧者，傍晚則變成年輕人的社交場域。不少泰國設計師品牌從這裡起步，在小坪數店面裡打磨風格。尼曼1巷到17巷各有特色，值得花一整個下午慢慢探索。這裡不是傳統清邁，而是這座城市的當代表情——國際化、創意、流動。", "contact_name": null, "country_code": "TH", "english_name": "Nimmanhaemin", "ticket_price": "免費或依業者而異", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": {"daily": "09:00-18:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": null}, {"id": "893e66ff-a019-4756-85a7-3bfecaa270dc", "fax": null, "name": "芽莊潛水", "tags": ["潛水", "海底", "珊瑚礁"], "type": "attraction", "notes": null, "phone": null, "images": null, "address": null, "city_id": "nha-trang", "website": null, "category": "活動體驗 / Activity", "latitude": null, "is_active": true, "longitude": null, "region_id": null, "country_id": "vietnam", "created_at": "2026-04-04T11:24:21.49+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "《芽莊潛水》擁有多處潛點,水質清澈,能見度佳。潛水學校提供體驗潛水、考證課程,教練專業。海底有珊瑚礁、熱帶魚、海龜。價格比泰國便宜,是學潛水的好地方。芽莊潛水證明:越南不只有河粉,還有海底世界。", "contact_name": null, "country_code": "VN", "english_name": "Nha Trang Scuba Diving", "ticket_price": null, "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "google_maps_url": null, "duration_minutes": null}, {"id": "