address": null, "city_id": "kagoshima", "website": null, "category": "景點 / Attraction", "latitude": 31.521587, "is_active": true, "longitude": 130.5474077, "region_id": "jp_kyushu", "country_id": "japan", "created_at": "2025-12-06T01:55:45.590404+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "鹿兒島黑豚涮涮鍋，鹿兒島黑豬肉涮涮鍋，肉質柔軟、脂肪甜美、涮幾秒即可食用。配柚子醋或芝麻醬。黑福多、華蓮都是名店。這是鹿兒島必吃美食，也是黑豬料理代表。套餐約3,000-5,可搭配白熊刨冰、薩摩料理一起品嚐。鹿兒島黑豬是日本六大黑豬之一。", "contact_name": null, "country_code": "JP", "english_name": "Kurobuta Shabu Shabu", "ticket_price": "免費或依業者而異", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": {"daily": "10:00-18:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": null}, {"id": "8aa7bf01-d881-4520-88f9-1e427e79be72", "fax": null, "name": "備前燒陶藝登窯燒製體驗", "tags": ["工藝體驗", "頂級體驗"], "type": "attraction", "notes": "頂級體驗 | 工藝體驗 | 價位: | 難度:None", "phone": null, "images": ["https://images.unsplash.com/photo-1493106641515-6b5631de4bb9?w=800", "https://images.unsplash.com/photo-1578749556568-bc2c40e68b61?w=800"], "address": null, "city_id": "osaka", "website": null, "category": "景點 / Attraction", "latitude": null, "is_active": true, "longitude": null, "region_id": "jp_kansai", "country_id": "japan", "created_at": "2026-04-06T22:24:08.174243+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "備前燒是日本六古窯之一，有1000年以上歷史，以不上釉、高溫長時間燒製而聞名。在岡山縣備前市的傳統窯元（大阪聯絡處），跟隨備前燒重要無形文化財保持者學習手捏成型技法。使用當地特有的田土陶土，以手捏或轆轤製作茶碗、花器等器皿。作品將在「大窯」（登窯）中以松木柴燒10-14天，形成獨特的「窯變」效果：緋襷、胡麻、桟切等自然釉色。", "contact_name": null, "country_code": "JP", "english_name": "Bizen-yaki Pottery Climbing Kiln Firing", "ticket_price": null, "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 0}, {"id": "8ac27cdf-11a2-4594-b891-c050fc1d086d", "fax": null, "name": "SM亞洲商城", "tags": null, "type": "attraction", "notes": null, "phone": null, "images": null, "address": null, "city_id": "manila", "website": null, "category": "購物 / Shopping", "latitude": 14.5356, "is_active": true, "longitude": 120.9823, "region_id": null, "country_id": "philippines", "created_at": "2026-01-23T22:34:02.766022+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "SMMallofAsia，馬尼拉最大的購物中心之一，位於馬尼拉灣畔。H&M、Zara、Uniqlo、超市、美食街、電影院、IMAX、溜冰場應有盡有。摩天輪、海濱步道可看日落。這是馬尼拉必逛商圈，也是購物天堂。", "contact_name": null, "country_code": "PH", "english_name": "SM Mall of Asia", "ticket_price": "免費或依業者而異", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 100, "opening_hours": {"daily": "08:00-18:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 180}, {"id": "8ac4d145-17c2-4e0d-b23d-96d6c401cc35", "fax": null, "name": "清邁藝術文化中心", "tags": ["博物館", "蘭納文化", "歷史"], "type": "museum", "notes": null, "phone": null, "images": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/thailand/8ac4d145-17c2-4e0d-b23d-96d6c401cc35-1.jpeg", "https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/thailand/8ac4d145-17c2-4e0d-b23d-96d6c401cc35-2.jpeg"], "address": null, "city_id": "chiang-mai", "website": null, "category": "景點 / Attraction", "latitude": 18.7883, "is_active": true, "longitude": 98.9853, "region_id": null, "country_id": "thailand", "created_at": "2025-12-06T01:24:40.057563+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "《清邁藝術文化中心》Chiang Mai Arts & Cultural Centre 位於古城中心,前身是市政廳。展覽以清邁歷史與蘭納文化為主題,從史前時期、蘭納王朝、緬甸統治到現代發展,透過文物、模型、影片完整呈現。展示空間不大但內容紮實,英文說明詳盡。二樓有蘭納傳統服飾、樂器、手工藝品展示,可以理解泰北文化的獨特性。這裡遊客稀少,多是對歷史有興趣的旅人與在地學生。門票便宜,冷氣充足,適合炎熱午後躲進來吸收知識。這不是華麗的博物館,而是認真的文化教育空間——清邁的故事,在此被好好訴說。", "contact_name": null, "country_code": "TH", "english_name": "Chiang Mai Arts Center", "ticket_price": "免費或依業者而異", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": {"daily": "09:00-18:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": null}, {"id": "8ad3a5b5-7c2d-4f6b-9137-ffc7fe5c30c4", "fax": null, "name": "北村韓屋住宿", "tags": null, "type": "experience", "notes": "首爾保存最完整的傳統韓屋聚落，600年歷史的瓦房依山而建。穿韓服漫步石板小巷，是體驗朝鮮時代生活的最佳去處。", "phone": null, "images": null, "address": null, "city_id": "seoul", "website": null, "category": "自然風景 / Nature", "latitude": 37.5823, "is_active": true, "longitude": 126.9836, "region_id": null, "country_id": "korea", "created_at": "2025-12-06T01:49:09.03583+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "首爾北村韓屋村，保存朝鮮時代傳統韓屋的社區。黑瓦、白牆、木門，韓屋沿著坡道整齊排列。北村八景是必訪拍照點，可以拍到韓屋與首爾天際線。許多韓屋改建成茶館、工藝坊、韓服體驗店。這裡仍有居民生活，請保持安靜尊重。穿韓服在韓屋間散步，是首爾最有韻味的體驗。", "contact_name": null, "country_code": "KR", "english_name": "Bukchon Hanok Stay", "ticket_price": "免費（韓服租借約15000-30000韓元）", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": {"note": "請勿喧嘩，尊重居民", "daily": "全天開放，商店約10:00-18:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 120}, {"id": "8ae7b232-21dc-46f5-b9ff-569ef389e259", "fax": null, "name": "鬥雞石", "tags": ["地標", "下龍灣", "攝影"], "type": "landmark", "notes": "兩塊石頭相對如鬥雞狀，是下龍灣的標誌性景觀。出現在越南貨幣上。遊船都會經過。", "phone": null, "images": null, "address": null, "city_id": "ha-long", "website": null, "category": "自然風景 / Nature", "latitude": 20.9, "is_active": true, "longitude": 107.1833, "region_id": null, "country_id": "vietnam", "created_at": "2025-12-06T01:24:42.913016+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "下龍灣鬥雞石，下龍灣地標，兩座石灰岩島嶼如兩隻雞鬥架。傳說是龍王的雞化為石頭守護下龍灣。這是下龍灣必拍景點，也是明信片常見景觀。包含在下龍灣遊船行程。建議在船上拍照。日落時分最美。", "contact_name": null, "country_code": "VN", "english_name": "Fighting Cock Rocks", "ticket_price": "0", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": {"open": "遊船經過"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 15}, {"id": "8afc5e44-15b9-42ca-8c98-dca1ec948d59", "fax": null, "name": "馬六甲海峽清真寺", "tags": ["清真寺", "水上", "日落", "攝影", "建築"], "type": "temple", "notes": "建在填海地上的水上清真寺，漲潮時彷彿漂浮在海上。日落時分光線最美，是馬六甲最佳攝影點之一。", "phone": null, "images": null, "address": null, "city_id": "malacca", "website": null, "category": "歷史文化 / History & Culture", "latitude": 2.1896, "is_active": true, "longitude": 102.2501, "region_id": null, "country_id": "malaysia", "created_at": "2025-12-06T02:06:48.847716+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "馬六甲海峽旁的現代清真寺，建在人工島上，漲潮時彷彿漂浮在海面上。白色建築配上金色圓頂，在夕陽時分格外美麗。這是馬六甲新地標，融合現代建築與伊斯蘭美學，也是拍攝日落的絕佳地點。", "contact_name": null, "country_code": "MY", "english_name": null, "ticket_price": "免費（外觀參觀）", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 555, "opening_hours": {"daily": "09:00-18:00（祈禱時間不開放）"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 30}, {"id": "8b02ac8d-9a9d-4c47-a1c1-f8b2d24d0f83", "fax": null, "name": "陳億粿條", "tags": ["美食", "米其林", "街頭小吃", "唐人街"], "type": "food", "notes": null, "phone": null, "images": null, "address": null, "city_id": "bangkok", "website": null, "category": "景點 / Attraction", "latitude": 13.7524938, "is_active": true, "longitude": 100.4935089, "region_id": null, "country_id": "thailand", "created_at": "2025-12-06T01:49:10.643843+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "《陳億粿條》藏身曼谷唐人街巷弄，創立於1966年，是米其林必比登推薦的泰式炒麵傳奇。老闆堅持使用炭火快炒，火舌舔舐鍋邊，河粉在高溫中翻騰，吸飽醬汁與蝦油香氣。配料豐富：新鮮白蝦、豆芽、韭黃、花生碎,蛋液在鍋邊煎成薄皮包裹炒麵，形成獨特口感。每晚18:00開門，排隊人潮綿延至街尾，深夜依然燈火通明，是體驗道地曼谷街頭美食文化的必訪朝聖地。", "contact_name": null, "country_code": "TH", "english_name": "Thipsamai Pad Thai", "ticket_price": "免費或依業者而異", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": {"daily": "09:00-18:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": null}, {"id": "8b102ead-2a03-4594-8aa8-56c610fbd306", "fax": null, "name": "聖彼得大教堂", "tags": ["教堂", "世界最大", "米開朗基羅", "圓頂", "梵蒂岡"], "type": "heritage", "notes": "天主教最神聖的教堂，世界最大教堂。米開朗基羅設計的圓頂。有聖殤像和聖彼得寶座。可登頂俯瞰梵蒂岡。免費入場但登頂收費。\n\n旅遊提示：搭電梯上圓頂還需爬320級台階", "phone": null, "images": null, "address": null, "city_id": null, "website": null, "category": "歷史文化 / History & Culture", "latitude": 41.893851, "is_active": true, "longitude": 12.4931577, "region_id": null, "country_id": "italy", "created_at": "2025-12-06T07:06:36.769043+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "梵蒂岡聖彼得大教堂，天主教最大教堂。米開朗基羅設計的圓頂、貝尼尼的廣場柱廊，文藝復興藝術傑作。登圓頂俯瞰羅馬，西斯汀教堂看《創世紀》，是藝術與信仰的朝聖地。", "contact_name": null, "country_code": "IT", "english_name": "St. Peter's Basilica", "ticket_price": "依官網而定", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 717, "opening_hours": {"daily": "08:00-18:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 120}, {"id": "8b1a2a1f-2e83-4d71-8b84-1535f4fd0899", "fax": null, "name": "海東龍宮寺", "tags": ["寺廟", "海景", "祈福", "日出", "絕景"], "type": "temple", "notes": "韓國唯一建在海邊懸崖上的寺廟，1376年建立。有十二生肖石像、108階梯、達摩祖師像等。據說在此許願特別靈驗。日出時分景色最美。\n\n旅遊提示：建議早上或傍晚前往，避開中午人潮和暑熱", "phone": null, "