d", "data_verified": false, "display_order": 889, "opening_hours": {"daily": "18:00-23:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": null}, {"id": "8b5e9fff-dac5-45a1-874e-a2c436cd7c79", "fax": null, "name": "外灘私人遊艇黃浦江巡遊", "tags": ["奢華體驗", "頂級體驗"], "type": "attraction", "notes": "頂級體驗 | 奢華體驗 | 價位: | 難度:None", "phone": null, "images": null, "address": null, "city_id": "shanghai", "website": null, "category": "景點 / Attraction", "latitude": null, "is_active": true, "longitude": null, "region_id": null, "country_id": "china", "created_at": "2026-04-06T22:24:04.252916+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "搭乘私人遊艇巡遊黃浦江，欣賞外灘萬國建築與陸家嘴天際線", "contact_name": null, "country_code": "CN", "english_name": "The Bund Private Yacht Cruise", "ticket_price": null, "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 0}, {"id": "8bb0fe14-f363-4c79-ada9-c75109c0d289", "fax": null, "name": "札幌電視塔", "tags": null, "type": "attraction", "notes": null, "phone": null, "images": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/japan/8bb0fe14-f363-4c79-ada9-c75109c0d289-1.jpeg", "https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/japan/8bb0fe14-f363-4c79-ada9-c75109c0d289-2.jpeg"], "address": null, "city_id": "sapporo", "website": null, "category": "景點 / Attraction", "latitude": 43.0612, "is_active": true, "longitude": 141.3566, "region_id": "jp_hokkaido", "country_id": "japan", "created_at": "2026-01-23T00:39:12.791692+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "札幌電視塔，札幌大通公園東端的地標建築，高147.2公尺。展望台高90公尺，可360度俯瞰札幌市區、大通公園、石狩平原。這是札幌最佳觀景點，也是拍攝大通公園全景的好地方。建議傍晚上塔，