 of Literature", "ticket_price": "免費或依業者而異", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 100, "opening_hours": {"daily": "10:00-18:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 60}, {"id": "9bc53758-838e-4815-ad1b-4c6ee2f79ea4", "fax": null, "name": "默拉皮火山", "tags": ["火山", "吉普車", "冒險", "活火山", "日惹"], "type": "attraction", "notes": "印尼最活躍的火山之一，2010年曾大爆發。可搭吉普車遊覽火山周邊，看熔岩遺跡和被掩埋的村莊。刺激又帶教育意義。\n\n旅遊提示：日出吉普車之旅最熱門", "phone": null, "images": null, "address": null, "city_id": "yogyakarta", "website": null, "category": "自然風景 / Nature", "latitude": -7.5407, "is_active": true, "longitude": 110.4457, "region_id": null, "country_id": "indonesia", "created_at": "2025-12-06T02:07:00.616393+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "默拉皮火山，爪哇島最活躍的火山之一，海拔2,930公尺。可參加Jeep Lava Tour，搭越野車看火山岩漿遺跡、火山博物館、被火山摧毀的村落。日出登山健行也是熱門活動。早上前往最佳。", "contact_name": null, "country_code": "ID", "english_name": null, "ticket_price": "免費或依業者而異", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 812, "opening_hours": {"daily": "08:00-17:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 240}, {"id": "9bfa219b-0d69-469f-904c-3de0eb52d93f", "fax": null, "name": "卡納克神廟", "tags": ["世界遺產", "古蹟", "必去", "神廟", "盧克索"], "type": "heritage", "notes": "埃及最大神廟群，至少需2-3小時參觀。多柱廳的134根巨柱令人震撼。建議請導遊講解歷史背景。", "phone": null, "images": null, "address": null, "city_id": null, "website": null, "category": "歷史文化 / History & Culture", "latitude": 25.7196939, "is_active": true, "longitude": 32.6527265, "region_id": "eg_luxor", "country_id": "egypt", "created_at": "2025-12-06T01:27:06.025395+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "卡納克神廟，埃及古神廟遺跡，巨柱、方尖碑、浮雕記錄法老王的豐功偉業與古埃及宗教信仰