e", "phone": null, "images": ["https://images.unsplash.com/photo-1490806843957-31f4c9a91c65?w=800", "https://images.unsplash.com/photo-1576674421245-f2fd2c0f8257?w=800"], "address": null, "city_id": "tokyo", "website": null, "category": "景點 / Attraction", "latitude": null, "is_active": true, "longitude": null, "region_id": "jp_kanto", "country_id": "japan", "created_at": "2026-04-06T22:24:10.451608+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "在日本最神聖的富士山，由專業登山嚮導一對一帶領，體驗從夜間登山到山頂日出的難忘旅程。不同於一般大眾登山團，這是完全客製化的私人行程：專屬嚮導會根據你的體能調整步伐，在八合目山屋預訂最佳房間（非大通鋪），提供專業登山裝備，並在山頂預留最佳觀日出位置。登頂後享用熱騰騰的日式早餐便當，俯瞰雲海與日出的震撼美景。下山後前往河口湖溫泉旅館，享受私人風呂療癒疲憊的身體。", "contact_name": null, "country_code": "JP", "english_name": "Private Guided Mt. Fuji Summit Sunrise Experience", "ticket_price": null, "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 0}, {"id": "9ea926e7-698c-45c0-9743-3ac3f2f8840e", "fax": null, "name": "駱駝騎乘", "tags": ["體驗", "沙漠", "傳統"], "type": "experience", "notes": "體驗傳統沙漠交通方式。艾爾奧拉、利雅德郊區都可安排。約100-200里亞爾/小時。", "phone": null, "images": null, "address": null, "city_id": null, "website": null, "category": "活動體驗 / Activity", "latitude": 23.333333, "is_active": true, "longitude": 45.333333, "region_id": null, "country_id": "saudi_arabia", "created_at": "2025-12-06T01:49:15.704981+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "駱駝騎乘，沙烏地阿拉伯景點，伊斯蘭聖地與現代化城市並存，展現阿拉伯文化與石油經濟發展。", "contact_name": null, "country_code": "SA", "english_name": "Camel Riding", "ticket_price": "依官網而定", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": {"open": "預約制"}, "deleted_reason": null, "google_maps_url": nu