-12-06T02:12:12.196007+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "過橋米線，中國知名景點，值得探訪。", "contact_name": null, "country_code": "CN", "english_name": null, "ticket_price": "免費或依業者而異", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 733, "opening_hours": {"daily": "08:30-17:30"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": null}, {"id": "acc601f5-9c3e-455e-8ef6-a3947ee0f85c", "fax": null, "name": "山寺", "tags": ["寺廟", "登山", "紅葉", "歷史"], "type": "attraction", "notes": null, "phone": null, "images": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/japan/acc601f5-9c3e-455e-8ef6-a3947ee0f85c-1.jpg", "https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/japan/acc601f5-9c3e-455e-8ef6-a3947ee0f85c-2.jpg"], "address": null, "city_id": "yamagata", "website": null, "category": "歷史文化 / History & Culture", "latitude": 38.3095946, "is_active": true, "longitude": 140.434729, "region_id": "jp_tohoku", "country_id": "japan", "created_at": "2026-04-01T08:26:42.698493+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "《山寺》正式名稱為立石寺，創建於860年，是日本東北地區最具靈性的山岳寺院。從山門到奧之院需攀登1015級石階，沿途穿越蒼鬱杉林、經過奇岩怪石、古老堂宇，每一步都是修行。登頂後，五大堂展望台視野開闊，山形盆地、最上川、遠山層疊盡收眼底，秋季紅葉如火，冬季雪景幽靜。松尾芭蕉曾在此留下俳句「閑さや 岩にしみ入る 蝉の声」(寂靜深處，蟬聲滲入岩石)，道出山寺的禪意與幽靜。", "contact_name": null, "country_code": "JP", "english_name": "Yamadera (Risshakuji Temple)", "ticket_price": null, "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "google_maps_url": null, "duration_minutes": null}, {"id": "acc86025-9048-4afd-ae69-51ce9fed0738", "fax": null, "name": "婆那加占婆塔", "tags": ["古蹟", "芽莊", "印度教"], "type": "heritage", "notes": "千年占婆文明遺跡，供奉女神婆那加。可俯瞰芽莊海灣。門票22,000越盾。", "phone": null, "images": null, "address": null, "city_id": "nha-trang", "website": null, "category": "自然風景 / Nature", "latitude": 12.2653884, "is_active": true, "longitude": 109.1951777, "region_id": null, "country_id": "vietnam", "created_at": "2025-12-06T01:55:53.112809+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "芽莊婆那加占婆塔，建於7-12世紀，印度教廟宇遺跡。紅磚建築在陽光下散發古老氣息，精緻的雕刻展現占婆文化。站在山丘上，可以俯瞰芽莊海港。這是芽莊重要的歷史遺跡。", "contact_name": null, "country_code": "VN", "english_name": "Po Nagar Cham Towers", "ticket_price": "成人22,000越南盾", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 577, "opening_hours": {"daily": "06:00-18:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 60}, {"id": "ace8c56b-f21f-4070-b869-da910c20da9c", "fax": null, "name": "會安夜市", "tags": ["夜市", "燈籠", "會安"], "type": "attraction", "notes": "安會河畔的夜市，燈籠攤位最有特色。可買手工燈籠當紀念品。放水燈很浪漫。", "phone": null, "images": null, "address": null, "city_id": "hoi-an", "website": null, "category": "購物 / Shopping", "latitude": 15.8795863, "is_active": true, "longitude": 108.3319406, "region_id": null, "country_id": "vietnam", "created_at": "2025-11-01T13:04:52.40537+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "會安夜市，沿ThuBon河畔的夜市，每晚營業。販售燈籠、絲綢、木雕、手工藝品、紀念品。河邊有小吃攤，販售越南春捲、法國麵包、甘蔗汁。可以買水燈放河祈福，燈火漂流河面浪漫至極。這是會安夜晚必訪之地，也是購買紀念品的好地方。價格需議價，建議貨比三家。晚上7-10點最熱鬧。", "contact_name": null, "country_code": "VN", "english_name": "Hoi An Night Market", "ticket_price": "免費入場", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": {"daily": "夜市17:00-23:00，傳統市場06:00-18:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 120}, {"id": "ad16f17e-8d9a-452c-b1d2-b2cff60fcc40", "f