35df4fe4ff2-1.jpg", "https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/thailand/b0e49e3a-d0bf-4b5d-9b57-b35df4fe4ff2-2.jpg"], "address": null, "city_id": "pattaya", "website": null, "category": "景點 / Attraction", "latitude": 12.9708133, "is_active": true, "longitude": 100.9749216, "region_id": null, "country_id": "thailand", "created_at": "2026-03-29T11:41:06.33392+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "《暹羅冰雪世界》是東南亞最大的冰雕樂園，室內溫度常年保持零下10度。展區分為冰雕藝術區、冰滑梯遊樂區、極地動物區，所有雕塑皆由中國哈爾濱冰雕師傅製作。遊客租借厚重外套入內，體驗熱帶國家難得的冰雪世界，冰吧提供特調冰飲，是炎夏獨特體驗。", "contact_name": null, "country_code": "TH", "english_name": "Frost Magical Ice of Siam", "ticket_price": null, "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": "10:00-20:00", "deleted_reason": null, "google_maps_url": null, "duration_minutes": 90}, {"id": "b10550cc-1d51-4a28-a8fd-44ffc28929f5", "fax": null, "name": "親不知子斷崖", "tags": null, "type": "attraction", "notes": null, "phone": null, "images": null, "address": "花蓮縣豐濱鄉台11線", "city_id": "769364e9-d3e2-474f-bc80-0184c00e6d9e", "website": null, "category": "自然風景 / Nature", "latitude": 23.65, "is_active": true, "longitude": 121.5167, "region_id": null, "country_id": "taiwan-country-001", "created_at": "2026-01-09T03:43:44.063392+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "花蓮豐濱親不知子斷崖，古道緊貼著峭壁，腳下就是太平洋驚濤拍岸。傳說過去的母親抱著孩子走過斷崖，因為太驚險，只能專注腳步，無暇顧及孩子，因而得名「親不知子」。如今改建成透明天空步道，部分路段是強化玻璃，可以看到腳下的海浪拍打岩石，驚險刺激。走過步道需要勇氣，但風景絕對值得——蔚藍太平洋、峭壁奇岩、遠處的磯崎海灣,都在視野中。這是花東海岸最刺激的景點。", "contact_name": null, "country_code": "TW", "english_name": "Qinbuzhizi Cliff", "ticket_price": "全票40元", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 74, "opening_hours": {"daily": "09:00-1