ta_verified": false, "display_order": 376, "opening_hours": {"daily": "09:00-22:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 240}, {"id": "b1ca7642-47b3-44a2-8197-ba99a940a5ad", "fax": null, "name": "晴空塔", "tags": ["世界最高塔", "東京地標", "634公尺", "展望台", "富士山", "夜景", "墨田水族館", "購物"], "type": "attraction", "notes": "展望台票價：天望甲板2100日圓起，天望回廊加購1000日圓。建議網路預約指定時間票避免排隊。日落時分上塔可同時欣賞夕陽和夜景。晴天才看得到富士山。", "phone": null, "images": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/japan/b1ca7642-47b3-44a2-8197-ba99a940a5ad-1.jpeg", "https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/japan/b1ca7642-47b3-44a2-8197-ba99a940a5ad-2.jpeg"], "address": null, "city_id": "tokyo", "website": null, "category": "活動體驗 / Activity", "latitude": 35.7101, "is_active": true, "longitude": 139.8107, "region_id": "jp_kanto", "country_id": "japan", "created_at": "2025-10-27T15:26:40.818404+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "東京晴空塔，高634公尺，日本最高建築。350公尺天望デッキ和450公尺天望回廊兩個觀景台，360度俯瞰東京。天氣好時能看到富士山。購物商場Solamachi有300家商店、水族館、天文館。夜晚塔身點燈，「雅」和「粋」交替。這是東京新地標，也是看東京夜景的最佳地點。", "contact_name": null, "country_code": "JP", "english_name": "Tokyo Skytree", "ticket_price": "350m觀景台平日2100日圓、假日2300日圓，450m追加1000-1100日圓", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 2, "opening_hours": {"daily": "08:00-22:00（最後入場21:00）"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 120}, {"id": "b1df4517-7555-4037-b6f5-8da03a890821", "fax": null, "name": "天竺山森林公園", "tags": null, "type": "park", "notes": null, "phone": null, "images": null, "address": null, "city_id": null, "website": null, "category": "自然風景 / Nature", "latitude": 24.5438732, "is_active": true, "longitude": 118.0768065, "region_id": null, "country_id": "china", "created_at": "2025-12-06T01:13:29.089213+00:00", "cr