22.659012+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "上海中心大廈，中國第一高樓，高632公尺，世界第二高樓。118層觀景台「上海之巔」，是世界最高觀景台之一。高速電梯55秒直達，360度俯瞰上海。黃浦江、外灘、東方明珠盡收眼底。夜景璀璨，整個上海在腳下閃耀。", "contact_name": null, "country_code": "CN", "english_name": "Shanghai Tower", "ticket_price": "成人198元", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 31, "opening_hours": {"daily": "08:30-21:30（最後入場21:00）"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 90}, {"id": "b20b37c7-2638-4762-b338-7fb539763a40", "fax": null, "name": "小野柳", "tags": null, "type": "attraction", "notes": null, "phone": null, "images": null, "address": "台東縣台東市松江路一段500號", "city_id": "02d6cb3c-b3d0-40c7-b283-d2d5f446ba1d", "website": null, "category": "自然風景 / Nature", "latitude": 22.7989, "is_active": true, "longitude": 121.1833, "region_id": null, "country_id": "taiwan-country-001", "created_at": "2026-01-09T03:36:28.944514+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "台東海濱的天然地質景觀，珊瑚礁和岩岸地形酷似野柳。海蝕平台、豆腐岩、蜂窩岩，各種奇特地形在此集中展現。退潮時可以走在岩石平台上，近距離觀察海蝕地形。這是認識台灣東岸地質最好的戶外教室。", "contact_name": null, "country_code": "TW", "english_name": "Xiaoyeliu", "ticket_price": "免費", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 48, "opening_hours": {"daily": "全天開放"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 60}, {"id": "b23717a3-8e6f-4ef8-8c8e-122766b74f89", "fax": null, "name": "陽明山國家公園", "tags": ["國家公園", "溫泉", "花季", "健行", "自然"], "type": "national_park", "notes": "台北近郊的火山地質公園，以溫泉、硫磺噴氣孔、杜鵑花聞名。春天花季時滿山遍野的杜鵑和櫻花，秋天的芒花也很壯觀。小油坑的硫磺噴氣是必訪景點。", "phone": null, "images": null, "address": null, "city_id": null, "website": null, "category": "自然風景 / Nature", "latitude": 25.1667, "is_active": true, "longitude": 121.55, "region_id": null, "country_id": "taiwan-country-001", "created_at": "2025-12-16T06:49:58.435491+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "台北陽明山國家公園，台灣第三座國家公園。火山地形、溫泉、櫻花、芒花、箭竹林,四季景色不同。春天賞櫻賞杜鵑，夏天避暑健行，秋天看芒花，冬天泡溫泉。擎天崗草原、小油坑硫磺噴氣孔、陽明書屋、冷水坑，每個景點都有特色。這是台北人的後花園，也是認識台灣火山地質的最佳教室。", "contact_name": null, "country_code": "TW", "english_name": "Yangmingshan National Park", "ticket_price": "免費", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 662, "opening_hours": {"daily": "24小時"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 300}, {"id": "b251c5da-d501-4784-87d4-3b63f67d9725", "fax": null, "name": "曼谷王船博物館", "tags": null, "type": "museum", "notes": null, "phone": null, "images": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/thailand/b251c5da-d501-4784-87d4-3b63f67d9725-1.jpeg", "https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/thailand/b251c5da-d501-4784-87d4-3b63f67d9725-2.jpeg"], "address": null, "city_id": "bangkok", "website": null, "category": "歷史文化 / History & Culture", "latitude": 13.7563, "is_active": true, "longitude": 100.5018, "region_id": null, "country_id": "thailand", "created_at": "2025-12-06T01:24:38.579566+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "曼谷諾伊運河旁的皇家船隊博物館，收藏泰國歷代皇家龍舟。52艘金碧輝煌的御用船隻中，最著名的是長達50公尺的金色龍舟Suphannahong。御船巡遊是泰王登基慶典的傳統。", "contact_name": null, "country_code": "TH", "english_name": "Royal Barge Museum", "ticket_price": "成人200-300泰銖", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": {"daily": "09:00-16:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": null}, {"id": "b2534508-5531-41be-a70a-2004dff0279f", "fax": null, "name": "札幌拉麵橫丁", "tags": ["拉麵", "味噌", "必吃"], "type": "food", "notes": null, "phone": null, "images": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/japan/b2534508-5531-41be-a70a-2004dff0279f-1.jpeg", "https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/japan/b2534508-5531-41be-a70a-2004dff0279f-2.jpeg"], "address": null, "city_id": "sapporo", "website": null, "category": "活動體驗 / Activity", "latitude": 43.061936, "is_active": true, "longitude": 141.3542924, "region_id": "jp_hokkaido", "country_id": "japan", "created_at": "2025-12-06T06:49:57.482546+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "札幌拉麵橫丁，札幌薄野區的拉麵街，1951年開業。17家小型拉麵店密集，每家僅8-10席座位。味噌拉麵是札幌特色，湯頭濃郁、加入玉米奶油。這是札幌拉麵發源地，也是體驗昭和時代氛圍的好地方。每碗約850-1,000日圓，建議晚上前往，充滿懷舊氣息。可搭配薄野區夜生活一起體驗。", "contact_name": null, "country_code": "JP", "english_name": "Sapporo Ramen Yokocho", "ticket_price": "約800-2000日圓/人", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 179, "opening_hours": {"daily": "11:00-22:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": null}, {"id": "b2884120-5b47-4971-bd83-617b1ca70cc8", "fax": null, "name": "泰式按摩課程", "tags": ["按摩", "課程", "體驗"], "type": "experience", "notes": null, "phone": null, "images": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/thailand/b2884120-5b47-4971-bd83-617b1ca70cc8-1.jpeg", "https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/thailand/b2884120-5b47-4971-bd83-617b1ca70cc8-2.jpeg"], "address": null, "city_id": "bangkok", "website": null, "category": "活動體驗 / Activity", "latitude": 13.7524938, "is_active": true, "longitude": 100.4935089, "region_id": null, "country_id": "thailand", "created_at": "2025-12-06T01:49:10.953851+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "《泰式按摩課程》通常為期三至七天,在臥佛寺或私人學校開設。課程從基礎解剖學開始,學習如何用體重而非蠻力施壓,掌握十條能量線(Sen)的走向。練習對象是同學彼此,過程中你會深刻體會到給予與接受按摩都需要專注。正統課程要求穿著寬鬆棉質服裝,赤腳在墊子上操作。這不只是技術學習,更是身體哲學的入門——如何傾聽他人身體的訊息,如何在施力中保持放鬆。結業後可獲認證,但真正的價值在於重新理解觸碰、平衡與呼吸的關係。", "contact_name": null, "country_code": "TH", "english_name": "Thai Massage Course", "ticket_price": "約300-600泰銖/小時", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": {"daily": "10:00-22:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": null}, {"id": "b2a346c7-525f-4289-bf64-3280fdac7511", "fax": null, "name": "新倉山淺間公園", "tags": null, "type": "attraction", "notes": null, "phone": null, "images": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/japan/b2a346c7-525f-4289-bf64-3280fdac7511-1.jpeg", "https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/japan/b2a346c7-525f-4289-bf64-3280fdac7511-2.jpeg"], "address": null, "city_id": "ebe380fc-1d8f-4555-8272-f3876f41b58b", "website": null, "category": "景點 / Attraction", "latitude": 35.5, "is_active": true, "longitude": 138.8, "region_id": "jp_kanto", "country_id": "japan", "created_at": "2026-01-23T02:43:30.937785+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "新倉山淺間公園，日本名山，自然風光優美，適合登山健行與欣賞四季景色。", "contact_name": null, "country_code": "JP", "english_name": "Arakurayama Sengen Park", "ticket_price": "成人300-500日圓", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 100, "opening_hours": {"daily": "09:00-17:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 90}, {"id": "b2a9f643-dc55-49e3-b98e-4eadd72a1b8f", "fax": null, "name": "大原美術館", "tags": ["美術館", "西洋畫", "文化", "藝術"], "type": "attraction", "notes": "日本第一座西洋美術館，收藏莫內、雷諾瓦等大師作品", "phone": null, "images": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/japan/b2a9f643-dc55-49e3-b98e-4eadd72a1b8f-1.jpg", "https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/japan/b2a9f643-dc55-49e3-b98e-4eadd72a1b8f-2.jpeg"], "address": null, "city_id": null, "website": "https://www.ohara.or.jp/", "category": "歷史文化 / History & Culture", "latitude": 34.6658, "is_active": true, "longitude": 133.9178, "region_id": "jp_chugoku", "country_id": "japan", "created_at": "2026-03-17T03:16:16.356483+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "日本第一座西洋美術館，收藏莫內、雷諾瓦、高更等印象派大師作品。美術館本身就是藝術品，希臘風格的建築、精心設計的展廳，讓藝術欣賞成為一種享受。這是倉敷文化的象徵，也是日本西洋美術收藏的重要據點。", "contact_name": null, "country_code": "JP", "english_name": "Ohara Museum of Art", "ticket_price": "成人1500日圓", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": {"closed": "週一", "tue_sun": "09:00-17:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 120}, {"id": "b2b3e271-b93f-491f-a25c-bf7aa4e6c645", "fax": null, "name": "日月老茶廠", "tags": null, "type": "attraction", "notes": null, "phone": null, "images": null, "address": "南投縣魚池鄉有水巷38號", "city_id": "nantou-698c1821-d3e7-4008-a70e-7633ba447409", "website": null, "category": "活動體驗 / Activity", "latitude": 23.8775, "is_active": true, "longitude": 120.9081, "region_id": null, "country_id": "taiwan-country-001", "created_at": "2026-01-09T03:43:44.063392+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "南投魚池的老茶廠，建於1959年。紅磚建築、木造屋頂，保留了老茶廠的歷史氛圍。現在轉型為觀光茶廠，開放參觀製茶過程，有品茗區可以品嚐紅茶。茶廠販售各式茶葉和茶點，是認識台灣茶文化的好地方。", "contact_name": null, "country_code": "TW", "english_name": "Sun Moon Lake Tea Factory", "ticket_price": "免費參觀", "workspace_i