s": null}, {"id": "b63575cc-162c-456d-b8e4-97c588f9cdfe", "fax": null, "name": "蘭納傳統舞蹈晚宴", "tags": ["傳統晚宴", "舞蹈表演", "泰北料理"], "type": "experience", "notes": null, "phone": null, "images": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/thailand/b63575cc-162c-456d-b8e4-97c588f9cdfe-1.jpeg", "https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/thailand/b63575cc-162c-456d-b8e4-97c588f9cdfe-2.jpeg"], "address": null, "city_id": "chiang-mai", "website": null, "category": "景點 / Attraction", "latitude": 18.7882778, "is_active": true, "longitude": 98.9858802, "region_id": null, "country_id": "thailand", "created_at": "2025-12-06T01:49:11.622483+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "《蘭納傳統舞蹈晚宴》Khantoke Dinner 是泰北傳統宴席形式,賓客席地而坐圍繞木製矮桌(Khantoke),享用泰北料理的同時觀賞傳統舞蹈表演。菜色包括咖哩雞、炸豬皮、北方香腸、青木瓜沙拉、糯米飯,口味道地但為了觀光客會降低辣度。舞蹈表演分多段,包括指甲舞、劍舞、蠟燭舞,服飾華麗,動作優雅。這是文化展演而非日常餐飲,有刻意包裝的成分,但對想快速了解蘭納文化的人來說是合理選擇。多家餐廳提供此服務,Old Chiang Mai Cultural Center 最具代表性。適合第一次來清邁、想體驗傳統文化的旅人。", "contact_name": null, "country_code": "TH", "english_name": "Khantoke Dinner", "ticket_price": "免費或依業者而異", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": {"daily": "09:00-18:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": null}, {"id": "b64d9953-521f-4c81-a2a4-6506d2f806e5", "fax": null, "name": "外灘", "tags": ["歷史", "建築", "夜景"], "type": "attraction", "notes": "上海地標，萬國建築博覽群，夜景最美，建議傍晚前往看日落和夜景", "phone": null, "images": null, "address": null, "city_id": null, "website": null, "category": "活動體驗 / Activity", "latitude": 31.2394, "is_active": true, "longitude": 121.499, "region_id": "cn_east", "country_id": "china", "created_at": "2025-11-01T10:48:50.33133+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "外灘，黃浦江西岸的萬國建築博覽群。哥德式、巴洛克、裝飾藝術風格建築並列，訴說上海租界歷史。對岸是陸家嘴三巨頭：東方明珠、環球金融、上海中心。夜晚燈光璀璨，遊船穿梭江面。", "contact_name": null, "country_code": "CN", "english_name": "The Bund", "ticket_price": "免費", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": {"daily": "全天開放，夜景最佳時間19:00-22:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 120}, {"id": "b68e36f6-7529-4e5b-a5e5-07e21764e4eb", "fax": null, "name": "日月潭", "tags": null, "type": "attraction", "notes": null, "phone": null, "images": null, "address": "南投縣魚池鄉中山路599號", "city_id": "nantou-698c1821-d3e7-4008-a70e-7633ba447409", "website": null, "category": "自然風景 / Nature", "latitude": 23.8652, "is_active": true, "longitude": 120.9163, "region_id": null, "country_id": "taiwan-country-001", "created_at": "2026-01-09T03:36:28.944514+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "日月潭是台灣最美的高山湖泊，海拔748公尺，湖面面積約7.7平方公里。清晨時分，霧氣籠罩湖面，遠山若隱若現；黃昏時，夕陽將湖水染成金黃。環湖步道、自行車道完善，可以用不同方式探索這座湖泊的美。這是台灣最具代表性的風景區，也是認識台灣高山湖泊生態的最佳場域。", "contact_name": null, "country_code": "TW", "english_name": "Sun Moon Lake", "ticket_price": "免費（遊船、纜車另計）", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 51, "opening_hours": {"daily": "全天開放，遊船約09:00-17:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 180}, {"id": "b6989786-62da-400b-aa42-da85da8e0a52", "fax": null, "name": "廣東省博物館", "tags": ["博物館", "免費", "嶺南文化", "建築", "文物"], "type": "attraction", "notes": "華南最大博物館，免費", "phone": null, "images": null, "address": "廣州市天河區珠江東路2號", "city_id": null, "website": null, "category": "歷史文化 / History & Culture", "latitude": 23.1183, "is_active": true, "longitude": 113.3267, "region_id": "cn_south", "country_id": "china", "created_at": "2025-12-05T14:47:41.47246+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "廣東省博物館，中國博物館，展示中國歷史文化藝術與科學知識。", "contact_name": null, "country_code": "CN", "english_name": "Guangdong Museum", "ticket_price": "免費或20-50元", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 26, "opening_hours": {"closed": "週一", "tue_sun": "09:00-17:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 180}, {"id": "b6a85788-5c94-4f30-96c7-82392316161b", "fax": null, "name": "有田燒陶瓷拉坯與繪製", "tags": ["工藝體驗", "頂級體驗"], "type": "attraction", "notes": "頂級體驗 | 工藝體驗 | 價位: | 難度:None", "phone": null, "images": ["https://images.unsplash.com/photo-1578749556568-bc2c40e68b61?w=800", "https://images.unsplash.com/photo-1565193566173-7a0ee3dbe261?w=800"], "address": null, "city_id": "fukuoka", "website": null, "category": "景點 / Attraction", "latitude": null, "is_active": true, "longitude": null, "region_id": "jp_kyushu", "country_id": "japan", "created_at": "2026-04-06T22:24:07.821381+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "有田燒是日本最早的瓷器，擁有400年歷史，以精緻的白瓷和華麗的彩繪聞名。在九州有田町的傳統窯元，跟隨陶藝世家第十五代傳人學習從拉坯到繪製的完整流程。使用有田特有的泉山陶石，在轆轤上手工成型，再以傳統染付技法（青花）或赤繪技法（紅色）繪製圖案。作品將在柴燒登窯中以1300度高溫燒製，完成後國際運送。", "contact_name": null, "country_code": "JP", "english_name": "Arita-yaki Porcelain Throwing & Painting", "ticket_price": null, "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 0}, {"id": "b6aa8e1d-56b9-44c0-988d-12cd864b4d2f", "fax": null, "name": "瓦洛洛市場", "tags": ["傳統市場", "生鮮", "在地生活"], "type": "attraction", "notes": null, "phone": null, "images": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/thailand/b6aa8e1d-56b9-44c0-988d-12cd864b4d2f-1.jpeg", "https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/thailand/b6aa8e1d-56b9-44c0-988d-12cd864b4d2f-2.jpeg"], "address": null, "city_id": "chiang-mai", "website": null, "category": "購物 / Shopping", "latitude": 18.7902357, "is_active": true, "longitude": 99.000535, "region_id": null, "country_id": "thailand", "created_at": "2025-11-01T12:55:07.838102+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "《瓦洛洛市場》Warorot Market 與瓦洛洛市集為同一地點,清邁最大的傳統市場。建築分三層,一樓生鮮、二樓乾貨、三樓服飾雜貨。這裡是在地人的日常採買地,觀光客稀少。生鮮區的魚蝦肉類堆疊如山,蔬果攤位色彩繽紛,空氣中混合著魚腥、香料與熱帶水果的氣味。乾貨區可以買到泰北特產:炸豬皮、香腸、辣椒醬、醃菜。三樓是便宜服飾,質量普通但價格低廉。市場外圍有小吃攤,清晨的粿條湯、豆漿油條都是銅板價。來這裡不是為了購物,而是為了感受清邁日常生活的溫度——混亂、真實、充滿人間煙火。", "contact_name": null, "country_code": "TH", "english_name": "Warorot Market", "ticket_price": "免費", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": {"daily": "18:00-00:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 120}, {"id": "b704796f-3a5a-4744-9e95-e985cfc6337c", "fax": null, "name": "安平古堡", "tags": null, "type": "attraction", "notes": null, "phone": null, "images": ["https://wzvwmawpkapcmkfmkvav.supabase.co/storage/v1/object/public/resources/attractions/b704796f-3a5a-4744-9e95-e985cfc6337c/1776736845015_kh5k3xto24.jpg"], "address": "台南市安平區國勝路82號", "city_id": "tainan-35ba0392-8bed-40b6-b7af-706ea6be60a5", "website": null, "category": "歷史文化 / History & Culture", "latitude": 23.0014, "is_active": true, "longitude": 120.1605, "region_id": null, "country_id": "taiwan-country-001", "created_at": "2026-01-09T03:31:23.908376+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-21T02:00:47.451603+00:00", "updated_by": null, "description": "台南最古老的城堡，荷蘭人在1624年建造的熱蘭遮城遺跡。紅磚城牆經過400年風霜，依然堅固。登上瞭望台，可以俯瞰安平港口和市區。這座城堡見證了荷蘭、明鄭、清代的統治，是台灣歷史的縮影。", "contact_name": null, "country_code": "TW", "english_name": "Anping Fort", "ticket_price": "全票70元", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 21, "opening_hours": {"daily": "08:30-17:30"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 60}, {"id": "b71bb246-73b9-4e25-a554-ac6eebc9e575", "fax": null, "name": "昭披耶公主號晚宴", "tags": ["遊船晚宴", "河景觀光", "傳統表演"], "type": "experience", "notes": "五星級河上晚宴，自助餐配現場音樂。欣賞鄭王廟、大皇宮夜景。約1500-2500泰銖/人。建議預訂。", "phone": null, "images": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/thailand/b71bb246-73b9-4e25-a554-ac6eebc9e575-1.jpeg", "https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/thailand/b71bb246-73b9-4e25-a554-ac6eebc9e575-2.jpeg"], "address": null, "city_id": "bangkok", "website": null, "category": "自然風景 / Nature", "latitude": 13.725, "is_active": true, "longitude": 100.5108, "region_id": null, "country_id": "thailand", "created_at": "2025-12-06T01:49:11.334995+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "《昭披耶公主號晚宴》Chao Phraya Princess Cruise 是一艘三層樓高的遊船,每晚載著數百名遊客在昭披耶河上航行兩小時。自助式晚餐提供泰式與國際料理,品質中規中矩,重點不在食物而在流動的風景:大皇宮、鄭王廟、拉瑪八世橋,這些白天擁擠的景點在夜晚打上燈光,從河面上看去有種距離的美感。船上有現場樂隊演奏與泰國傳統舞蹈表演,氛圍是觀光化的浪漫。這是給第一次來曼谷的人的入門體驗,不深刻但也不會失望。河風吹散白天的燥熱,城市的燈火在水面上拉長成模糊的光帶。這是可以預期的美好。", "contact_name": null, "country_code": "TH", "english_name": "Chao Phraya Princess Cruise", "ticket_price": "免費或依業者而異", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": {"daily": "09:00-18:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 150}, {"id": "b7de2833-528b-4dd9-8c97-3acbf4223c4d", "fax": null, "name": "越秀公園", "tags": ["公園", "五羊雕塑", "地標", "免費"], "type": "attraction", "notes": "五羊雕塑是廣州市徽來源", "phone": null, "images": null, "address": "廣州市越秀區解放北路960號", "city_id": null, "website": null, "category": "自然風