: null, "google_maps_url": null, "duration_minutes": 180}, {"id": "b9250dc3-9d63-458d-9866-301dbda5f49e", "fax": null, "name": "樂高樂園", "tags": null, "type": "attraction", "notes": null, "phone": null, "images": ["https://wzvwmawpkapcmkfmkvav.supabase.co/storage/v1/object/public/resources/attractions/b9250dc3-9d63-458d-9866-301dbda5f49e/1775740808597_jxclylhs5pp.png"], "address": "", "city_id": null, "website": null, "category": "景點 / Attraction", "latitude": null, "is_active": true, "longitude": null, "region_id": null, "country_id": "japan", "created_at": "2026-04-09T11:48:18.890114+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "位於名古屋的日本樂高樂園 (LEGOLAND Japan) 是專為 2 至 12 歲兒童及其家庭設計的夢幻樂園。園內不僅有超過 40 種遊樂設施，還有由 1,700 萬塊積木打造的壯觀場景。", "contact_name": null, "country_code": "JP", "english_name": null, "ticket_price": null, "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "google_maps_url": null, "duration_minutes": null}, {"id": "b928a302-9238-4d22-ba42-317a2fb94b32", "fax": null, "name": "西湖", "tags": ["湖泊", "單車", "晨跑"], "type": "attraction", "notes": null, "phone": null, "images": null, "address": null, "city_id": "hanoi", "website": null, "category": "自然風景 / Nature", "latitude": 21.0580419, "is_active": true, "longitude": 105.8139655, "region_id": null, "country_id": "vietnam", "created_at": "2026-04-04T11:17:37.351+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "《西湖》是河內最大的淡水湖,周長約17公里,湖畔聚集高級餐廳、咖啡館與外國使館。清晨時分湖邊擠滿晨跑與太極拳的市民,傍晚則成為年輕人的約會地點。湖畔的鎮國寺是河內最古老的佛寺,紅色佛塔倒映在湖水中構成經典畫面。租輛單車環湖,或在湖畔咖啡館坐一下午,都是理解河內生活節奏的方式。這裡不是刻意營造的景觀,而是城市日常的一部分——河內人在此運動、約會、冥想,湖水見證這座城市的呼吸。", "contact_name": null, "country_code": "VN", "english_name": "West Lake", "ticket_price": null, "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "google_maps_url": null, "duration_minutes": null}, {"id": "b94ad559-fbc2-4e68-973b-d7b06c83c525", "fax": null, "name": "暹羅傳奇樂園", "tags": ["文化", "主題樂園", "表演", "親子"], "type": "主題樂園", "notes": null, "phone": null, "images": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/thailand/b94ad559-fbc2-4e68-973b-d7b06c83c525-1.jpg", "https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/thailand/b94ad559-fbc2-4e68-973b-d7b06c83c525-2.jpg"], "address": null, "city_id": "pattaya", "website": null, "category": "景點 / Attraction", "latitude": null, "is_active": true, "longitude": null, "region_id": null, "country_id": "thailand", "created_at": "2026-03-29T11:41:05.813366+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "《暹羅傳奇樂園》以泰國三大王朝歷史為主題，重現素可泰、大城、拉達那哥辛時期建築與文化。園區分為文化村、市集、表演劇場，遊客可體驗泰拳、傳統舞蹈、手工藝製作。夜間水上劇場結合煙火、燈光、特技，呈現泰國史詩故事。對於想深入了解泰國文化又不失娛樂性的旅客，是絕佳選擇。", "contact_name": null, "country_code": "TH", "english_name": "Legend Siam Pattaya", "ticket_price": null, "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": "09:00-22:00", "deleted_reason": null, "google_maps_url": null, "duration_minutes": 240}, {"id": "b9966125-3e0b-4cf9-8593-8926a9c4d487", "fax": null, "name": "鬼石坊主地獄", "tags": null, "type": "attraction", "notes": null, "phone": null, "images": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/japan/b9966125-3e0b-4cf9-8593-8926a9c4d487-1.jpeg", "https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/japan/b9966125-3e0b-4cf9-8593-8926a9c4d487-2.jpeg"], "address": null, "city_id": "beppu", "website": null, "category": "景點 / Attraction", "latitude": 33.3217, "is_active": true, "longitude": 13