untry_code": "JP", "english_name": "Arakurayama Sengen Park", "ticket_price": "免費", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 693, "opening_hours": {"daily": "全天開放"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 90}, {"id": "bfc52494-3410-4e8f-b857-fe37d210058e", "fax": null, "name": "胡志明市咖啡文化博物館", "tags": ["咖啡", "博物館", "滴漏"], "type": "attraction", "notes": null, "phone": null, "images": null, "address": null, "city_id": "ho-chi-minh", "website": null, "category": "歷史文化 / History & Culture", "latitude": null, "is_active": true, "longitude": null, "region_id": null, "country_id": "vietnam", "created_at": "2026-04-04T11:19:47.021+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "《胡志明市咖啡文化博物館》位於老公寓三樓,展示越南咖啡從種植、烘焙到沖煮的完整歷史。館藏包含古董咖啡機、烘豆器、磨豆機,還有各時期的咖啡包裝與廣告。館長會親自沖煮咖啡,解釋越南滴漏咖啡的技巧與哲學。這裡不是華麗的博物館,而是咖啡愛好者的私人收藏空間。門票包含一杯咖啡,可以坐在復古家具上慢慢品嚐。咖啡博物館證明:越南咖啡文化深厚,值得被認真對待。", "contact_name": null, "country_code": "VN", "english_name": "Saigon Coffee Museum", "ticket_price": null, "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "google_maps_url": null, "duration_minutes": null}, {"id": "bfe6c75b-ce7f-4b6b-86b7-86f86cc50100", "fax": null, "name": "三十三間堂", "tags": null, "type": "temple", "notes": "堂內 1001 尊千手觀音像整齊排列，每尊表情都不同，氣勢震撼。", "phone": null, "images": ["https://images.pexels.com/photos/15993978/pexels-photo-15993978.jpeg?auto=compress&cs=tinysrgb&h=650&w=940", "https://images.pexels.com/photos/6192212/pexels-photo-6192212.jpeg?auto=compress&cs=tinysrgb&h=650&w=940", "https://images.pexels.com/photos/7486691/pexels-photo-7486691.jpeg?auto=compress&cs=tinysrgb&h=650&w=940", "https://images.pexels.com/photos/33545207/pexels-photo-33545207.jpeg?auto=compress&cs=tinysrgb&h=650&w=940", "https://images.pexels.com/photos/2924090/pexels-photo-2924090.jpeg?auto=compress&cs=tinysrgb&h=650&w=940"], "address": null, "city_id": "kyoto", "website": null, "category": "歷史文化 / History & Culture", "latitude": 34.9877, "is_active": true, "longitude": 135.7717, "region_id": "jp_kansai", "country_id": "japan", "created_at": "2025-12-06T01:24:26.233881+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "京都三十三間堂，蓮華王院本堂，以千手觀音聞名。1001尊等身大千手觀音立像排列，中央坐像高3.3公尺，國寶級文物。堂內長120公尺，33間，故名三十三間堂。這是京都最震撼的佛教藝術景點，也是攝影可搭配京都國立博物館一起參觀。", "contact_name": null, "country_code": "JP", "english_name": "Sanjusangendo", "ticket_price": "免費或依業者而異", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": {"daily": "10:00-18:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 60}, {"id": "c01dc90d-627e-49d8-ab7b-d5b04f389e66", "fax": null, "name": "邦盛魚市場", "tags": ["市場", "海鮮", "在地", "美食"], "type": "市場", "notes": null, "phone": null, "images": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/thailand/c01dc90d-627e-49d8-ab7b-d5b04f389e66-1.jpg", "https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/thailand/c01dc90d-627e-49d8-ab7b-d5b04f389e66-2.jpg"], "address": null, "city_id": "pattaya", "website": null, "category": "購物 / Shopping", "latitude": null, "is_active": true, "longitude": null, "region_id": null, "country_id": "thailand", "created_at": "2026-03-29T11:41:08.438276+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "《邦盛魚市場》是春武里府最大的海鮮市場，凌晨漁船返港卸貨，新鮮漁獲直送攤位。遊客可親眼挑選龍蝦、螃蟹、海魚，交由現場餐廳代為料理，價格實惠、份量足。市場周圍有傳統小吃攤，販售泰式甜品、炸物。想體驗在地生活、品嚐最新鮮海鮮的旅客，值得一訪。", "contact_name": null, "country_code": "TH", "english_name": "Bangsaen Fish Market", "ticket_price": null, "workspace_id": "8ef05a74-1f87-48ab-afd3-9b