n_id": null, "country_id": "singapore", "created_at": "2025-12-06T02:06:36.0189+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "新加坡魚尾獅公園，城市地標。高8.6公尺的魚尾獅雕像，獅頭代表新加坡原名Singapura，魚尾象徵漁村起源。雕像口中噴水，背景是濱海灣金沙、摩天輪，是新加坡最經典的拍照角度。雖然公園不大，但這是每個遊客必訪的打卡點。", "contact_name": null, "country_code": "SG", "english_name": null, "ticket_price": "免費", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 610, "opening_hours": {"daily": "全天開放"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 30}, {"id": "c69f7ffa-cf78-47ec-b241-0429693b9456", "fax": null, "name": "芭東海灘", "tags": ["必去", "海灘", "普吉島", "夜生活"], "type": "attraction", "notes": "普吉島最熱鬧的海灘，水上活動與夜生活應有盡有。", "phone": null, "images": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/thailand/c69f7ffa-cf78-47ec-b241-0429693b9456-1.jpeg", "https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/thailand/c69f7ffa-cf78-47ec-b241-0429693b9456-2.jpeg"], "address": null, "city_id": "phuket", "website": null, "category": "活動體驗 / Activity", "latitude": 7.8961, "is_active": true, "longitude": 98.2972, "region_id": null, "country_id": "thailand", "created_at": "2025-10-27T15:26:40.818404+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "普吉島芭東海灘，普吉最熱鬧的海灘。3公里長的沙灘、清澈海水、水上活動、海灘酒吧，應有盡有。白天曬太陽玩水，傍晚看日落，夜晚逛班贊海鮮市場、江西冷購物中心。這裡不是最美的海灘，但最方便、最熱鬧。適合喜歡熱鬧的遊客。", "contact_name": null, "country_code": "TH", "english_name": "Patong Beach", "ticket_price": "免費", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 1, "opening_hours": {"daily": "全天開放"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 240}, {"id": "c6c3afcb-21fd-4e97-acc3-85571a6c6354", "fax": null, "name": "綠山動物園", "tags"