ull, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "台東知本溫泉區，是台灣東部最著名的溫泉鄉。弱鹼性碳酸氫鈉泉，泉質清澈無色，對皮膚溫和。溫泉飯店、露天風呂集中在此，在山林環繞中泡湯，是放鬆身心的最佳選擇。知本溫泉已有百年歷史，是台東旅遊的重要據點。", "contact_name": null, "country_code": "TW", "english_name": "Zhiben Hot Springs", "ticket_price": "依業者而異，約200-500元/人", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 45, "opening_hours": {"daily": "依各溫泉業者營業時間"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 120}, {"id": "c70bbd13-870d-46ba-acdd-0c148756d1f8", "fax": null, "name": "境港魚市場", "tags": ["市場", "海鮮", "螃蟹", "美食"], "type": "attraction", "notes": "山陰地區最大漁港，可品嚐新鮮海產和松葉蟹（11-3月產季）", "phone": null, "images": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/japan/c70bbd13-870d-46ba-acdd-0c148756d1f8-1.jpeg", "https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/japan/c70bbd13-870d-46ba-acdd-0c148756d1f8-2.jpeg"], "address": null, "city_id": null, "website": null, "category": "購物 / Shopping", "latitude": 35.535, "is_active": true, "longitude": 133.236, "region_id": "jp_chugoku", "country_id": "japan", "created_at": "2026-03-17T03:16:16.356483+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "鳥取境港魚市場，境港的海鮮市場，日本海新鮮漁獲、松葉蟹、海鮮丼、烤魚應有盡有。可現場挑選海鮮、現烤現吃。這是鳥取必訪景點，也是海鮮愛好者天堂。免費參觀，建議預留2-3小時。可搭配水木茂之路、境台場一起遊覽。11-3月松葉蟹季最肥美。", "contact_name": null, "country_code": "JP", "english_name": "Sakaiminato Fish Market", "ticket_price": "依購買商品", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": {"daily": "07:00-16:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 90}, {"id": "c710d608-81ee-43e3-8d31-3ae5799d38c8", "fax": null, "name": "涉谷十字路口", "tags": null, "type": "attraction", "notes": null, "p