0"], "address": null, "city_id": "shanghai", "website": null, "category": "景點 / Attraction", "latitude": null, "is_active": true, "longitude": null, "region_id": null, "country_id": "china", "created_at": "2026-04-06T22:24:10.036847+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "景泰藍是中國傳統金屬工藝，以銅胎掐絲琺瑯技法聞名，在明代景泰年間達到頂峰，故名景泰藍。在上海的景泰藍工坊（北京工藝聯絡處），跟隨國家級非遺傳承人學習掐絲琺瑯技藝。使用紫銅片作底胎，用銅絲掐出圖案（花鳥、龍鳳、山水），點填各色琺瑯釉，經800度高溫燒製、打磨、鍍金，完成一件景泰藍首飾盒或花瓶。景泰藍以藍色為主調，色彩豐富，工藝繁複，是清代皇室御用工藝品。", "contact_name": null, "country_code": "CN", "english_name": "Beijing Cloisonné Enamel Crafting", "ticket_price": null, "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 0}, {"id": "cf57e7dc-99d4-4c42-b802-12712a498593", "fax": null, "name": "阿勇河泛舟", "tags": null, "type": "attraction", "notes": null, "phone": null, "images": null, "address": null, "city_id": "bali", "website": null, "category": "活動體驗 / Activity", "latitude": -8.4234, "is_active": true, "longitude": 115.2612, "region_id": null, "country_id": "indonesia", "created_at": "2026-01-23T22:33:57.932321+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "阿勇河泛舟，烏布最熱門的戶外活動。2小時泛舟，穿越熱帶雨林、瀑布、峽谷、稻田，景色壯觀。中等難度，適合初學者與家庭。沿途可看猴子、鳥類、石雕。需穿快乾衣物。", "contact_name": null, "country_code": "ID", "english_name": "Ayung River Rafting", "ticket_price": "免費或依業者而異", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 100, "opening_hours": {"daily": "08:00-17:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 180}, {"id": "cf7eb6b3-bd1d-43e5-becf-5527c165a826", "fax": null, "name": "倉敷帆布", "tags": ["帆布", "工藝品", "紀念品", "倉敷"], "type": "attraction", "notes": "倉敷特產的厚實帆布製品，耐用