: "d0865078-be6c-4f6f-875d-a05db53a30ba", "fax": null, "name": "京都西陣織和服腰帶編織", "tags": ["工藝體驗", "頂級體驗"], "type": "attraction", "notes": "頂級體驗 | 工藝體驗 | 價位: | 難度:None", "phone": null, "images": ["https://images.unsplash.com/photo-1544441892-794166f1e3be?w=800", "https://images.unsplash.com/photo-1583417319070-4a69db38a482?w=800"], "address": null, "city_id": "kyoto", "website": null, "category": "景點 / Attraction", "latitude": null, "is_active": true, "longitude": null, "region_id": "jp_kansai", "country_id": "japan", "created_at": "2026-04-06T22:24:08.452035+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "西陣織是京都最高級的織物工藝，有1200年歷史，專門製作和服腰帶（帯）與高級絲織品。在西陣地區的傳統機屋，跟隨西陣織工藝士學習使用傳統「高機」（立式織機）編織。體驗從整經、穿綜到織造的完整工序，使用金銀線、彩色絲線編織複雜的紋樣。西陣織以「綴織」「唐織」等技法聞名，一條高級腰帶需要數月時間完成。在此體驗中可織成小型作品如茶席墊或裝飾布。", "contact_name": null, "country_code": "JP", "english_name": "Kyoto Nishijin-ori Obi Weaving", "ticket_price": null, "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 0}, {"id": "d0957c8c-b4c7-4331-b440-737f19dc4f81", "fax": null, "name": "加路蘭海岸", "tags": null, "type": "attraction", "notes": null, "phone": null, "images": null, "address": "台東縣台東市富岡里加路蘭", "city_id": "02d6cb3c-b3d0-40c7-b283-d2d5f446ba1d", "website": null, "category": "景點 / Attraction", "latitude": 22.8108, "is_active": true, "longitude": 121.1933, "region_id": null, "country_id": "taiwan-country-001", "created_at": "2026-01-09T03:36:28.944514+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "台東加路蘭的海岸藝術區，漂流木裝置藝術散布在海岸。藝術家用漂流木創作，每件作品都獨特。這裡面對太平洋，視野遼闊，是欣賞海景、拍照的好地方。沒有過度開發，保持著原始的海岸風貌。", "contact_name": null, "country_code": "TW", "english_name": "Jialulan Coast", "ticket_price": "免費", "workspace_