be", "website": null, "category": "景點 / Attraction", "latitude": 34.7961, "is_active": true, "longitude": 135.2483, "region_id": "jp_kansai", "country_id": "japan", "created_at": "2026-01-23T00:38:02.904061+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "日本三大古湯之一，歷史超過1300年，豐臣秀吉曾多次造訪。擁有金泉與銀泉兩大名泉，療效卓著。溫泉街保留江戶風情，有足湯、溫泉饅頭、炭酸煎餅等特產。周邊有太閣之湯、金之湯、銀之湯等公共浴場與高級溫泉旅館，是神戶後花園與身心靈療癒聖地。", "contact_name": null, "country_code": "JP", "english_name": "Arima Onsen", "ticket_price": "公共湯屋650-1500日圓", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 5, "opening_hours": {"daily": "08:00-22:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 180}, {"id": "d2a5b8f4-6766-446d-8d26-8b3db7e64138", "fax": null, "name": "交子大道", "tags": ["網紅", "夜景", "燈光秀", "地標", "購物"], "type": "attraction", "notes": "天府雙塔LED燈光秀必看", "phone": null, "images": null, "address": "成都市高新區交子大道", "city_id": null, "website": null, "category": "購物 / Shopping", "latitude": 30.575, "is_active": true, "longitude": 104.065, "region_id": "cn_southwest", "country_id": "china", "created_at": "2025-12-05T14:47:40.549943+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "成都封面級景觀！全長1.7公里，背靠「天府雙塔」和「交子之環」。雙塔外立面有5.2萬㎡的LED屏幕，可呈現多元燈光秀。是成都時尚潮流、藝術文化活動最受歡迎的場地，經常舉辦消費節、藝術節、品牌路演等活動。", "contact_name": null, "country_code": "CN", "english_name": "Jiaozi Avenue", "ticket_price": "免費或依業者而異", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 32, "opening_hours": {"daily": "08:30-17:30"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 120}, {"id": "d2b07c92-438a-407f-bcca-a069b8f29b50", "fax": null, "name": "萬石植物園", "tags": null, "type": "attraction", "notes": null, "phone": null, "images": null, "address": nul