public/attractions/japan/d45b8081-5404-4884-8264-f4be72878d82-2.jpeg"], "address": null, "city_id": "ise", "website": null, "category": "購物 / Shopping", "latitude": 34.4569, "is_active": true, "longitude": 136.7239, "region_id": "jp_kansai", "country_id": "japan", "created_at": "2026-01-23T02:46:30.506084+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "伊勢托福橫丁，伊勢神宮內宮前的復古商店街，重現江戶時代伊勢參拜町風情。伊勢烏龍麵、赤福餅、松阪牛串燒、土產店林立。", "contact_name": null, "country_code": "JP", "english_name": "Okage Yokocho", "ticket_price": "免費或依業者而異", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 100, "opening_hours": {"daily": "10:00-18:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 90}, {"id": "d45d750c-47b9-40c4-8630-fd807f75b07b", "fax": null, "name": "古城區", "tags": ["古城", "護城河", "探索"], "type": "heritage", "notes": null, "phone": null, "images": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/thailand/d45d750c-47b9-40c4-8630-fd807f75b07b-1.jpeg", "https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/thailand/d45d750c-47b9-40c4-8630-fd807f75b07b-2.jpeg"], "address": null, "city_id": "chiang-mai", "website": null, "category": "歷史文化 / History & Culture", "latitude": 18.7811975, "is_active": true, "longitude": 98.9950328, "region_id": null, "country_id": "thailand", "created_at": "2025-12-06T01:24:38.751889+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "《古城區》以方形護城河為界,內部面積約1.5平方公里,保留了蘭納王朝時期的城市格局。主要道路呈棋盤狀分布,寺廟、咖啡館、民宿、餐廳與在地居民的房舍交錯共存。這裡沒有刻意的保存計畫,而是自然演化的結果——老房子被改建成咖啡館,新建築必須符合高度限制,現代與傳統在此找到平衡。租輛單車是最佳探索方式,隨意轉進小巷,也許會發現隱藏的咖啡館或工藝品店。古城區的魅力不在單一景點,而在整體氛圍——慢、舊、人性化。這是清邁的心臟,也是最容易迷路但最值得迷路的地方。", "contact_name": null, "country_code": "TH", "english_name": "Old City", "ticket_price": "免費或依業者而異", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": {"daily": "09:00-18:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": null}, {"id": "d468d217-7c46-4dca-a32a-1774dc45ed58", "fax": null, "name": "六榕寺", "tags": ["寺廟", "花塔", "佛教"], "type": "temple", "notes": "廣州最古老的佛教寺廟之一，建於南朝梁代。花塔是廣州地標，登塔可俯瞰老城區，蘇東坡曾題「六榕」二字。", "phone": null, "images": null, "address": null, "city_id": null, "website": null, "category": "歷史文化 / History & Culture", "latitude": 23.1311, "is_active": true, "longitude": 113.2614, "region_id": "cn_south", "country_id": "china", "created_at": "2025-12-06T07:04:26.238311+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "六榕寺，中國佛教或道教寺廟，展現中國傳統宗教建築藝術與文化。", "contact_name": null, "country_code": "CN", "english_name": "Temple of the Six Banyan Trees", "ticket_price": "成人10-30元", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 99, "opening_hours": {"daily": "08:00-17:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 60}, {"id": "d46b37ad-d755-4e33-b8c7-c7ab75b44f00", "fax": null, "name": "久保田一竹美術館", "tags": null, "type": "attraction", "notes": "河口湖畔展示辻が花染色藝術的美術館。高第風格的建築本身就是藝術品，庭園可眺望富士山。", "phone": null, "images": ["https://images.pexels.com/photos/69903/pexels-photo-69903.jpeg?auto=compress&cs=tinysrgb&h=650&w=940", "https://images.pexels.com/photos/20967/pexels-photo.jpg?auto=compress&cs=tinysrgb&h=650&w=940", "https://images.pexels.com/photos/2574476/pexels-photo-2574476.jpeg?auto=compress&cs=tinysrgb&h=650&w=940", "https://images.pexels.com/photos/1671016/pexels-photo-1671016.jpeg?auto=compress&cs=tinysrgb&h=650&w=940", "https://images.pexels.com/photos/1674049/pexels-photo-1674049.jpeg?auto=compress&cs=tinysrgb&h=650&w=940"], "address": null, "city_id": "hakone", "website": null, "c