y_id": null, "website": null, "category": "活動體驗 / Activity", "latitude": 12.568, "is_active": true, "longitude": 99.958, "region_id": "th_central", "country_id": "thailand", "created_at": "2026-03-17T03:14:01.620413+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "華欣 PlearnWan 復古村，仿 1950 年代泰國老街的文創園區。復古商店、咖啡廳、冰淇淋店、雜貨鋪，充滿懷舊氛圍。適合拍照、逛小店、吃甜點。這是華欣必訪景點，也是 IG 打卡熱門。免費參觀，建議預留 1-2 小時。可搭配 Cicada Market、華欣海灘一起遊覽。下午時光最愜意。", "contact_name": null, "country_code": "TH", "english_name": "Plearn Wan Vintage Village", "ticket_price": "免費入場", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": {"daily": "09:00-20:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 90}, {"id": "d634c4c1-d003-4b16-a179-b22dda84b39f", "fax": null, "name": "奈良公園", "tags": null, "type": "attraction", "notes": null, "phone": null, "images": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/japan/d634c4c1-d003-4b16-a179-b22dda84b39f-1.jpeg", "https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/japan/d634c4c1-d003-4b16-a179-b22dda84b39f-2.jpeg"], "address": null, "city_id": "nara", "website": null, "category": "景點 / Attraction", "latitude": 34.6851, "is_active": true, "longitude": 135.843, "region_id": "jp_kansai", "country_id": "japan", "created_at": "2026-01-23T00:38:02.450222+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "奈良公園，1200隻野生鹿自由漫步的公園。鹿被視為神的使者，可以餵食鹿仙貝。東大寺、春日大社、興福寺都在公園內。春天櫻花、秋天楓紅，四季皆美。鹿會鞠躬討食，但也會搶食，需小心。這是奈良最獨特的體驗，也是日本唯一鹿與人共存的地方。", "contact_name": null, "country_code": "JP", "english_name": "Nara Park", "ticket_price": "公園免費，東大寺600日圓", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 1, "opening_hours": {"d