icine Wellness 3 Days", "ticket_price": null, "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 0}, {"id": "d6a21d98-5ff0-49f2-99c0-6253114c7710", "fax": null, "name": "浦富海岸", "tags": ["海岸", "奇岩", "遊船", "國家公園"], "type": "attraction", "notes": "山陰海岸國家公園，奇岩怪石和清澈海水，遊覽船約40分鐘", "phone": null, "images": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/japan/d6a21d98-5ff0-49f2-99c0-6253114c7710-1.jpeg", "https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/japan/d6a21d98-5ff0-49f2-99c0-6253114c7710-2.jpeg"], "address": null, "city_id": null, "website": null, "category": "自然風景 / Nature", "latitude": 35.572, "is_active": true, "longitude": 134.338, "region_id": "jp_chugoku", "country_id": "japan", "created_at": "2026-03-17T03:16:16.356483+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "山陰海岸國家公園的一部分，奇岩怪石與清澈海水交織出壯麗景觀。搭乘遊覽船穿梭在岩石間，近距離欣賞海蝕洞、海蝕崖，感受大自然的雕刻藝術。海水透明度極高，是山陰地區最美的海岸線。", "contact_name": null, "country_code": "JP", "english_name": "Uradome Coast", "ticket_price": "遊覽船約1300日圓", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": {"daily": "09:00-17:00，遊覽船依季節調整"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 120}, {"id": "d6a88fd5-d45d-4317-bbb3-13ff942eb2bb", "fax": null, "name": "白燈塔", "tags": ["燈塔", "地標", "歷史"], "type": "attraction", "notes": null, "phone": null, "images": null, "address": null, "city_id": null, "website": null, "category": "歷史文化 / History & Culture", "latitude": 22.3495, "is_active": true, "longitude": 120.3715, "region_id": null, "country_id": "taiwan-country-001", "created_at": "2026-03-17T03:12:44.571464+00:00", "created_by": null, "deleted_at": null, "deleted_by": n