inutes": 90}, {"id": "db8b3a20-3305-4017-82e2-80677cc2ac8e", "fax": null, "name": "悟孟寺", "tags": ["隧道寺廟", "森林", "禪修"], "type": "temple", "notes": "清邁郊外的森林寺廟，建於14世紀的獨特磚造隧道通往佛像。幽靜的氛圍適合冥想，是當地人喜愛的靜修之地。", "phone": null, "images": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/thailand/db8b3a20-3305-4017-82e2-80677cc2ac8e-1.jpeg", "https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/thailand/db8b3a20-3305-4017-82e2-80677cc2ac8e-2.jpeg"], "address": null, "city_id": "chiang-mai", "website": null, "category": "歷史文化 / History & Culture", "latitude": 18.7939, "is_active": true, "longitude": 98.9461, "region_id": null, "country_id": "thailand", "created_at": "2025-12-16T06:49:14.126554+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "《悟孟寺》Wat Umong 藏身於素帖山腳的森林深處,以地下隧道系統區別於其他金碧輝煌的泰北寺院。昏暗的拱形磚道內,佛像在燭光中靜默,空氣潮濕而涼爽。走出隧道,是一片荒蕪感十足的寺院腹地——斷裂的佛塔被樹根纏繞,野生鹿群在草地遊蕩,湖畔佈滿青苔與落葉。這裡沒有觀光寺廟的熱鬧與規整,反而保留了某種被時間遺忘的靜謐。修行者在此禪坐,旅人在林間漫步,所有人都在這片非典型的宗教空間中,尋找與自己獨處的可能。這是清邁最特別的寺廟——不追求華麗,只追求內心的安靜。", "contact_name": null, "country_code": "TH", "english_name": "Wat Umong", "ticket_price": "成人100-200泰銖", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 506, "opening_hours": {"daily": "08:00-17:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 60}, {"id": "db8e2213-52b2-4106-a526-8f4ef9828026", "fax": null, "name": "福岡市美術館", "tags": null, "type": "attraction", "notes": null, "phone": null, "images": null, "address": null, "city_id": null, "website": null, "category": "景點 / Attraction", "latitude": null, "is_active": true, "longitude": null, "region_id": null, "country_id": "japan", "created_at": "2026-04-09T01:28:10.455781+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": null, "contact_name": null, "country_code": "JP", "english_name": null, "ticket_price": null, "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "google_maps_url": null, "duration_minutes": null}, {"id": "dba07eba-ab61-43cd-bb84-627d7bb5a51a", "fax": null, "name": "河內摩托車維修師傅體驗", "tags": ["在地深度", "頂級體驗"], "type": "attraction", "notes": "頂級體驗 | 在地深度 | 價位: | 難度:None", "phone": null, "images": ["https://images.unsplash.com/photo-1582655299221-2e0fd73faa37?w=800", "https://images.unsplash.com/photo-1559827260-dc66d52bef19?w=800"], "address": null, "city_id": "hanoi", "website": null, "category": "景點 / Attraction", "latitude": null, "is_active": true, "longitude": null, "region_id": null, "country_id": "vietnam", "created_at": "2026-04-06T22:24:12.773289+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "河內有800萬輛摩托車，摩托車維修師傅是這座城市的重要角色。跟隨路邊維修攤的老師傅，學習基本的摩托車維修技巧：換輪胎、調整煞車、更換機油、修補爆胎。了解越南獨特的摩托車文化：為何一家四口能騎一台車、如何在摩托車上載冰箱、雨季的騎車技巧。午餐與師傅在路邊攤吃河粉，聊天喝越南咖啡。下午騎著修好的摩托車環城（師傅陪同），探訪維修師傅的私房景點：老城區的窄巷、還劍湖的日落、隱藏的咖啡館。體驗河內最真實的街頭生活。", "contact_name": null, "country_code": "VN", "english_name": "Hanoi Motorbike Mechanic Experience", "ticket_price": null, "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 0}, {"id": "dbde5389-0ec0-44d7-a522-71a08b82b469", "fax": null, "name": "烏奇沙城堡", "tags": ["城堡", "岩石", "觀景", "日落", "卡帕多奇亞"], "type": "heritage", "notes": "60公尺高的巨大岩石城堡，是古代的避難所和瞭望台。可攀登到頂端俯瞰卡帕多奇亞全景。日落時分景色最美。是經典明信片場景。\n\n旅遊提示：日落時分來看風景最美", "phone": null, "images": null, "address": null, "city_id": null, "website": null, "category": "歷史文化 / History & Culture", "latitude": 38.6304425, "is_active": true, "longitude": 34.805323, "region_id": "tr_cappadocia", "country_id": "turkey", "creat