ull, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "《會安古鎮單車遊》是探索周邊鄉村最好的方式。騎過稻田、菜園、水牛、鴨群，經過傳統村落與手工藝工坊。導遊會帶你去觀光客不知道的地方——在地人的市場、河邊的釣魚人、農家的菜園。中途停靠農家品嚐越南茶與點心，與村民聊天。這不是刻意包裝的鄉村體驗，而是真實的日常生活。半天行程約台幣600-800元，包含單車、導遊、點心。會安的魅力不只在古鎮，也在周邊的鄉村寧靜。", "contact_name": null, "country_code": "VN", "english_name": "Hoi An Bicycle Tour", "ticket_price": null, "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "google_maps_url": null, "duration_minutes": null}, {"id": "e3caef1f-78d4-4560-a67d-af03abf5a46c", "fax": null, "name": "成田山新勝寺", "tags": ["寺廟", "歷史", "鰻魚", "初詣"], "type": "attraction", "notes": null, "phone": null, "images": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/japan/e3caef1f-78d4-4560-a67d-af03abf5a46c-1.jpeg", "https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/japan/e3caef1f-78d4-4560-a67d-af03abf5a46c-2.jpeg"], "address": null, "city_id": "tokyo", "website": null, "category": "歷史文化 / History & Culture", "latitude": 35.7863311, "is_active": true, "longitude": 140.3172238, "region_id": "jp_kanto", "country_id": "japan", "created_at": "2025-10-28T06:41:25.804661+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "成田山新勝寺，日本佛教寺院，展現日本傳統寺廟建築與庭園造景之美。", "contact_name": null, "country_code": "JP", "english_name": "Naritasan Shinshoji Temple", "ticket_price": "免費或300-500日圓", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 2, "opening_hours": {"daily": "06:00-17:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 120}, {"id": "e3fde5e5-0f6d-4619-a1f8-b68783df5984", "fax": null, "name": "雍和宮", "tags": null, "type": "temple", "notes": "北京最大的藏傳佛教寺院，原為雍正皇帝府邸。萬福閣內18米高的白檀木彌勒佛像是鎮寺之寶。", "phone": null, "images": null, "address":