ry": "活動體驗 / Activity", "latitude": null, "is_active": true, "longitude": null, "region_id": null, "country_id": "vietnam", "created_at": "2026-04-04T11:24:19.047+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "《峴港衝浪》在美溪沙灘,浪況適合初學者。衝浪學校提供教練、衝浪板、防寒衣,兩小時課程約台幣800-1,200元。越南中部海岸是東南亞少數適合衝浪的地點,峴港正在發展衝浪文化。這是體驗峴港海洋活力的方式——不只曬太陽,還要與海浪搏鬥。", "contact_name": null, "country_code": "VN", "english_name": "Da Nang Surfing", "ticket_price": null, "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "google_maps_url": null, "duration_minutes": null}, {"id": "e83e0e94-9460-45be-a9f8-8aec9b1bc6be", "fax": null, "name": "韓國寺廟寄宿Templestay三日", "tags": ["養生靜修", "頂級體驗"], "type": "attraction", "notes": "頂級體驗 | 養生靜修 | 價位: | 難度:None", "phone": null, "images": ["https://images.unsplash.com/photo-1517154421773-0529f29ea451?w=800", "https://images.unsplash.com/photo-1545569341-9eb8b30979d9?w=800"], "address": null, "city_id": "seoul", "website": null, "category": "景點 / Attraction", "latitude": null, "is_active": true, "longitude": null, "region_id": null, "country_id": "korea", "created_at": "2026-04-06T22:24:13.43045+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "在首爾近郊的千年古剎，體驗三日兩夜的韓國寺廟寄宿（Templestay）。這是韓國政府推廣的文化體驗項目，讓現代人暫離塵囂，體驗僧侶生活。清晨3:30起床參加晨鐘儀式與早課，聆聽108響鐘聲淨化心靈。學習108拜（禮佛）、抄經（寫佛經）、茶道（禪茶一味）。參與寺廟工作：打掃、種菜、準備齋飯。與住持進行一對一對話，討論人生煩惱與佛法智慧。晚上山中夜行禪，觀星冥想。享用寺廟素食（精緻的韓式寺剎料理）。這是身心靈全面放鬆與充電的旅程。", "contact_name": null, "country_code": "KR", "english_name": "Korean Temple Stay 3 Days", "ticket_price": null, "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 0}, {"id": "e865d237-2b41-4bab-a230-7b26d84774a3", "fax": null, "name": "麥加大清真寺", "tags": ["清真寺", "麥加", "聖地", "朝覲"], "type": "temple", "notes": "伊斯蘭最神聖的清真寺，環繞著天房卡巴。僅限穆斯林進入麥加。全球穆斯林朝聖目的地。", "phone": null, "images": null, "address": null, "city_id": null, "website": null, "category": "歷史文化 / History & Culture", "latitude": 21.4225, "is_active": true, "longitude": 39.8262, "region_id": null, "country_id": "saudi_arabia", "created_at": "2025-12-06T01:24:46.760214+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "沙烏地阿拉伯麥加，伊斯蘭教第一聖地。克爾白天房是穆斯林朝拜方向，每年數百萬穆斯林來此朝聖。非穆斯林禁止進入麥加。", "contact_name": null, "country_code": "SA", "english_name": "Masjid al-Haram", "ticket_price": "免費（非穆斯林可能限制）", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": {"daily": "09:00-17:00（祈禱時間不開放）"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 180}, {"id": "e8a31da6-7ea3-4b2d-99bf-0be726862e5e", "fax": null, "name": "大阪造幣局", "tags": ["櫻花", "春季", "造幣"], "type": "attraction", "notes": null, "phone": null, "images": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/japan/e8a31da6-7ea3-4b2d-99bf-0be726862e5e-1.jpeg", "https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/japan/e8a31da6-7ea3-4b2d-99bf-0be726862e5e-2.jpeg"], "address": null, "city_id": "osaka", "website": null, "category": "活動體驗 / Activity", "latitude": 34.6953499, "is_active": true, "longitude": 135.5210225, "region_id": "jp_kansai", "country_id": "japan", "created_at": "2025-12-06T06:57:31.523206+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "日本貨幣鑄造機構，每年春季限定開放「櫻花通道」，全長約560公尺，種植約340株珍稀櫻花品種，包括關山櫻、松月櫻、紅手毬等，花期比一般染井吉野晚。夜間點燈夢幻浪漫，是大阪賞櫻秘境。博物館展示歷代貨幣、勳章製作工藝，免費參觀。是春季限定的大阪必訪櫻花景點。", "contact_name": null, "country_code": "JP", "english_name": "Japan Mint", "ticket_price": "免費（櫻花季限定開放）", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 46, "opening_hours": {"daily": "櫻花季09:00-21:00，約一週"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": null}, {"id": "e8bcf34c-947d-4e11-8367-c1c82ec95485", "fax": null, "name": "烏布SPA", "tags": ["SPA", "按摩", "放鬆", "養生", "必體驗"], "type": "experience", "notes": "峇里島以SPA聞名，烏布尤其有許多高品質SPA中心。傳統峇里式按摩結合花瓣浴、磨砂、精油。價格相對便宜，是峇里島必做體驗。\n\n旅遊提示：推薦Karsa Spa或Ubud Traditional Spa", "phone": null, "images": null, "address": null, "city_id": "bali", "website": null, "category": "自然風景 / Nature", "latitude": -8.5069, "is_active": true, "longitude": 115.2624, "region_id": null, "country_id": "indonesia", "created_at": "2025-12-06T02:06:56.263234+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "烏布SPA位於印尼，擁有壯麗自然景觀與熱帶風情。原始生態、獨特地貌適合喜愛大自然的旅人探索。無論徒步健行、觀景攝影或生態觀察，都能感受印尼自然之美的震撼與寧靜。", "contact_name": null, "country_code": "ID", "english_name": null, "ticket_price": "約Rp 50,000-200,000", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 525, "opening_hours": {"daily": "08:00-17:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 120}, {"id": "e91121c7-e179-4206-9a60-c701832f948e", "fax": null, "name": "清邁僧侶托缽與寺廟生活", "tags": ["在地深度", "頂級體驗"], "type": "attraction", "notes": "頂級體驗 | 在地深度 | 價位: | 難度:None", "phone": null, "images": ["https://images.unsplash.com/photo-1552465011-b4e21bf6e79a?w=800", "https://images.unsplash.com/photo-1563492065599-3520f775eeed?w=800"], "address": null, "city_id": "chiang-mai", "website": null, "category": "景點 / Attraction", "latitude": null, "is_active": true, "longitude": null, "region_id": null, "country_id": "thailand", "created_at": "2026-04-06T22:24:12.350263+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "體驗泰北僧侶的一日生活，深入了解上座部佛教文化。清晨5點跟隨僧侶進行托缽（Alms Round），赤腳行走於清邁古城，接受信眾供養的食物。返回寺廟後參與早課誦經，學習巴利文經文的基本唸法。早餐享用信眾供養的素食（過午不食，僧侶只吃早餐）。上午學習坐禪與行禪，由資深僧侶指導正念呼吸法。午餐後參與寺廟日常工作：打掃、整理經書。下午茶時間與僧侶對話（Monk Chat），詢問佛法與人生問題。這是深度理解泰國佛教文化的難得機會。", "contact_name": null, "country_code": "TH", "english_name": "Chiang Mai Monk Alms Round & Temple Life", "ticket_price": null, "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 0}, {"id": "e959607e-823d-4815-acab-92a897285292", "fax": null, "name": "梨花女子大學", "tags": ["大學", "建築", "拍照", "購物街", "梨大"], "type": "attraction", "notes": "校園本身就是景點，ECC 地下建築與梨花牆是必拍場景。", "phone": null, "images": null, "address": null, "city_id": "seoul", "website": null, "category": "地標建築 / Landmark", "latitude": 37.5618, "is_active": true, "longitude": 126.9467, "region_id": null, "country_id": "korea", "created_at": "2025-12-06T01:24:33.467025+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "1886年創校的韓國第一所女子大學，校園建築兼具歐式與現代風格。「ECC」地下校園是建築大師Dominique Perrault設計，如同峽谷般壯觀。是韓劇取景勝地。", "contact_name": null, "country_code": "KR", "english_name": "Ewha Womans University", "ticket_price": "免費或依業者而異", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": {"daily": "10:00-20:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 60}, {"id": "e985d11e-bdf4-4f2b-980c-1504db302ecb", "fax": null, "name": "海遊館", "tags": null, "type": "attraction", "notes": null, "phone": null, "images": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/japan/e985d11e-bdf4-4f2b-980c-1504db302ecb-1.jpeg", "https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/japan/e985d11e-bdf4-4f2b-980c-1504db302ecb-2.jpeg"], "address": null, "city_id": "osaka", "website": null, "category": "景點 / Attraction", "latitude": 34.6545, "is_active": true, "longitude": 135.429, "region_id": "jp_kansai", "country_id": "japan", "created_at": "2026-01-23T00:37:05.675061+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "世界最大級水族館之一，以環太平洋火山帶為主題，8層樓巨型水槽展示鯨鯊、魟魚、海豚等海洋生物。中央大水槽「太平洋」可360度觀賞鯨鯊悠游，企鵝區、水獺、海豹等療癒系動物深受喜愛。館內設有觸摸池、夜間特別參觀活動。鄰近天保山摩天輪與市場街，是大阪港必訪景點。", "contact_name": null, "country_code": "JP", "english_name": "Osaka Aquarium Kaiyukan", "ticket_price": "成人2700日圓", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 9, "opening_hours": {"daily": "10:00-20:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 150}, {"id": "ea196e6d-8dfc-4692-a364-30cfda983a9f", "fax": null, "name": "六本木之丘", "tags": null, "type": "landmark", "notes": "東京城中城，森美術館展覽精彩，展望台夜景與東京鐵塔相映。", "phone": null, "images": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/japan/ea196e6d-8dfc-4692-a364-30cfda983a9f-1.jpeg", "https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/japan/ea196e6d-8dfc-4692-a364-30cfda983a9f-2.jpeg"], "address": null, "city_id": "tokyo", "website": null, "category": "歷史文化 / History & Culture", "latitude": 35.6605, "is_active": true, "longitude": 139.7292, "region_id": "jp_kanto", "country_id": "japan", "created_at": "2025-12-06T01:24:21.076679+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "六本木Hills，六本木大型複合設施，2003年開幕。森大樓、展望台、森美術館、電影院、GrandHyatt酒店、購物中心、餐廳應有盡有。52樓展望台TokyoCityView可360度俯瞰東京，東京鐵塔、晴空塔盡收眼底。這是六本木地標，也是東京必訪景點。展望台", "contact_name": null, "country_code": "JP", "english_name": "Roppongi Hills", "ticket_price": "免費或依業者而異", "workspac