_maps_url": null, "duration_minutes": null}, {"id": "f0404986-2427-46e5-9dec-05af99ae54d9", "fax": null, "name": "湄南河長尾船", "tags": ["傳統交通", "運河探索", "在地生活"], "type": "experience", "notes": null, "phone": null, "images": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/thailand/f0404986-2427-46e5-9dec-05af99ae54d9-1.jpeg", "https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/thailand/f0404986-2427-46e5-9dec-05af99ae54d9-2.jpeg"], "address": null, "city_id": "bangkok", "website": null, "category": "自然風景 / Nature", "latitude": 13.7563, "is_active": true, "longitude": 100.5018, "region_id": null, "country_id": "thailand", "created_at": "2025-12-06T01:49:11.063551+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "《湄南河長尾船》引擎的轟鳴聲撕裂河面的寧靜,船尾的長軸在水中劃出白色軌跡。這種傳統的泰式木船原本是運河區居民的交通工具,如今成為觀光客體驗曼谷水路系統的載具。船夫站在船尾操控方向,穿過狹窄的運河,兩側是高腳屋與寺廟,偶爾有蜥蜴從岸邊滑入水中。速度很快,風很大,河水的腥味混合著引擎油的氣味。這不是浪漫的遊船體驗,而是貼近曼谷真實生活肌理的方式:粗糙、直接、充滿生命力。這是水上城市的脈搏,也是工業化前的交通記憶。", "contact_name": null, "country_code": "TH", "english_name": "Longtail Boat Tour", "ticket_price": "免費或依業者而異", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": {"daily": "09:00-18:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": null}, {"id": "f04a21aa-5455-4682-8b0b-33c8cfb0f2ef", "fax": null, "name": "青森縣立美術館", "tags": null, "type": "attraction", "notes": null, "phone": null, "images": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/japan/f04a21aa-5455-4682-8b0b-33c8cfb0f2ef-1.jpeg", "https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/japan/f04a21aa-5455-4682-8b0b-33c8cfb0f2ef-2.jpg"], "address": null, "city_id": "aomori", "website": null, "category": "景點 / Attraction", "latitude": 40.8267, "is_active": true, "longitude": 140.7067, "region_id": "jp_