es": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/thailand/f07ea40f-7210-4213-83e0-8f4da5f7612d-1.jpeg", "https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/thailand/f07ea40f-7210-4213-83e0-8f4da5f7612d-2.jpeg"], "address": null, "city_id": "chiang-mai", "website": null, "category": "購物 / Shopping", "latitude": 18.7883, "is_active": true, "longitude": 98.9867, "region_id": null, "country_id": "thailand", "created_at": "2025-12-16T06:49:15.57543+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "《真心市集》JingJai Market 是清邁大學附近的文創市集,每週三到日下午開市。攤位以年輕創作者為主,販售手工飾品、插畫、獨立出版品、二手古著。這裡的氛圍比週末夜市更藝術、更小眾,價格也偏高但品質穩定。木製攤位整齊排列,燈串營造溫馨氛圍,背景音樂是Indie樂團的現場演出。小吃攤供應有機沙拉、手沖咖啡、純素甜點,迎合年輕世代的飲食偏好。這裡不是觀光客市集,而是清邁年輕創作者的展示平台。適合想了解清邁當代文化的人,但如果只想買紀念品,週末夜市更合適。", "contact_name": null, "country_code": "TH", "english_name": "JingJai Market", "ticket_price": "免費或依業者而異", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 532, "opening_hours": {"daily": "09:00-18:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 90}, {"id": "f081c3b9-1fb9-4017-bf93-64fd81a2af9d", "fax": null, "name": "評彈表演", "tags": null, "type": "experience", "notes": "蘇州評彈是江南傳統曲藝，在茶館可邊品茶邊欣賞，表演約1小時", "phone": null, "images": null, "address": null, "city_id": null, "website": null, "category": "活動體驗 / Activity", "latitude": 31.23, "is_active": true, "longitude": 121.47, "region_id": "cn_east", "country_id": "china", "created_at": "2025-12-06T01:49:15.222606+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "評彈表演，中國知名景點，值得探訪。", "contact_name": null, "country_code": "CN", "english_name": "Pingtan Performance", "ticket_price": "免費或依業者而異", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": {"daily": "08:30-17:30"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": null}, {"id": "f08d4e7c-d48c-4cd5-bc9b-2e8f193ced49", "fax": null, "name": "帕蓬夜市", "tags": ["夜市", "觀光", "爭議"], "type": "market", "notes": null, "phone": null, "images": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/thailand/f08d4e7c-d48c-4cd5-bc9b-2e8f193ced49-1.jpeg", "https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/thailand/f08d4e7c-d48c-4cd5-bc9b-2e8f193ced49-2.jpeg"], "address": null, "city_id": "bangkok", "website": null, "category": "購物 / Shopping", "latitude": 13.7286838, "is_active": true, "longitude": 100.5318283, "region_id": null, "country_id": "thailand", "created_at": "2025-12-06T01:24:38.405289+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "《帕蓬夜市》夾在成人娛樂街區之間,形成奇特的並置關係。攤位販售大量仿冒品與旅遊紀念品,品質參差且需要議價技巧。這裡的氛圍介於觀光陷阱與在地商業之間,夜晚人潮擁擠但缺乏特殊性。若非住宿地點鄰近,實無必要特意前往。周邊的巷弄文化與夜市本身形成強烈對比,反倒成為更值得觀察的都市現象。不是推薦景點,更像是曼谷多層次樣貌的一個切面——商業、情色、觀光在此交錯,呈現某種粗糙但真實的城市肌理。", "contact_name": null, "country_code": "TH", "english_name": "Patpong Night Market", "ticket_price": "免費或依業者而異", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": {"daily": "18:00-23:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": null}, {"id": "f11aebf7-32a1-4597-8e51-6b8a693cd6f6", "fax": null, "name": "氣多大社", "tags": null, "type": "attraction", "notes": null, "phone": null, "images": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/japan/f11aebf7-32a1-4597-8e51-6b8a693cd6f6-1.jpeg", "https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/japan/f11aebf7-32a1-4597-8e51-6b8a693cd6f6-2.jpeg"], "address": null, "city_id": "kanazawa", "website": null, "category": "歷史文化 / History & Culture", "latitude": 36.8978, "is_active": true, "longitude": 136.7711, "region_id": "jp_chubu", "country_id": "japan", "created_at": "2025-12-05T04:43:38.729781+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "石川縣氣多大社，能登半島最重要的神社，2,000年歷史。緣結之神、入らずの森、茅葺屋頂本殿。免費參觀，每月", "contact_name": null, "country_code": "JP", "english_name": "Keta Taisha", "ticket_price": "免費或依業者而異", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": {"daily": "10:00-18:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": null}, {"id": "f1252a9f-0692-4533-b86c-03c78d3382ab", "fax": null, "name": "湄公河三角洲一日遊", "tags": ["湄公河", "水道", "一日遊"], "type": "attraction", "notes": null, "phone": null, "images": null, "address": null, "city_id": "ho-chi-minh", "website": null, "category": "活動體驗 / Activity", "latitude": null, "is_active": true, "longitude": null, "region_id": null, "country_id": "vietnam", "created_at": "2026-04-04T11:19:45.848+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "《湄公河三角洲一日遊》從胡志明出發,搭車約兩小時抵達美托(My Tho)。換乘小船穿梭水道,兩岸是椰林、果園與水上人家。停靠蜜蜂農場品嚐蜂蜜茶、參觀椰子糖工坊、在水上餐廳吃象耳魚。最精彩的是搭手搖小船穿越狹窄水道,陽光穿過椰葉灑在水面,安靜到只聽見槳聲與鳥鳴。這不是原始風光,而是人與水共生的文化景觀——湄公河養活數百萬人,也塑造了越南南部的生活方式。", "contact_name": null, "country_code": "VN", "english_name": "Mekong Delta Day Trip", "ticket_price": null, "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "google_maps_url": null, "duration_minutes": null}, {"id": "f13d07c1-838b-4d2b-8aba-8cffd7b10156", "fax": null, "name": "拜訂寺", "tags": ["佛教", "寺廟", "大型園區", "朝聖"], "type": "attraction", "notes": "園區廣闊，建議搭乘電瓶車。需尊重宗教禮儀，穿著端莊。", "phone": null, "images": null, "address": null, "city_id": null, "website": null, "category": "歷史文化 / History & Culture", "latitude": 20.26, "is_active": true, "longitude": 105.95, "region_id": null, "country_id": "vietnam", "created_at": "2026-03-17T08:15:51.600585+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "寧平拜訂寺，東南亞最大的佛教寺廟群，佔地700公頃。500尊羅漢石像、金碧輝煌的大雄寶殿、高10公尺的青銅鐘、巨大的臥佛像，規模宏大。電瓶車往返山門與主殿，步行需爬階梯。這是越南最重要的佛教聖地之一，也是寧平必訪景點。", "contact_name": null, "country_code": "VN", "english_name": null, "ticket_price": "免費（電瓶車30,000越南盾）", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": {"notes": "佛教節日與週末特別擁擠", "regular": {"open": "06:00", "close": "18:00"}}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 150}, {"id": "f172b72a-e49c-456c-986f-93f00bff0983", "fax": null, "name": "婆羅浮屠日出", "tags": ["日出", "世界遺產", "攝影", "震撼", "必體驗"], "type": "experience", "notes": "從婆羅浮屠寺廟頂層觀賞日出是終生難忘的體驗。金色陽光穿透晨霧，照亮千年石刻。需購買特別的日出票，價格較貴但值得。\n\n旅遊提示：穿保暖衣物，清晨很冷", "phone": null, "images": null, "address": null, "city_id": "yogyakarta", "website": null, "category": "歷史文化 / History & Culture", "latitude": -7.6079, "is_active": true, "longitude": 110.2038, "region_id": null, "country_id": "indonesia", "created_at": "2025-12-06T02:06:59.989545+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "婆羅浮屠日出，世界文化遺產婆羅浮屠的日出行程。凌晨4點入園，攀登9層佛塔，等待日出。陽光穿透薄霧，照亮佛塔與默拉皮火山，景色震撼。需早起，但絕對值得。", "contact_name": null, "country_code": "ID", "english_name": null, "ticket_price": "約Rp 50,000-200,000", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 579, "opening_hours": {"daily": "08:00-17:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 180}, {"id": "f18a2fa3-04e7-4fa4-bc6c-c4be5adc523a", "fax": null, "name": "入鹿拉麵", "tags": ["米其林", "必比登", "拉麵"], "type": "food