2+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "首爾梨花壁畫村，駱山公園山坡上的老社區，70多幅壁畫點綴巷弄。錦鯉階梯、天使翅膀、花朵牆成IG打卡熱點。藝術家進駐計劃活化老社區，穿梭蜿蜒小巷驚喜連連，可眺望首爾全景。這是首爾必訪景點，也是文青天堂。免費參觀，建議預留2-3小時。可搭配東大門、惠化站一起遊覽。需爬坡，穿好走的鞋。", "contact_name": null, "country_code": "KR", "english_name": "Ihwa Mural Village", "ticket_price": "免費或依業者而異", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 7, "opening_hours": {"daily": "10:00-20:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 150}, {"id": "f3a4e74d-bf20-4a97-a876-cf1b2db628ca", "fax": null, "name": "清邁柚木雕刻工藝體驗", "tags": ["工藝體驗", "頂級體驗"], "type": "attraction", "notes": "頂級體驗 | 工藝體驗 | 價位: | 難度:None", "phone": null, "images": ["https://images.unsplash.com/photo-1452860606245-08befc0ff44b?w=800", "https://images.unsplash.com/photo-1513519245088-0e12902e35ca?w=800"], "address": null, "city_id": "chiang-mai", "website": null, "category": "景點 / Attraction", "latitude": null, "is_active": true, "longitude": null, "region_id": null, "country_id": "thailand", "created_at": "2026-04-06T22:24:09.083102+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "泰北柚木雕刻是蘭納王朝流傳下來的傳統工藝，以精細的花卉與佛教圖案聞名。在清邁郊外的木雕村，跟隨泰國文化部認證的木雕大師學習傳統柚木雕刻。使用百年泰北柚木，學習使用傳統雕刻刀具，雕刻蘭納風格的花窗、動物或佛教符號。柚木質地堅硬、色澤金黃，是製作寺廟建築與高級家具的頂級木材。完成作品可以是小型擺飾、相框或首飾盒。", "contact_name": null, "country_code": "TH", "english_name": "Chiang Mai Teak Wood Carving", "ticket_price": null, "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 0}, {"id": "f3c251a3-ee04-492f-9843-6da6eb37e449", "fax": null, "name": "首里城", "tags": ["世界遺產", "城堡", "歷史", "沖繩"], "type": "heritage", "notes": "琉球王國的象徵，2019 年火災後正在重建，展現琉球獨特的赤紅建築之美。", "