aceb93744?w=800", "https://images.unsplash.com/photo-1548013146-72479768bada?w=800"], "address": null, "city_id": "shanghai", "website": null, "category": "景點 / Attraction", "latitude": null, "is_active": true, "longitude": null, "region_id": null, "country_id": "china", "created_at": "2026-04-06T22:24:11.601657+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "探索電影《阿凡達》取景地張家界的震撼美景，專屬VIP通道避開人潮。清晨搭乘VIP包廂纜車直達天子山，由專業攝影師帶領尋找最佳拍攝角度。徒步金鞭溪峽谷，欣賞3000多座石英砂岩峰林。午餐享用土家族特色料理。下午挑戰天門山玻璃棧道與玻璃橋（世界最高最長），體驗懸崖邊的心跳感。乘坐天門洞纜車（全球最長高山客運索道），穿越999級天梯。晚上入住張家界最奢華度假村，享受山景溫泉與湘菜盛宴。", "contact_name": null, "country_code": "CN", "english_name": "Zhangjiajie Avatar Mountains Private Expedition", "ticket_price": null, "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": null, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 0}, {"id": "f8b68f9e-b059-4fb7-ae77-b03f022d3f94", "fax": null, "name": "梵天寺", "tags": null, "type": "temple", "notes": null, "phone": null, "images": null, "address": null, "city_id": null, "website": null, "category": "歷史文化 / History & Culture", "latitude": 30.2200264, "is_active": true, "longitude": 120.1625681, "region_id": null, "country_id": "china", "created_at": "2025-12-06T01:13:30.536266+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "梵天寺，中國佛教或道教寺廟，展現中國傳統宗教建築藝術與文化。", "contact_name": null, "country_code": "CN", "english_name": "Fantian Temple", "ticket_price": "成人10-30元", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": {"daily": "08:00-17:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": null}, {"id": "f8fbe506-b2b9-43c9-9b27-384f4fc75cf1", "fax": null, "name": "先斗町", "tags": ["京料理", "夜生活", "餐