-15T21:18:09.793607+00:00", "updated_by": null, "description": "香港中環的現代中菜餐廳Madame Fù，以創意手法重新詮釋粵菜經典。蟹粉小籠包、黑松露燒賣、花雕醉雞,傳統風味搭配精緻擺盤。餐廳設計融合Art Deco與東方元素，奢華而不失雅致。主廚團隊曾在米其林餐廳歷練，呈現高水準中菜。價格偏高，人均約600-800港幣。", "contact_name": null, "country_code": "CN", "english_name": "Madame Fu Grand Cafe Chinois", "ticket_price": "午市套餐約400-500港幣/人，晚市人均600-800港幣", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 954, "opening_hours": {"daily": "午餐12:00-14:30，晚餐18:00-22:30"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 150}, {"id": "f98e6d15-5da8-45ae-94be-3cf7571cc9fa", "fax": null, "name": "外灘下午茶", "tags": null, "type": "food", "notes": "上海最具代表性的景觀，黃浦江畔的萬國建築博覽群。隔江眺望陸家嘴三件套，夜景璀璨是上海的經典明信片。", "phone": null, "images": null, "address": null, "city_id": null, "website": null, "category": "景點 / Attraction", "latitude": 31.24, "is_active": true, "longitude": 121.49, "region_id": "cn_east", "country_id": "china", "created_at": "2025-12-06T01:49:14.288815+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "外灘下午茶，上海外灘老建築改建的奢華酒店下午茶。和平飯店、外灘華爾道夫、半島酒店、浦華大酒店都有提供。英式三層架、司康、馬卡龍、精緻甜點，搭配黃浦江景觀。感受老上海風華。", "contact_name": null, "country_code": "CN", "english_name": "Bund Afternoon Tea", "ticket_price": "免費或依業者而異", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": {"daily": "08:30-17:30"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 90}, {"id": "f9d2bcfc-45b0-45af-af70-0f0b6de0066d", "fax": null, "name": "拙政園", "tags": null, "type": "garden", "notes": null, "phone": null, "images": null, "address": null, "city_id": null, "website": null, "category": "景點 / Attraction", "latitude": 31.3237, "is_active": true, "longitude": 120.6341, "region_id": "cn_east", "country_id": "china", "created_at": "2025-12-06T01:24:49.949751+00:00", "created_by": null, "deleted_a