00:00", "updated_by": null, "description": "宿霧烤乳豬，宿霧代表美食，整隻乳豬炭烤至皮脆肉嫩，配酸辣醬。Rico's Lechon、Zubuchon、CNT Lechon 都是名店。這是宿霧必吃美食，也是CNN評選的世界最好吃烤乳豬。一公斤約1,500-2,500披索。可搭配宿霧市區景點一起遊覽。外帶或內用都可。皮脆、肉香、汁多。", "contact_name": null, "country_code": "PH", "english_name": null, "ticket_price": "免費或依業者而異", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 580, "opening_hours": {"daily": "08:00-18:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 480}, {"id": "fb03d7c1-0147-4da4-b67b-8c83bb72d472", "fax": null, "name": "濱海灣金沙", "tags": ["地標", "賭場", "購物", "空中花園", "新加坡"], "type": "landmark", "notes": "新加坡最著名地標，三棟大樓頂端連接的船型空中花園（Skypark）可俯瞰全市。有賭場、購物中心、博物館。無邊際泳池僅供住客使用。\n\n旅遊提示：觀景台和泳池是分開的，觀景台可購票", "phone": null, "images": null, "address": null, "city_id": null, "website": null, "category": "景點 / Attraction", "latitude": 1.2839, "is_active": true, "longitude": 103.861, "region_id": null, "country_id": "singapore", "created_at": "2025-12-06T02:06:35.843311+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "新加坡金沙酒店，地標性建築。57層樓高的三座塔樓，頂端是空中花園SkyPark，彷彿巨船橫架。屋頂無邊際泳池僅住客可用，是新加坡最夢幻的游泳池。觀景台對外開放，可俯瞰濱海灣全景。酒店內有賭場、購物中心、米其林餐廳、劇院，是綜合娛樂城。", "contact_name": null, "country_code": "SG", "english_name": null, "ticket_price": "觀景台成人SGD 26（住客免費），房價SGD 400+/晚起", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 823, "opening_hours": {"daily": "酒店24小時，觀景台10:00-22:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 120}, {"id": "fb07ecc1-355b-4537-91db-60d6bfe8ce34", "fax": null, "name": "月洞", "tags": null, "type": "attraction", "notes": null, "phone": null, "images": null, "address": "花蓮縣豐濱鄉港口村石門班哨角", "city_id": "769364e9-d3e2-474f-bc80-0184c00e6d9e", "website": null, "category": "自然風景 / Nature", "latitude": 23.5097, "is_active": true, "longitude": 121.5147, "region_id": null, "coun