344, "region_id": null, "country_id": "vietnam", "created_at": "2025-12-06T01:24:41.506928+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "胡志明陵，胡志明主席遺體安放處，位於河內巴亭廣場。1975年建成，蘇聯風格建築，莊嚴肅穆。瞻仰胡志明遺容需排隊，且有嚴格服裝規定。陵墓周圍有胡志明博物館、主席府、一柱寺。這是越南最重要的歷史景點，也是認識越南現代史的必訪之地。", "contact_name": null, "country_code": "VN", "english_name": "Ho Chi Minh Mausoleum", "ticket_price": "免費（服裝需端莊）", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 0, "opening_hours": {"note": "週一五休息", "open": "08:00", "close": "11:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 60}, {"id": "fe929487-589c-4cb6-8d86-413f9de69147", "fax": null, "name": "杜夢灣", "tags": ["海灘", "購物", "飯店區", "浮潛", "日落"], "type": "attraction", "notes": "關島最熱鬧的觀光區，白沙海灘綿延2公里。聚集各大飯店、免稅店、餐廳。海水清澈適合浮潛，傍晚日落美景動人。DFS免稅店和各大購物中心都在此區。\n\n旅遊提示：這是關島旅遊的核心區域，住宿選這裡最方便", "phone": null, "images": null, "address": null, "city_id": null, "website": null, "category": "自然風景 / Nature", "latitude": 13.5011, "is_active": true, "longitude": 144.8011, "region_id": null, "country_id": "usa", "created_at": "2025-12-17T03:48:38.284375+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "杜夢灣，美國著名景點，展現美國自然與文化多樣性。", "contact_name": null, "country_code": "US", "english_name": "Tumon Bay", "ticket_price": "0", "workspace_id": "8ef05a74-1f87-48ab-afd3-9bfeb423935d", "data_verified": false, "display_order": 298, "opening_hours": {"open": "00:00", "close": "24:00"}, "deleted_reason": null, "google_maps_url": null, "duration_minutes": 180}, {"id": "fe9c34a7-2e61-4bb4-a31e-fd123ef97a3a", "fax": null, "name": "萬丈窟", "tags": ["UNESCO", "洞穴", "熔岩", "地質"], "type": "attraction", "notes": "UNESCO世界自然遺產，熔岩洞窟，氣溫常年保持11-21度，建議攜帶外套", "phone": null, "images": null, "address": null, "city_id": null, "website": "http:/